-- ── UNIT 01 — Telling Your Story ──

  '{"warmup":"Bạn đã từng đến nước ngoài chưa? Lần cuối bạn đi du lịch là khi nào? Đây là sự khác biệt giữa hiện tại hoàn thành và quá khứ đơn!",
    "objectives":["Phân biệt hiện tại hoàn thành (have/has + V3) và quá khứ đơn (V2/V-ed)","Dùng đúng since, for, just, already, yet, ever với hiện tại hoàn thành","Nhận biết khi nào dùng thì nào qua ngữ cảnh"],
    "grammarHtml":"<b>Hiện tại hoàn thành:</b> S + have/has + V3. Dùng khi: kinh nghiệm sống (ever/never), hành động mới xảy ra (just), kết quả còn ảnh hưởng (already/yet), khoảng thời gian kéo dài đến nay (since/for).<br><b>Quá khứ đơn:</b> S + V2/V-ed. Dùng khi có thời điểm cụ thể trong quá khứ (yesterday, last year, in 2010, ago).<br><b>Dấu hiệu:</b> just/already/yet/ever/never/since/for → hoàn thành; yesterday/last.../in [year]/ago → quá khứ đơn.",
    "vocabBlock":[
      {"word":"already","ipa":"/ɔːlˈredi/","meaningVi":"đã rồi (trước dự kiến)","example":"I''ve already eaten."},
      {"word":"yet","ipa":"/jet/","meaningVi":"chưa / chưa xong (câu hỏi, phủ định)","example":"Have you finished yet?"},
      {"word":"just","ipa":"/dʒʌst/","meaningVi":"vừa mới","example":"She has just arrived."},
      {"word":"ever","ipa":"/ˈevə/","meaningVi":"đã từng (câu hỏi)","example":"Have you ever been to Paris?"},
      {"word":"since","ipa":"/sɪns/","meaningVi":"kể từ (mốc thời gian)","example":"I''ve lived here since 2018."},
      {"word":"for","ipa":"/fɔː/","meaningVi":"trong (khoảng thời gian)","example":"She has worked here for three years."}],
    "examples":[
      {"en":"I have visited Japan twice.","vi":"Tôi đã từng đến Nhật Bản hai lần."},
      {"en":"She visited Japan last year.","vi":"Cô ấy đã đến Nhật Bản năm ngoái."},
      {"en":"Have you ever tried sushi?","vi":"Bạn đã từng ăn sushi chưa?"},
      {"en":"He has just finished his homework.","vi":"Anh ấy vừa làm xong bài tập."},
      {"en":"They haven''t called yet.","vi":"Họ vẫn chưa gọi."}],
    "commonMistakes":["❌ \"I have seen him yesterday.\" → ✅ \"I saw him yesterday.\" (yesterday = quá khứ đơn)","❌ \"Did you ever eat sushi?\" → ✅ \"Have you ever eaten sushi?\" (ever = hoàn thành)","❌ \"She has worked here since three years.\" → ✅ \"...for three years.\" (khoảng thời gian dùng for)"],
    "tips":["Thấy yesterday/last .../ago → dùng quá khứ đơn ngay.","Thấy ever/never/just/already/yet/since/for → dùng hiện tại hoàn thành."]}'::jsonb);


  '{"warmup":"Khi kể chuyện: \"Khi tôi đến, anh ấy đã đi rồi.\" — sự kiện nào xảy ra trước? Đó là quá khứ hoàn thành!",
    "objectives":["Dùng had + V3 để chỉ hành động xảy ra trước một hành động quá khứ khác","Kết hợp before/after/when/by the time với quá khứ hoàn thành","Phân biệt quá khứ hoàn thành và quá khứ đơn"],
    "grammarHtml":"<b>Quá khứ hoàn thành:</b> S + had + V3. Dùng để chỉ hành động xảy ra <b>trước</b> một hành động quá khứ khác.<br>Dấu hiệu: before, after, when, by the time, already, because.<br><b>Ví dụ cấu trúc:</b> When I arrived, he had already left. (had left xảy ra trước arrived)<br>After she had eaten, she went to bed.",
    "vocabBlock":[
      {"word":"by the time","ipa":"/baɪ ðə taɪm/","meaningVi":"vào lúc mà","example":"By the time we arrived, the film had started."},
      {"word":"already","ipa":"/ɔːlˈredi/","meaningVi":"đã rồi","example":"He had already gone."},
      {"word":"just","ipa":"/dʒʌst/","meaningVi":"vừa mới (trong quá khứ)","example":"She had just left when I called."},
      {"word":"before","ipa":"/bɪˈfɔː/","meaningVi":"trước khi","example":"I had studied before the exam."},
      {"word":"after","ipa":"/ˈɑːftə/","meaningVi":"sau khi","example":"After he had left, we talked."}],
    "examples":[
      {"en":"When I arrived, she had already left.","vi":"Khi tôi đến, cô ấy đã đi rồi."},
      {"en":"He was tired because he had worked all day.","vi":"Anh ấy mệt vì đã làm việc cả ngày."},
      {"en":"By the time the bus came, we had waited for an hour.","vi":"Đến lúc xe buýt đến, chúng tôi đã chờ một tiếng."},
      {"en":"After she had finished dinner, she called her friend.","vi":"Sau khi ăn xong, cô ấy gọi cho bạn."}],
    "commonMistakes":["❌ \"When I arrived, she already left.\" → ✅ \"...she had already left.\" (sự kiện trước cần had + V3)","❌ Dùng nhầm had done cho cả hai sự kiện → Chỉ sự kiện XẢY RA TRƯỚC mới dùng had + V3."],
    "tips":["Vẽ trục thời gian: sự kiện nào trước dùng had + V3, sự kiện sau dùng quá khứ đơn.","before/after/when/by the time là dấu hiệu thường gặp."]}'::jsonb);


  '{"warmup":"Hôm nay bạn cảm thấy thế nào? Hãy nghĩ về những cảm xúc khác nhau mà bạn đã trải qua tuần này.",
    "objectives":["Học và dùng 10 từ diễn tả cảm xúc B1","Phân biệt admire/amazed/annoyed/confident/disappointed/embarrassed/frustrated/relieved/proud/shocked","Dùng cảm xúc trong câu miêu tả trải nghiệm"],
    "vocabBlock":[
      {"word":"admire","ipa":"/ədˈmaɪə/","meaningVi":"ngưỡng mộ","example":"I admire her courage."},
      {"word":"amazed","ipa":"/əˈmeɪzd/","meaningVi":"kinh ngạc, choáng ngợp","example":"I was amazed by the scenery."},
      {"word":"annoyed","ipa":"/əˈnɔɪd/","meaningVi":"khó chịu, bực bội","example":"She felt annoyed when he was late."},
      {"word":"confident","ipa":"/ˈkɒnfɪdənt/","meaningVi":"tự tin","example":"He felt confident before the exam."},
      {"word":"disappointed","ipa":"/ˌdɪsəˈpɔɪntɪd/","meaningVi":"thất vọng","example":"She was disappointed with the result."},
      {"word":"embarrassed","ipa":"/ɪmˈbærəst/","meaningVi":"xấu hổ, bối rối","example":"I felt embarrassed when I fell."},
      {"word":"frustrated","ipa":"/frʌˈstreɪtɪd/","meaningVi":"nản lòng, bực tức","example":"He was frustrated with the traffic."},
      {"word":"relieved","ipa":"/rɪˈliːvd/","meaningVi":"nhẹ nhõm","example":"I was relieved when I passed."},
      {"word":"proud","ipa":"/praʊd/","meaningVi":"tự hào","example":"She was proud of her son."},
      {"word":"shocked","ipa":"/ʃɒkt/","meaningVi":"sốc, bàng hoàng","example":"We were shocked by the news."}],
    "examples":[
      {"en":"I felt relieved after the exam was over.","vi":"Tôi cảm thấy nhẹ nhõm sau khi kết thúc kỳ thi."},
      {"en":"She was proud of what she had achieved.","vi":"Cô ấy tự hào về những gì mình đã đạt được."},
      {"en":"He was frustrated because the plan had failed.","vi":"Anh ấy nản lòng vì kế hoạch đã thất bại."}],
    "commonMistakes":["Nhầm embarrassed (xấu hổ về bản thân) với ashamed (hổ thẹn vì làm điều xấu).","frustrated (bực tức do cản trở) khác annoyed (khó chịu nhẹ hơn)."],
    "tips":["Kết hợp cảm xúc với hiện tại hoàn thành/quá khứ đơn để kể chuyện: I was shocked when I heard the news."]}'::jsonb);


  '{"warmup":"Bạn đã từng có một chuyến đi thực sự đáng nhớ chưa? Hãy đọc về chuyến đi của Ana và trả lời câu hỏi đọc hiểu.",
    "objectives":["Đọc hiểu đoạn văn B1 sử dụng thì hoàn thành và quá khứ","Tìm thông tin chi tiết về sự kiện và cảm xúc trong bài","Ôn từ vựng cảm xúc và cấu trúc thì hoàn thành qua ngữ cảnh"],
    "vocabBlock":[
      {"word":"memorable","ipa":"/ˈmemərəbl/","meaningVi":"đáng nhớ","example":"It was a memorable experience."},
      {"word":"journey","ipa":"/ˈdʒɜːni/","meaningVi":"hành trình, chuyến đi","example":"The journey took three hours."},
      {"word":"unexpected","ipa":"/ˌʌnɪkˈspektɪd/","meaningVi":"bất ngờ, không mong đợi","example":"There was an unexpected delay."},
      {"word":"overcome","ipa":"/ˌəʊvəˈkʌm/","meaningVi":"vượt qua","example":"She overcame her fear of flying."}],
    "examples":[
      {"en":"Last year, Ana decided to travel alone for the first time. She had always wanted to visit Vietnam, so she booked a flight to Hanoi. When she arrived at the airport, she realised she had left her passport at the hotel. She was shocked and frustrated, but she stayed calm. She called the hotel, and a kind staff member brought her passport just in time. After that experience, Ana felt more confident than ever. She had overcome a real challenge, and the rest of her trip was amazing. She has never forgotten that journey.","vi":"Năm ngoái, Ana quyết định đi du lịch một mình lần đầu tiên. Cô ấy luôn muốn đến thăm Việt Nam, vì vậy cô đặt vé máy bay đến Hà Nội. Khi đến sân bay, cô nhận ra mình đã bỏ quên hộ chiếu ở khách sạn. Cô bị sốc và bực tức, nhưng vẫn giữ bình tĩnh. Cô gọi điện cho khách sạn, và một nhân viên tốt bụng mang hộ chiếu đến đúng lúc. Sau trải nghiệm đó, Ana cảm thấy tự tin hơn bao giờ hết. Cô đã vượt qua một thử thách thực sự, và phần còn lại của chuyến đi thật tuyệt vời. Cô chưa bao giờ quên hành trình đó."}],
    "commonMistakes":["Đọc kỹ để phân biệt cảm xúc của Ana ở từng thời điểm khác nhau."],
    "tips":["Chú ý thì của động từ trong bài để hiểu thứ tự các sự kiện."]}'::jsonb);


  '{"warmup":"Ôn tập Unit 1: hiện tại hoàn thành, quá khứ hoàn thành và từ vựng cảm xúc.","objectives":["Tổng hợp can-do Unit 1","Đạt ≥ 75% để hoàn thành Unit"],"vocabBlock":[],"examples":[],"commonMistakes":[],"tips":["Cần đúng ≥ 8/10 để qua Unit."]}'::jsonb);


UPDATE learning_units SET review_lesson_id = 'b1-u01-l5' WHERE id = 'b1-u01';

-- ── UNIT 02 — Recent Experiences & Changes ──

  '{"warmup":"Bạn đã học tiếng Anh bao lâu rồi? ''I have been studying English for...'' — đó là hiện tại hoàn thành tiếp diễn!",
    "objectives":["Dùng have/has been + V-ing để chỉ hành động bắt đầu trong quá khứ và vẫn còn tiếp diễn","Dùng for và since với thì này","Phân biệt present perfect continuous với present perfect simple"],
    "grammarHtml":"<b>Cấu trúc:</b> S + have/has + been + V-ing.<br><b>Dùng khi:</b> hành động bắt đầu trong quá khứ và vẫn đang tiếp diễn hoặc vừa dừng lại, nhấn mạnh độ dài của hành động.<br><b>So sánh:</b><br>I have read the book. (xong, nhấn kết quả)<br>I have been reading the book. (còn đang đọc, nhấn thời gian)<br><b>Dấu hiệu:</b> for, since, all day/morning/week, how long.",
    "vocabBlock":[
      {"word":"for","ipa":"/fɔː/","meaningVi":"trong (khoảng thời gian)","example":"I''ve been waiting for two hours."},
      {"word":"since","ipa":"/sɪns/","meaningVi":"kể từ (mốc thời gian)","example":"She''s been working since 8 am."},
      {"word":"all day","ipa":"/ɔːl deɪ/","meaningVi":"cả ngày","example":"He''s been studying all day."},
      {"word":"how long","ipa":"/haʊ lɒŋ/","meaningVi":"bao lâu","example":"How long have you been waiting?"},
      {"word":"recently","ipa":"/ˈriːsntli/","meaningVi":"gần đây","example":"Have you been feeling well recently?"}],
    "examples":[
      {"en":"I have been learning English for three years.","vi":"Tôi đã học tiếng Anh được ba năm (và vẫn đang học)."},
      {"en":"She has been working here since January.","vi":"Cô ấy đã làm việc ở đây từ tháng Giêng."},
      {"en":"How long have you been waiting?","vi":"Bạn đã chờ bao lâu rồi?"},
      {"en":"He looks tired. He has been running.","vi":"Anh ấy trông mệt. Anh ấy vừa chạy bộ về."}],
    "commonMistakes":["❌ ''I am studying English for three years.'' → ✅ ''I have been studying English for three years.''","Không dùng stative verbs (know, like, want) với -ing."],
    "tips":["how long + have been + V-ing = câu hỏi về thời gian hành động kéo dài.","Kết quả hiện tại rõ ràng → dùng present perfect continuous."]}'::jsonb);


  '{"warmup":"''Khi anh ấy đến bệnh viện, bác sĩ đã mổ được 2 tiếng.'' Bác sĩ đang làm gì trước khi anh đến? Đó là quá khứ hoàn thành tiếp diễn!",
    "objectives":["Dùng had been + V-ing để chỉ hành động đang diễn ra trước một thời điểm quá khứ","Dùng thì này để giải thích nguyên nhân của trạng thái trong quá khứ"],
    "grammarHtml":"<b>Cấu trúc:</b> S + had been + V-ing.<br><b>Dùng khi:</b> hành động đang tiếp diễn trước (và đến) một thời điểm quá khứ; thường giải thích nguyên nhân.<br>He was tired because he had been running. (chạy bộ gây ra mệt)<br><b>So sánh:</b> had done = hoàn thành; had been doing = nhấn thời gian/quá trình.",
    "vocabBlock":[
      {"word":"exhausted","ipa":"/ɪɡˈzɔːstɪd/","meaningVi":"kiệt sức","example":"She was exhausted because she had been working all day."},
      {"word":"nervous","ipa":"/ˈnɜːvəs/","meaningVi":"lo lắng, hồi hộp","example":"He was nervous because he had been waiting."},
      {"word":"wet","ipa":"/wet/","meaningVi":"ướt","example":"Her clothes were wet — she had been walking in the rain."},
      {"word":"concentrate","ipa":"/ˈkɒnsntreɪt/","meaningVi":"tập trung","example":"I couldn''t concentrate because they had been making noise."}],
    "examples":[
      {"en":"She was tired because she had been studying for hours.","vi":"Cô ấy mệt vì đã học liên tục mấy tiếng."},
      {"en":"His hands were dirty because he had been fixing the car.","vi":"Tay anh ấy bẩn vì đã sửa xe."},
      {"en":"When the teacher arrived, the students had been talking for ten minutes.","vi":"Khi giáo viên đến, học sinh đã nói chuyện được mười phút."}],
    "commonMistakes":["Không dùng stative verbs với had been + V-ing.","had done (kết quả) vs had been doing (thời gian/quá trình)."],
    "tips":["Tìm trạng thái trong quá khứ (tired, wet, nervous) → giải thích bằng had been + V-ing."]}'::jsonb);


  '{"warmup":"Bạn có thói quen lành mạnh không? Hãy nghĩ về chế độ ăn, luyện tập và thói quen hàng ngày.",
    "objectives":["Học 10 từ vựng về cuộc sống hàng ngày và sức khỏe","Dùng từ trong câu nói về thói quen và thay đổi lối sống"],
    "vocabBlock":[
      {"word":"diet","ipa":"/ˈdaɪət/","meaningVi":"chế độ ăn uống","example":"A healthy diet includes vegetables and fruit."},
      {"word":"exercise","ipa":"/ˈeksəsaɪz/","meaningVi":"tập thể dục","example":"She exercises three times a week."},
      {"word":"habit","ipa":"/ˈhæbɪt/","meaningVi":"thói quen","example":"Reading before bed is a good habit."},
      {"word":"lifestyle","ipa":"/ˈlaɪfstaɪl/","meaningVi":"lối sống","example":"He has changed his lifestyle completely."},
      {"word":"routine","ipa":"/ruːˈtiːn/","meaningVi":"thói quen hàng ngày","example":"My morning routine takes 30 minutes."},
      {"word":"stress","ipa":"/stres/","meaningVi":"căng thẳng","example":"Too much work causes stress."},
      {"word":"improve","ipa":"/ɪmˈpruːv/","meaningVi":"cải thiện","example":"He has improved his English."},
      {"word":"develop","ipa":"/dɪˈveləp/","meaningVi":"phát triển","example":"She wants to develop new skills."},
      {"word":"maintain","ipa":"/meɪnˈteɪn/","meaningVi":"duy trì","example":"It is hard to maintain a healthy weight."},
      {"word":"reduce","ipa":"/rɪˈdjuːs/","meaningVi":"giảm, hạn chế","example":"He has reduced his sugar intake."}],
    "examples":[
      {"en":"I have been trying to improve my diet recently.","vi":"Gần đây tôi đã cố gắng cải thiện chế độ ăn."},
      {"en":"She has developed a regular exercise routine.","vi":"Cô ấy đã xây dựng thói quen tập thể dục đều đặn."},
      {"en":"Reducing stress is important for a healthy lifestyle.","vi":"Giảm căng thẳng rất quan trọng cho lối sống lành mạnh."}],
    "commonMistakes":["diet (n) = chế độ ăn, không chỉ ăn kiêng.","exercise có thể là danh từ hoặc động từ."],
    "tips":["Kết hợp từ với present perfect continuous: I have been reducing stress by exercising."]}'::jsonb);


  '{"warmup":"Hãy tưởng tượng bạn vừa chuyển đến một thành phố mới. Cuộc sống thay đổi thế nào?",
    "objectives":["Nghe và hiểu bài nói về thay đổi cuộc sống","Nhận biết thì hiện tại hoàn thành tiếp diễn qua ngữ cảnh nghe"],
    "vocabBlock":[
      {"word":"settle in","ipa":"/ˈsetl ɪn/","meaningVi":"ổn định, quen dần","example":"It takes time to settle in a new city."},
      {"word":"challenge","ipa":"/ˈtʃælɪndʒ/","meaningVi":"thách thức","example":"Moving alone is a big challenge."},
      {"word":"neighbourhood","ipa":"/ˈneɪbəhʊd/","meaningVi":"khu phố","example":"I love my new neighbourhood."},
      {"word":"commute","ipa":"/kəˈmjuːt/","meaningVi":"đi làm hàng ngày","example":"The daily commute is tiring."}],
    "examples":[
      {"en":"Hi, my name is David. I moved to Ho Chi Minh City six months ago. It has been an amazing experience, but also quite challenging. I have been trying to learn Vietnamese, and I have been making some progress. The city is very busy and I have been getting used to the noise and the traffic. I have been meeting new people at work, and I have already made some good friends. I feel much more settled now than I did when I first arrived.","vi":"Xin chào, tôi là David. Tôi chuyển đến Thành phố Hồ Chí Minh sáu tháng trước. Đây là trải nghiệm tuyệt vời nhưng cũng khá thử thách. Tôi đã cố gắng học tiếng Việt và đã có một số tiến bộ. Thành phố rất nhộn nhịp và tôi đang dần quen với tiếng ồn và giao thông. Tôi đã gặp gỡ nhiều người mới ở chỗ làm và đã kết bạn được. Bây giờ tôi cảm thấy ổn định hơn nhiều so với lúc mới đến."}],
    "commonMistakes":["Nghe kỹ thì của động từ để hiểu hành động đã kết thúc hay còn tiếp diễn."],
    "tips":["Chú ý các cụm have been + V-ing để biết hành động nào David vẫn đang làm."]}'::jsonb);


  '{"warmup":"Ôn tập Unit 2: present perfect continuous, past perfect continuous và từ vựng cuộc sống & sức khỏe.","objectives":["Tổng hợp can-do Unit 2","Đạt ≥ 75% để hoàn thành Unit"],"vocabBlock":[],"examples":[],"commonMistakes":[],"tips":["Cần đúng ≥ 8/10 để qua Unit."]}'::jsonb);


UPDATE learning_units SET review_lesson_id = 'b1-u02-l5' WHERE id = 'b1-u02';


-- ── UNIT 03 — Hopes & Dreams ──

  '{"warmup":"''Nếu trời nắng, tôi sẽ đi biển.'' vs ''Nếu tôi là triệu phú, tôi sẽ du lịch vòng quanh thế giới.'' Tình huống nào có thể xảy ra, tình huống nào là mơ ước?",
    "objectives":["Ôn lại first conditional: If + present simple, will + V","Dùng second conditional: If + past simple, would + V","Phân biệt khi nào dùng first vs second conditional"],
    "grammarHtml":"<b>First conditional</b> (có thể xảy ra):<br>If + present simple, will + V.<br>If it rains, I will stay at home.<br><b>Second conditional</b> (giả định, không có thật/khó xảy ra):<br>If + past simple, would + V.<br>If I had a million dollars, I would travel the world.<br><b>Lưu ý:</b> Động từ ''to be'' trong second conditional thường dùng ''were'' cho mọi chủ ngữ: If I were you, I would...",
    "vocabBlock":[
      {"word":"unless","ipa":"/ənˈles/","meaningVi":"trừ phi, nếu không","example":"I will go unless it rains."},
      {"word":"provided that","ipa":"/prəˈvaɪdɪd ðæt/","meaningVi":"miễn là","example":"I will help provided that you ask nicely."},
      {"word":"as long as","ipa":"/əz lɒŋ əz/","meaningVi":"miễn là, chừng nào","example":"I will stay as long as you need me."},
      {"word":"would","ipa":"/wʊd/","meaningVi":"sẽ (trong tình huống giả định)","example":"I would travel if I had time."},
      {"word":"were","ipa":"/wɜː/","meaningVi":"là (dạng giả định của to be)","example":"If I were rich, I would buy a house."}],
    "examples":[
      {"en":"If you study hard, you will pass the exam.","vi":"Nếu bạn học chăm, bạn sẽ đậu kỳ thi."},
      {"en":"If I were a doctor, I would help poor people.","vi":"Nếu tôi là bác sĩ, tôi sẽ giúp đỡ người nghèo."},
      {"en":"I would buy a car if I had more money.","vi":"Tôi sẽ mua xe nếu tôi có nhiều tiền hơn."},
      {"en":"If it doesn''t rain, we will have a picnic.","vi":"Nếu trời không mưa, chúng tôi sẽ đi picnic."}],
    "commonMistakes":["❌ ''If I would have money...'' → ✅ ''If I had money...'' (mệnh đề if không dùng would).","❌ ''If I was you'' → ✅ ''If I were you'' (dùng were trong second conditional)."],
    "tips":["First conditional = thực tế có thể xảy ra → dùng will.","Second conditional = tưởng tượng/giả định → dùng would."]}'::jsonb);


  '{"warmup":"''Vào lúc 8 giờ tối mai, tôi sẽ đang học bài.'' Đây là hành động đang diễn ra tại thời điểm cụ thể trong tương lai — future continuous!",
    "objectives":["Dùng will be + V-ing để chỉ hành động đang diễn ra tại thời điểm tương lai","Phân biệt future simple (will do) với future continuous (will be doing)","Dùng thì này để nói về kế hoạch đã sắp xếp sẵn"],
    "grammarHtml":"<b>Cấu trúc:</b> S + will be + V-ing.<br><b>Dùng khi:</b><br>1. Hành động đang diễn ra tại thời điểm cụ thể trong tương lai: This time tomorrow, I will be flying to Singapore.<br>2. Kế hoạch đã sắp xếp sẵn: I will be meeting him at six.<br>3. Hỏi lịch của người khác một cách lịch sự: Will you be using the car tonight?<br><b>Phân biệt:</b> will do = quyết định ngay lúc nói; will be doing = đã sắp xếp/đang diễn ra.",
    "vocabBlock":[
      {"word":"this time tomorrow","ipa":"/ðɪs taɪm təˈmɒrəʊ/","meaningVi":"vào giờ này ngày mai","example":"This time tomorrow I will be travelling."},
      {"word":"at this time next week","ipa":"/æt ðɪs taɪm nekst wiːk/","meaningVi":"vào giờ này tuần sau","example":"She will be working at this time next week."},
      {"word":"meanwhile","ipa":"/ˈmiːnwaɪl/","meaningVi":"trong khi đó","example":"Meanwhile, he will be waiting."},
      {"word":"flight","ipa":"/flaɪt/","meaningVi":"chuyến bay","example":"Our flight leaves at ten."},
      {"word":"board","ipa":"/bɔːd/","meaningVi":"lên tàu/máy bay","example":"We will be boarding soon."}],
    "examples":[
      {"en":"This time next week, I will be lying on a beach.","vi":"Vào giờ này tuần sau, tôi sẽ đang nằm trên bãi biển."},
      {"en":"At 9 pm tonight, she will be studying for her exam.","vi":"Vào 9 giờ tối nay, cô ấy sẽ đang ôn thi."},
      {"en":"Will you be using the car tomorrow? I need a lift.","vi":"Ngày mai bạn có dùng xe không? Tôi cần đi nhờ."}],
    "commonMistakes":["❌ ''I will be travel tomorrow.'' → ✅ ''I will be travelling tomorrow.'' (thiếu -ing).","Không dùng stative verbs với will be + V-ing: ❌ ''I will be knowing'' → ✅ ''I will know.''"],
    "tips":["this time tomorrow/next week là dấu hiệu thường dùng với future continuous.","Hỏi lịch lịch sự: Will you be + V-ing...?"]}'::jsonb);


  '{"warmup":"Ước mơ nghề nghiệp của bạn là gì? Hãy nghĩ về những từ liên quan đến career và education!",
    "objectives":["Học 10 từ vựng về công việc và mục tiêu học tập","Dùng từ trong câu nói về ước mơ và kế hoạch"],
    "vocabBlock":[
      {"word":"career","ipa":"/kəˈrɪə/","meaningVi":"sự nghiệp, nghề nghiệp","example":"She wants to build a career in medicine."},
      {"word":"degree","ipa":"/dɪˈɡriː/","meaningVi":"bằng đại học","example":"He has a degree in engineering."},
      {"word":"qualification","ipa":"/ˌkwɒlɪfɪˈkeɪʃn/","meaningVi":"bằng cấp, chứng chỉ","example":"You need the right qualifications for this job."},
      {"word":"salary","ipa":"/ˈsæləri/","meaningVi":"lương","example":"The salary is quite good."},
      {"word":"promotion","ipa":"/prəˈməʊʃn/","meaningVi":"thăng chức","example":"She got a promotion last year."},
      {"word":"apply","ipa":"/əˈplaɪ/","meaningVi":"nộp đơn, ứng tuyển","example":"I am going to apply for that job."},
      {"word":"achieve","ipa":"/əˈtʃiːv/","meaningVi":"đạt được","example":"He achieved his goal."},
      {"word":"succeed","ipa":"/səkˈsiːd/","meaningVi":"thành công","example":"If you work hard, you will succeed."},
      {"word":"opportunity","ipa":"/ˌɒpəˈtjuːnɪti/","meaningVi":"cơ hội","example":"This is a great opportunity."},
      {"word":"challenge","ipa":"/ˈtʃælɪndʒ/","meaningVi":"thách thức","example":"Starting a new job is always a challenge."}],
    "examples":[
      {"en":"If I get a degree, I will have more opportunities.","vi":"Nếu tôi có bằng đại học, tôi sẽ có nhiều cơ hội hơn."},
      {"en":"She wants to succeed in her career.","vi":"Cô ấy muốn thành công trong sự nghiệp."},
      {"en":"I am going to apply for a promotion next month.","vi":"Tháng tới tôi sẽ nộp đơn xin thăng chức."}],
    "commonMistakes":["career (n) ≠ job; career = sự nghiệp lâu dài, job = công việc cụ thể.","apply for (nộp đơn cho) vs apply to (nộp đơn vào trường/công ty)."],
    "tips":["Kết hợp từ với first/second conditional để nói về mục tiêu."]}'::jsonb);


  '{"warmup":"Bạn có ước mơ về một công việc cụ thể không? Hãy đọc câu chuyện của Linh và khám phá hành trình theo đuổi ước mơ.",
    "objectives":["Đọc hiểu đoạn văn B1 về chủ đề nghề nghiệp","Nhận biết cách dùng conditional và future continuous trong văn bản","Ôn từ vựng work & study goals"],
    "vocabBlock":[
      {"word":"passion","ipa":"/ˈpæʃn/","meaningVi":"đam mê","example":"She has a passion for design."},
      {"word":"determination","ipa":"/dɪˌtɜːmɪˈneɪʃn/","meaningVi":"quyết tâm","example":"Success requires determination."},
      {"word":"internship","ipa":"/ˈɪntɜːnʃɪp/","meaningVi":"thực tập","example":"She did an internship at a design company."},
      {"word":"portfolio","ipa":"/pɔːtˈfəʊliəʊ/","meaningVi":"hồ sơ, portfolio tác phẩm","example":"Her portfolio impressed the employers."}],
    "examples":[
      {"en":"Linh has always wanted to be a graphic designer. She studied art at university and got a degree two years ago. Since then, she has been building her portfolio and applying for jobs. She was rejected many times, but she never gave up. Last month, she applied for a position at a top design agency. If she gets the job, she will be working with some of the best designers in the country. This time next year, she might be leading her own team. Linh believes that if you have passion and determination, you will eventually succeed.","vi":"Linh luôn muốn trở thành nhà thiết kế đồ họa. Cô học mỹ thuật ở đại học và tốt nghiệp hai năm trước. Từ đó, cô đã xây dựng portfolio và nộp đơn xin việc. Cô bị từ chối nhiều lần nhưng không bao giờ bỏ cuộc. Tháng trước, cô nộp đơn vào một agency thiết kế hàng đầu. Nếu được nhận, cô sẽ làm việc cùng những nhà thiết kế giỏi nhất đất nước. Vào giờ này năm sau, có lẽ cô đang dẫn dắt nhóm của mình. Linh tin rằng nếu bạn có đam mê và quyết tâm, bạn sẽ thành công."}],
    "commonMistakes":["Đọc kỹ để phân biệt điều đã xảy ra và điều có thể xảy ra."],
    "tips":["Chú ý các cấu trúc: If she gets the job, she will be working..."]}'::jsonb);


  '{"warmup":"Ôn tập Unit 3: first/second conditional, future continuous và từ vựng mục tiêu.","objectives":["Tổng hợp can-do Unit 3","Đạt ≥ 75% để hoàn thành Unit"],"vocabBlock":[],"examples":[],"commonMistakes":[],"tips":["Cần đúng ≥ 8/10 để qua Unit."]}'::jsonb);


UPDATE learning_units SET review_lesson_id = 'b1-u03-l5' WHERE id = 'b1-u03';


-- ── UNIT 04 — If Only... ──

  '{"warmup":"''Giá mà tôi học chăm hơn, tôi đã thi đậu.'' Nhưng thực tế là tôi không học chăm và tôi không đậu. Đây là tình huống không thể thay đổi trong quá khứ — third conditional!",
    "objectives":["Dùng third conditional: If + had done, would have done","Nói về tình huống giả định trong quá khứ","Phân biệt second và third conditional"],
    "grammarHtml":"<b>Cấu trúc:</b> If + had + V3, would have + V3.<br><b>Dùng khi:</b> tưởng tượng kết quả khác cho tình huống đã xảy ra trong quá khứ (không thể thay đổi thực tế).<br>If I had studied harder, I would have passed. (Thực tế: tôi không học chăm → không đậu)<br><b>Rút gọn:</b> If I''d studied harder, I''d have passed.<br><b>So sánh:</b><br>2nd: If I had money, I would buy it. (giả định hiện tại)<br>3rd: If I had had money, I would have bought it. (giả định quá khứ)",
    "vocabBlock":[
      {"word":"would have","ipa":"/wʊd həv/","meaningVi":"đã có thể/sẽ đã (giả định quá khứ)","example":"I would have called you."},
      {"word":"had done","ipa":"/hæd dʌn/","meaningVi":"đã làm (trong điều kiện giả định)","example":"If she had known, she would have come."},
      {"word":"regret","ipa":"/rɪˈɡret/","meaningVi":"hối tiếc","example":"I regret not studying harder."},
      {"word":"otherwise","ipa":"/ˈʌðəwaɪz/","meaningVi":"nếu không thì, không thì","example":"I studied hard. Otherwise, I would have failed."},
      {"word":"consequence","ipa":"/ˈkɒnsɪkwəns/","meaningVi":"hậu quả, kết quả","example":"Every action has a consequence."}],
    "examples":[
      {"en":"If I had left earlier, I would have caught the bus.","vi":"Giá mà tôi đi sớm hơn, tôi đã bắt kịp xe buýt."},
      {"en":"She would have passed if she had studied harder.","vi":"Cô ấy đã đậu rồi nếu cô ấy học chăm hơn."},
      {"en":"If he hadn''t been late, they wouldn''t have missed the flight.","vi":"Nếu anh ấy không đến muộn, họ đã không lỡ chuyến bay."}],
    "commonMistakes":["❌ ''If I would have studied...'' → ✅ ''If I had studied...'' (mệnh đề if dùng had + V3, không dùng would).","❌ ''I would have pass'' → ✅ ''I would have passed'' (V3 sau would have)."],
    "tips":["Third conditional: If + had done → would have done. Cả hai đều có ''have'' nhưng ở khác vị trí.","Dùng ''d (had/would) cho rút gọn khi nói: If I''d known, I''d have helped."]}'::jsonb);


  '{"warmup":"''Lẽ ra tôi nên ở nhà.'' ''Có thể anh ấy đã quên.'' — Những cụm từ này nói về quá khứ theo cách nào?",
    "objectives":["Dùng should have + V3 để diễn đạt hối tiếc và phê bình","Dùng might have / could have + V3 để suy đoán về quá khứ","Phân biệt ba cấu trúc"],
    "grammarHtml":"<b>should have + V3</b>: hối tiếc (đã không làm) hoặc phê bình (lẽ ra nên làm).<br>You should have called me. (= Lẽ ra bạn nên gọi cho tôi.)<br>I shouldn''t have eaten so much. (= Lẽ ra tôi không nên ăn nhiều vậy.)<br><b>might have + V3</b>: suy đoán có thể xảy ra (không chắc).<br>She might have forgotten. (= Có lẽ cô ấy đã quên.)<br><b>could have + V3</b>: khả năng có thể đã xảy ra, hoặc cơ hội bị bỏ lỡ.<br>You could have told me! (= Bạn đã có thể nói với tôi mà!)",
    "vocabBlock":[
      {"word":"should have","ipa":"/ʃʊd həv/","meaningVi":"lẽ ra nên đã","example":"I should have studied more."},
      {"word":"shouldn''t have","ipa":"/ˈʃʊdnt həv/","meaningVi":"lẽ ra không nên đã","example":"You shouldn''t have said that."},
      {"word":"might have","ipa":"/maɪt həv/","meaningVi":"có lẽ đã (không chắc)","example":"She might have missed the bus."},
      {"word":"could have","ipa":"/kʊd həv/","meaningVi":"đã có thể / lẽ ra có thể","example":"You could have asked for help."},
      {"word":"must have","ipa":"/mʌst həv/","meaningVi":"chắc chắn đã (suy đoán mạnh)","example":"He must have forgotten."}],
    "examples":[
      {"en":"You should have told me about the meeting.","vi":"Lẽ ra bạn nên cho tôi biết về cuộc họp."},
      {"en":"She might have taken the wrong bus.","vi":"Có lẽ cô ấy đã đi nhầm xe buýt."},
      {"en":"I could have helped if you had asked.","vi":"Tôi đã có thể giúp nếu bạn hỏi."},
      {"en":"He must have been tired — he fell asleep immediately.","vi":"Chắc anh ấy đã mệt lắm — anh ấy ngủ ngay lập tức."}],
    "commonMistakes":["❌ ''I should have to study more.'' → ✅ ''I should have studied more.'' (không thêm to).","❌ ''might has gone'' → ✅ ''might have gone'' (luôn dùng have, không chia)."],
    "tips":["should have = hối tiếc/phê bình; might have = không chắc; could have = cơ hội bị bỏ lỡ.","must have = suy đoán chắc chắn về quá khứ."]}'::jsonb);


  '{"warmup":"Khi bạn mắc lỗi, bạn cảm thấy thế nào? Hãy nghĩ về những từ liên quan đến hối tiếc và trách nhiệm.",
    "objectives":["Học 10 từ vựng về hối tiếc và trách nhiệm xã hội","Dùng từ trong câu nói về quyết định và hậu quả"],
    "vocabBlock":[
      {"word":"regret","ipa":"/rɪˈɡret/","meaningVi":"hối tiếc (n/v)","example":"I regret not calling her sooner."},
      {"word":"blame","ipa":"/bleɪm/","meaningVi":"đổ lỗi, trách móc","example":"Don''t blame yourself for the accident."},
      {"word":"fault","ipa":"/fɔːlt/","meaningVi":"lỗi, sự sai lầm","example":"It was my fault."},
      {"word":"guilty","ipa":"/ˈɡɪlti/","meaningVi":"tội lỗi, có lỗi","example":"He felt guilty about lying."},
      {"word":"ashamed","ipa":"/əˈʃeɪmd/","meaningVi":"hổ thẹn, xấu hổ","example":"She was ashamed of her behaviour."},
      {"word":"forgive","ipa":"/fəˈɡɪv/","meaningVi":"tha thứ","example":"Can you forgive me?"},
      {"word":"apologise","ipa":"/əˈpɒlədʒaɪz/","meaningVi":"xin lỗi","example":"He apologised for being late."},
      {"word":"consequence","ipa":"/ˈkɒnsɪkwəns/","meaningVi":"hậu quả","example":"Think about the consequences."},
      {"word":"decision","ipa":"/dɪˈsɪʒn/","meaningVi":"quyết định","example":"It was a difficult decision."},
      {"word":"mistake","ipa":"/mɪˈsteɪk/","meaningVi":"lỗi lầm","example":"Everyone makes mistakes."}],
    "examples":[
      {"en":"I regret not apologising sooner.","vi":"Tôi hối tiếc vì không xin lỗi sớm hơn."},
      {"en":"She felt guilty and ashamed of her decision.","vi":"Cô ấy cảm thấy tội lỗi và hổ thẹn về quyết định của mình."},
      {"en":"If I had thought about the consequences, I wouldn''t have made that mistake.","vi":"Giá mà tôi suy nghĩ về hậu quả, tôi đã không mắc lỗi đó."}],
    "commonMistakes":["blame (v): blame sb for sth = đổ lỗi ai vì điều gì.","apologise for + V-ing: He apologised for being late (không dùng to be)."],
    "tips":["guilty (cảm giác) vs fault (sự thật khách quan): I feel guilty. It was my fault.","forgive sb for sth: Can you forgive me for what I said?"]}'::jsonb);


  '{"warmup":"Ai cũng có quyết định hối tiếc. Hãy nghe Mark kể về quyết định anh ấy ước giá mà mình không làm.",
    "objectives":["Nghe và hiểu bài nói về hối tiếc quyết định trong quá khứ","Nhận biết third conditional và should have trong ngữ cảnh nghe"],
    "vocabBlock":[
      {"word":"turn down","ipa":"/tɜːn daʊn/","meaningVi":"từ chối (lời đề nghị)","example":"He turned down the job offer."},
      {"word":"regrettable","ipa":"/rɪˈɡretəbl/","meaningVi":"đáng tiếc","example":"It was a regrettable decision."},
      {"word":"in hindsight","ipa":"/ɪn ˈhaɪndsaɪt/","meaningVi":"nhìn lại mới thấy","example":"In hindsight, I should have accepted."},
      {"word":"opportunity","ipa":"/ˌɒpəˈtjuːnɪti/","meaningVi":"cơ hội","example":"It was a great opportunity."}],
    "examples":[
      {"en":"Five years ago, I had the chance to work in Japan. A company offered me a position, but I turned it down because I was afraid of living abroad. I thought I wasn''t ready. But in hindsight, I should have accepted the offer. If I had gone to Japan, I would have learned so much. I might have developed my career much faster. I could have made amazing connections. Now I regret that decision deeply. I shouldn''t have let fear control my choices.","vi":"Năm năm trước, tôi có cơ hội làm việc ở Nhật. Một công ty đề nghị cho tôi vị trí đó, nhưng tôi từ chối vì sợ sống ở nước ngoài. Tôi nghĩ mình chưa sẵn sàng. Nhưng nhìn lại, lẽ ra tôi nên chấp nhận. Nếu tôi đã đến Nhật, tôi đã học được rất nhiều. Có lẽ tôi đã phát triển sự nghiệp nhanh hơn. Tôi đã có thể tạo nhiều mối quan hệ tuyệt vời. Bây giờ tôi hối tiếc quyết định đó sâu sắc. Lẽ ra tôi không nên để nỗi sợ kiểm soát lựa chọn của mình."}],
    "commonMistakes":["Nghe kỹ để phân biệt should have (hối tiếc), might have (có lẽ đã), could have (đã có thể)."],
    "tips":["in hindsight là cụm từ báo hiệu nhìn lại về quyết định trong quá khứ."]}'::jsonb);


  '{"warmup":"Ôn tập Unit 4: third conditional, should/might/could have và từ vựng hối tiếc.","objectives":["Tổng hợp can-do Unit 4","Đạt ≥ 75% để hoàn thành Unit"],"vocabBlock":[],"examples":[],"commonMistakes":[],"tips":["Cần đúng ≥ 8/10 để qua Unit."]}'::jsonb);


UPDATE learning_units SET review_lesson_id = 'b1-u04-l5' WHERE id = 'b1-u04';


-- ── UNIT 05 — Your Opinions ──

  '{"warmup":"Để nói ý kiến rõ ràng, bạn cần kết nối ý tưởng. ''I like it because...'' ''However, there are problems...'' Đây là các từ nối!",
    "objectives":["Dùng từ nối nguyên nhân: because, since, as","Dùng từ nối kết quả: so, therefore, as a result","Dùng từ nối tương phản: although, even though, however, despite, in spite of"],
    "grammarHtml":"<b>Nguyên nhân (cause):</b> because/since/as + clause. <i>She stayed home because it was raining.</i><br><b>Kết quả (effect):</b> so + clause; therefore (đầu câu/giữa câu). <i>It was raining, so she stayed home. It was raining. Therefore, she stayed home.</i><br><b>Tương phản (contrast):</b><br>although/even though + clause: <i>Although it was raining, she went out.</i><br>however (đầu câu, sau dấu phẩy/chấm phẩy): <i>It was raining. However, she went out.</i><br>despite/in spite of + noun/V-ing: <i>Despite the rain, she went out.</i>",
    "vocabBlock":[
      {"word":"because","ipa":"/bɪˈkɒz/","meaningVi":"vì, bởi vì","example":"She left because she was tired."},
      {"word":"so","ipa":"/səʊ/","meaningVi":"vì vậy, nên","example":"It was hot, so I opened the window."},
      {"word":"since","ipa":"/sɪns/","meaningVi":"vì (nguyên nhân)","example":"Since it was late, we went home."},
      {"word":"although","ipa":"/ɔːlˈðəʊ/","meaningVi":"mặc dù (+ mệnh đề)","example":"Although he was tired, he kept working."},
      {"word":"however","ipa":"/haʊˈevə/","meaningVi":"tuy nhiên","example":"It was difficult. However, we succeeded."},
      {"word":"despite","ipa":"/dɪˈspaɪt/","meaningVi":"mặc dù (+ danh từ/V-ing)","example":"Despite the rain, they played."},
      {"word":"therefore","ipa":"/ˈðeəfɔː/","meaningVi":"do đó, vì vậy","example":"She studied hard. Therefore, she passed."} ],
    "examples":[
      {"en":"I didn''t go out because it was raining.","vi":"Tôi không ra ngoài vì trời mưa."},
      {"en":"It was expensive. However, I bought it anyway.","vi":"Nó đắt tiền. Tuy nhiên, tôi vẫn mua."},
      {"en":"Despite being tired, she finished the project.","vi":"Mặc dù mệt, cô ấy vẫn hoàn thành dự án."},
      {"en":"He was late, so he missed the meeting.","vi":"Anh ấy đến muộn, vì vậy lỡ cuộc họp."}],
    "commonMistakes":["❌ ''Despite she was tired'' → ✅ ''Despite being tired'' (despite + noun/V-ing, không + mệnh đề).","❌ ''Although, she went out'' → although không đứng đầu câu độc lập với dấu phẩy.","❌ ''However she was tired'' → ✅ ''However, she was tired.'' (however cần dấu phẩy sau)."],
    "tips":["although/even though + clause vs despite/in spite of + noun/V-ing.","therefore = kết quả, dùng câu trang trọng hơn so."]}'::jsonb);


  '{"warmup":"''The film was boring.'' vs ''I was bored.'' Tại sao? Câu đầu mô tả bộ phim, câu sau mô tả cảm giác của tôi!",
    "objectives":["Phân biệt -ing adjectives (mô tả sự vật/tình huống) và -ed adjectives (mô tả cảm giác của người)","Dùng đúng: boring/bored, exciting/excited, interesting/interested, surprising/surprised, tiring/tired, frightening/frightened"],
    "grammarHtml":"<b>-ing adjective:</b> mô tả đặc điểm của sự vật, tình huống, hoặc hành động gây ra cảm giác đó.<br><i>The film is boring.</i> (bộ phim gây buồn chán)<br><b>-ed adjective:</b> mô tả cảm giác của người (hoặc động vật).<br><i>I am bored.</i> (tôi cảm thấy buồn chán)<br><b>Các cặp thường gặp:</b><br>boring/bored, exciting/excited, interesting/interested, surprising/surprised, tiring/tired, frightening/frightened, amusing/amused, confusing/confused.",
    "vocabBlock":[
      {"word":"boring","ipa":"/ˈbɔːrɪŋ/","meaningVi":"nhàm chán (gây buồn)","example":"The lecture was boring."},
      {"word":"bored","ipa":"/bɔːd/","meaningVi":"chán (cảm giác)","example":"I felt bored during the lecture."},
      {"word":"exciting","ipa":"/ɪkˈsaɪtɪŋ/","meaningVi":"thú vị, hấp dẫn (gây hứng)","example":"The game was exciting."},
      {"word":"excited","ipa":"/ɪkˈsaɪtɪd/","meaningVi":"hứng khởi (cảm giác)","example":"She was excited about the trip."},
      {"word":"interesting","ipa":"/ˈɪntrəstɪŋ/","meaningVi":"thú vị (gây tò mò)","example":"It was an interesting book."},
      {"word":"interested","ipa":"/ˈɪntrəstɪd/","meaningVi":"thấy thích thú (cảm giác)","example":"I am interested in science."},
      {"word":"tiring","ipa":"/ˈtaɪərɪŋ/","meaningVi":"mệt mỏi (gây mệt)","example":"The journey was tiring."},
      {"word":"tired","ipa":"/taɪəd/","meaningVi":"mệt (cảm giác)","example":"I feel tired after work."}],
    "examples":[
      {"en":"The match was exciting. The fans were excited.","vi":"Trận đấu rất hấp dẫn. Các fan rất hứng khởi."},
      {"en":"The news was surprising. She was surprised.","vi":"Tin tức rất bất ngờ. Cô ấy bị bất ngờ."},
      {"en":"Learning grammar can be confusing, but students shouldn''t feel confused forever!","vi":"Học ngữ pháp có thể gây khó hiểu, nhưng học sinh không nên mãi bị bối rối!"}],
    "commonMistakes":["❌ ''I am boring.'' (= Tôi là người nhàm chán) → ✅ ''I am bored.'' (= Tôi đang chán).","❌ ''The book is interested.'' → ✅ ''The book is interesting.''"],
    "tips":["Người/động vật = -ed; sự vật/tình huống = -ing.","Hỏi: Cái gì/ai GÂY RA cảm giác? → -ing. Ai CẢM THẤY? → -ed."]}'::jsonb);


  '{"warmup":"Khi muốn nói ý kiến của mình bằng tiếng Anh, bạn dùng gì ngoài ''I think''?",
    "objectives":["Học các cụm từ diễn đạt ý kiến cá nhân","Phân biệt cách diễn đạt chắc chắn vs không chắc","Dùng các cụm từ trong hội thoại tranh luận"],
    "vocabBlock":[
      {"word":"In my opinion","ipa":"/ɪn maɪ əˈpɪnjən/","meaningVi":"theo ý kiến của tôi","example":"In my opinion, homework is necessary."},
      {"word":"I think","ipa":"/aɪ θɪŋk/","meaningVi":"tôi nghĩ","example":"I think this is a good idea."},
      {"word":"I believe","ipa":"/aɪ bɪˈliːv/","meaningVi":"tôi tin rằng","example":"I believe exercise is important."},
      {"word":"I''d say","ipa":"/aɪd seɪ/","meaningVi":"tôi sẽ nói rằng (không chắc lắm)","example":"I''d say about fifty people were there."},
      {"word":"Personally","ipa":"/ˈpɜːsənəli/","meaningVi":"cá nhân tôi","example":"Personally, I prefer coffee to tea."},
      {"word":"As far as I know","ipa":"/əz fɑːr əz aɪ nəʊ/","meaningVi":"theo tôi biết","example":"As far as I know, the shop is closed."},
      {"word":"I''m not sure I agree","ipa":"/aɪm nɒt ʃʊər aɪ əˈɡriː/","meaningVi":"tôi không chắc tôi đồng ý","example":"I''m not sure I agree with that view."},
      {"word":"That''s a good point","ipa":"/ðæts ə ɡʊd pɔɪnt/","meaningVi":"đó là một điểm hay","example":"That''s a good point — I hadn''t thought of that."}],
    "examples":[
      {"en":"In my opinion, students should have less homework.","vi":"Theo ý kiến của tôi, học sinh nên có ít bài tập hơn."},
      {"en":"Personally, I believe technology makes life easier.","vi":"Cá nhân tôi tin rằng công nghệ giúp cuộc sống dễ hơn."},
      {"en":"That''s a good point, but I''m not sure I agree.","vi":"Đó là điểm hay, nhưng tôi không chắc tôi đồng ý."},
      {"en":"As far as I know, the new policy starts next month.","vi":"Theo tôi biết, chính sách mới bắt đầu tháng sau."}],
    "commonMistakes":["''In my opinion, I think...'' → không cần cả hai: chọn một cụm.","As far as I know ≠ theo tôi biết chính xác; = theo tôi biết (có thể sai)."],
    "tips":["Kết hợp: ''In my opinion, ... However, I''m not sure I agree that...'' để tạo lập luận rõ ràng."]}'::jsonb);


  '{"warmup":"Bạn nghĩ gì về bài tập về nhà? Có nên bãi bỏ không? Hãy đọc và tìm hiểu lập luận của hai phía.",
    "objectives":["Đọc hiểu bài văn nghị luận B1","Nhận biết lập luận ủng hộ và phản đối","Học cách nhận biết từ nối trong văn nghị luận"],
    "vocabBlock":[
      {"word":"ban","ipa":"/bæn/","meaningVi":"cấm, bãi bỏ","example":"Should homework be banned?"},
      {"word":"argument","ipa":"/ˈɑːɡjumənt/","meaningVi":"lập luận, tranh luận","example":"There are good arguments on both sides."},
      {"word":"benefit","ipa":"/ˈbenɪfɪt/","meaningVi":"lợi ích","example":"Homework has many benefits."},
      {"word":"stress","ipa":"/stres/","meaningVi":"căng thẳng, áp lực","example":"Too much homework causes stress."}],
    "examples":[
      {"en":"Should homework be banned? Many students believe it should. In their opinion, homework causes stress and takes time away from family and hobbies. Despite this, most teachers disagree. They believe homework helps students practise what they have learned and develop good study habits. Furthermore, research suggests that students who do homework achieve better results in exams. However, there is also evidence that too much homework can lead to anxiety and burnout. Therefore, many experts suggest a balance is needed: some homework, but not too much. Personally, I think the quality of homework matters more than the quantity.","vi":"Bài tập về nhà có nên bị bãi bỏ không? Nhiều học sinh nghĩ là nên. Theo ý kiến của họ, bài tập về nhà gây căng thẳng và chiếm thời gian dành cho gia đình và sở thích. Mặc dù vậy, hầu hết giáo viên không đồng ý. Họ tin rằng bài tập giúp học sinh luyện tập và hình thành thói quen học tập tốt. Hơn nữa, nghiên cứu cho thấy học sinh làm bài tập đạt kết quả thi tốt hơn. Tuy nhiên, cũng có bằng chứng rằng bài tập quá nhiều có thể gây lo âu và kiệt sức. Vì vậy, nhiều chuyên gia cho rằng cần có sự cân bằng: một số bài tập, nhưng không quá nhiều. Cá nhân tôi nghĩ chất lượng bài tập quan trọng hơn số lượng."}],
    "commonMistakes":["Đọc kỹ để phân biệt ý kiến của học sinh, giáo viên và chuyên gia."],
    "tips":["Chú ý các từ nối: despite, however, therefore, furthermore để theo dõi lập luận."]}'::jsonb);


  '{"warmup":"Ôn tập Unit 5: từ nối, tính từ -ing/-ed và cụm từ ý kiến.","objectives":["Tổng hợp can-do Unit 5","Đạt ≥ 75% để hoàn thành Unit"],"vocabBlock":[],"examples":[],"commonMistakes":[],"tips":["Cần đúng ≥ 8/10 để qua Unit."]}'::jsonb);


UPDATE learning_units SET review_lesson_id = 'b1-u05-l5' WHERE id = 'b1-u05';


-- ── UNIT 06 — In the News ──

  '{"warmup":"''Apple makes iPhones.'' vs ''iPhones are made by Apple.'' Câu thứ hai nhấn vào điều gì? Bị động giúp chúng ta thay đổi trọng tâm câu!",
    "objectives":["Tạo câu bị động ở thì hiện tại đơn (am/is/are + V3)","Tạo câu bị động ở thì quá khứ đơn (was/were + V3)","Dùng by-agent khi cần thiết, bỏ qua khi không quan trọng"],
    "grammarHtml":"<b>Câu chủ động → bị động:</b><br>Hiện tại đơn: S + am/is/are + V3 (by agent).<br>Active: People speak English worldwide. → Passive: English is spoken worldwide.<br>Quá khứ đơn: S + was/were + V3 (by agent).<br>Active: Someone stole my car. → Passive: My car was stolen.<br><b>Quy tắc:</b> Tân ngữ câu chủ động → Chủ ngữ câu bị động. By + agent (người/vật thực hiện) — bỏ qua nếu không quan trọng.<br><b>Câu phủ định:</b> is not/was not + V3. <b>Câu hỏi:</b> Is/Was + S + V3?",
    "vocabBlock":[
      {"word":"is made","ipa":"/ɪz meɪd/","meaningVi":"được làm ra","example":"This product is made in Vietnam."},
      {"word":"was built","ipa":"/wɒz bɪlt/","meaningVi":"được xây dựng","example":"The bridge was built in 1990."},
      {"word":"are sold","ipa":"/ɑː səʊld/","meaningVi":"được bán","example":"Millions of phones are sold each year."},
      {"word":"were found","ipa":"/wɜː faʊnd/","meaningVi":"được tìm thấy","example":"Fossils were found near the river."},
      {"word":"by","ipa":"/baɪ/","meaningVi":"bởi (người/vật thực hiện)","example":"The letter was written by her."}],
    "examples":[
      {"en":"English is taught in schools worldwide.","vi":"Tiếng Anh được dạy ở các trường học trên toàn thế giới."},
      {"en":"The window was broken by the ball.","vi":"Cửa sổ bị vỡ bởi quả bóng."},
      {"en":"The new museum was opened last year.","vi":"Bảo tàng mới được khai trương năm ngoái."},
      {"en":"These cars are not made in this country.","vi":"Những chiếc xe này không được sản xuất ở đất nước này."}],
    "commonMistakes":["❌ ''English is speak worldwide.'' → ✅ ''English is spoken worldwide.'' (V3, không phải V nguyên thể).","❌ ''The car was builded.'' → ✅ ''The car was built.'' (V3 bất quy tắc).","❌ By the passive → bỏ by agent khi chủ thể không quan trọng hoặc không biết."],
    "tips":["Nhớ V3 của các động từ bất quy tắc: build → built, write → written, sell → sold, find → found.","Bỏ by-agent khi: chủ thể là people/someone/everyone hoặc không biết."]}'::jsonb);


  '{"warmup":"''Ngôi nhà đã được sửa.'' vs ''Ngôi nhà sẽ được sửa.'' Làm sao nói những câu này trong tiếng Anh?",
    "objectives":["Tạo câu bị động ở thì hiện tại hoàn thành (has/have been + V3)","Tạo câu bị động ở thì tương lai (will be + V3)","Dùng bị động trong bối cảnh tin tức và thông báo"],
    "grammarHtml":"<b>Present perfect passive:</b> S + have/has + been + V3.<br>The bridge has been repaired. (= Ai đó đã sửa xong cây cầu.)<br><b>Future passive:</b> S + will be + V3.<br>The new road will be built next year. (= Người ta sẽ xây con đường mới năm sau.)<br><b>Ứng dụng:</b> Thụ động rất phổ biến trong tin tức và thông báo chính thức khi chủ thể không quan trọng hoặc không biết.",
    "vocabBlock":[
      {"word":"has been repaired","ipa":"/hæz bɪn rɪˈpeəd/","meaningVi":"đã được sửa chữa","example":"The road has been repaired."},
      {"word":"have been arrested","ipa":"/hæv bɪn əˈrestɪd/","meaningVi":"đã bị bắt","example":"Three people have been arrested."},
      {"word":"will be built","ipa":"/wɪl bi bɪlt/","meaningVi":"sẽ được xây dựng","example":"A new hospital will be built."},
      {"word":"will be announced","ipa":"/wɪl bi əˈnaʊnst/","meaningVi":"sẽ được thông báo","example":"The results will be announced tomorrow."},
      {"word":"is expected to","ipa":"/ɪz ɪkˈspektɪd tʊ/","meaningVi":"được dự kiến sẽ","example":"The law is expected to change."}],
    "examples":[
      {"en":"The new law has been approved by parliament.","vi":"Luật mới đã được quốc hội thông qua."},
      {"en":"Three suspects have been arrested.","vi":"Ba nghi phạm đã bị bắt."},
      {"en":"A new station will be opened next spring.","vi":"Một ga tàu mới sẽ được khai trương vào mùa xuân tới."},
      {"en":"The decision will be announced on Monday.","vi":"Quyết định sẽ được thông báo vào thứ Hai."}],
    "commonMistakes":["❌ ''has been repair'' → ✅ ''has been repaired'' (cần V3).","❌ ''will been built'' → ✅ ''will be built'' (will + be, không có been)."],
    "tips":["Present perfect passive: has/have BEEN + V3 (be bắt buộc).","Future passive: will BE + V3 (không có been, chỉ be)."]}'::jsonb);


  '{"warmup":"Bạn theo dõi tin tức ở đâu? TV, mạng xã hội, hay báo? Hãy học từ vựng về truyền thông và công nghệ!",
    "objectives":["Học 10 từ vựng về truyền thông và công nghệ","Dùng từ trong câu nói về tin tức và thông tin"],
    "vocabBlock":[
      {"word":"headline","ipa":"/ˈhedlaɪn/","meaningVi":"tiêu đề, đầu đề báo","example":"The headline read: ''New Discovery''."},
      {"word":"broadcast","ipa":"/ˈbrɔːdkɑːst/","meaningVi":"phát sóng (v/n)","example":"The news is broadcast at 7 pm."},
      {"word":"journalist","ipa":"/ˈdʒɜːnəlɪst/","meaningVi":"nhà báo","example":"She works as a journalist for BBC."},
      {"word":"report","ipa":"/rɪˈpɔːt/","meaningVi":"bản tin, tường thuật (n/v)","example":"A report was published about climate change."},
      {"word":"publish","ipa":"/ˈpʌblɪʃ/","meaningVi":"xuất bản, đăng","example":"The article was published online."},
      {"word":"online","ipa":"/ˈɒnlaɪn/","meaningVi":"trực tuyến","example":"Most people read news online now."},
      {"word":"network","ipa":"/ˈnetwɜːk/","meaningVi":"mạng lưới, kênh truyền thông","example":"She joined a professional network."},
      {"word":"communicate","ipa":"/kəˈmjuːnɪkeɪt/","meaningVi":"giao tiếp, truyền đạt","example":"We communicate through social media."},
      {"word":"access","ipa":"/ˈækses/","meaningVi":"truy cập, tiếp cận (v/n)","example":"Everyone should have access to information."},
      {"word":"post","ipa":"/pəʊst/","meaningVi":"đăng (bài), bài đăng (n)","example":"She posted the news on her social media."}],
    "examples":[
      {"en":"The story was broadcast on all major networks.","vi":"Câu chuyện được phát sóng trên tất cả các kênh lớn."},
      {"en":"The report was published by a well-known journalist.","vi":"Bản báo cáo được đăng bởi một nhà báo nổi tiếng."},
      {"en":"Millions of people access the news online every day.","vi":"Hàng triệu người truy cập tin tức trực tuyến mỗi ngày."}],
    "commonMistakes":["broadcast = phát sóng (cả n và v, không thêm -ed: broadcast/broadcast)","post (mạng xã hội) = đăng bài (v), bài đăng (n)"],
    "tips":["Nhiều từ này thường xuất hiện trong câu bị động: The news was broadcast, The report was published."]}'::jsonb);


  '{"warmup":"Hãy tưởng tượng bạn đang nghe bản tin buổi sáng. Những thông tin quan trọng nào được đề cập?",
    "objectives":["Nghe và hiểu bản tin ngắn B1 theo phong cách tin tức","Nhận biết câu bị động trong ngữ cảnh tin tức","Ôn từ vựng truyền thông qua bài nghe"],
    "vocabBlock":[
      {"word":"announce","ipa":"/əˈnaʊns/","meaningVi":"thông báo","example":"The results were announced this morning."},
      {"word":"confirm","ipa":"/kənˈfɜːm/","meaningVi":"xác nhận","example":"The plan has been confirmed."},
      {"word":"injured","ipa":"/ˈɪndʒəd/","meaningVi":"bị thương","example":"Several people were injured."},
      {"word":"rescue","ipa":"/ˈreskjuː/","meaningVi":"cứu hộ","example":"Three people were rescued from the sea."}],
    "examples":[
      {"en":"Good morning. Here are today''s headlines. A new trade agreement has been signed between two neighbouring countries. The deal is expected to create thousands of new jobs. In local news, a fire broke out at a warehouse last night. Three people were injured, but all have been taken to hospital and are reported to be in a stable condition. The cause of the fire has not been confirmed yet. In sport, the national football team has been selected for the championship. Matches will be broadcast live on national television. That''s all for now. Stay tuned for more updates.","vi":"Chào buổi sáng. Đây là các tiêu đề tin hôm nay. Một hiệp định thương mại mới đã được ký kết giữa hai nước láng giềng. Thỏa thuận này dự kiến sẽ tạo ra hàng nghìn việc làm mới. Về tin địa phương, một đám cháy bùng phát tại kho hàng tối qua. Ba người bị thương nhưng tất cả đã được đưa vào bệnh viện và được cho biết đang ổn định. Nguyên nhân vụ cháy chưa được xác nhận. Về thể thao, đội tuyển bóng đá quốc gia đã được chọn tham dự giải vô địch. Các trận đấu sẽ được phát sóng trực tiếp trên truyền hình quốc gia."}],
    "commonMistakes":["Nghe kỹ tất cả dạng bị động trong bản tin để hiểu ai làm gì với ai."],
    "tips":["Tin tức thường dùng bị động để không đề cập chủ thể: Three people were injured."]}'::jsonb);


