INSERT INTO learning_lessons (id, level_code, skill_code, unit_id, lesson_type, lesson_order, title, subtitle, duration_minutes, xp_reward, required_score_to_pass, content, theory_content) VALUES
 ('b1-u01-l1','B1','reading','b1-u01','normal',1,'Present Perfect vs Past Simple','Have done vs did: since/for/just/already/yet/ever',10,20,70,'{}'::jsonb,
INSERT INTO learning_lesson_activities (id, lesson_id, activity_type, display_order, phase, difficulty, counts_toward_mastery, payload) VALUES
 ('b1-u01-l1-p1','b1-u01-l1','grammar_fill_blank',1,'practice','easy',false,'{"question":"Chia động từ đúng thì: \"She ___ (visit) Paris last summer.\"","acceptedAnswers":["visited"],"explanationVi":"last summer = thời điểm cụ thể → quá khứ đơn: visited."}'::jsonb),
 ('b1-u01-l1-p2','b1-u01-l1','multiple_choice',2,'practice','easy',false,'{"question":"Chọn câu ĐÚNG: \"I ___ just ___ my keys.\"","options":[{"id":"a","text":"have ... found"},{"id":"b","text":"did ... find"},{"id":"c","text":"had ... find"}],"correctOptionId":"a","explanationVi":"just đi với hiện tại hoàn thành: have just found."}'::jsonb),
 ('b1-u01-l1-p3','b1-u01-l1','vocabulary_match',3,'practice','easy',false,'{"question":"Nối từ chỉ thời gian với thì phù hợp:","pairs":[{"left":"yesterday","right":"Quá khứ đơn"},{"left":"just","right":"Hiện tại hoàn thành"},{"left":"last year","right":"Quá khứ đơn"},{"left":"ever","right":"Hiện tại hoàn thành"}],"explanationVi":"Phân loại dấu hiệu thời gian theo thì."}'::jsonb),
 ('b1-u01-l1-p4','b1-u01-l1','grammar_fill_blank',4,'practice','medium',false,'{"question":"Điền for hoặc since: \"I have known him ___ 2015.\"","acceptedAnswers":["since"],"explanationVi":"2015 là mốc thời gian cụ thể → since."}'::jsonb),
 ('b1-u01-l1-p5','b1-u01-l1','translation',5,'practice','medium',false,'{"question":"Dịch sang tiếng Anh:","sourceText":"Bạn đã từng ăn phở chưa?","acceptedAnswers":["Have you ever eaten pho?","Have you ever tried pho?","Have you ever had pho?"],"explanationVi":"Have you ever + V3: Have you ever eaten pho?"}'::jsonb),
 ('b1-u01-l1-p6','b1-u01-l1','error_correction',6,'practice','medium',false,'{"question":"Sửa lỗi trong câu:","sourceText":"Have you finished the report yesterday?","acceptedAnswers":["Did you finish the report yesterday?","Did you finish the report yesterday"],"explanationVi":"yesterday = quá khứ đơn: Did you finish...?"}'::jsonb),
 ('b1-u01-l1-p7','b1-u01-l1','grammar_fill_blank',7,'practice','medium',false,'{"question":"Chia động từ: \"They ___ (not call) yet.\"","acceptedAnswers":["haven''t called","have not called"],"explanationVi":"yet + phủ định → haven''t called."}'::jsonb),
 ('b1-u01-l1-q1','b1-u01-l1','multiple_choice',8,'quiz','easy',true,'{"question":"Chọn thì ĐÚNG: \"We ___ in Hanoi for five years.\"","options":[{"id":"a","text":"lived"},{"id":"b","text":"have lived"},{"id":"c","text":"are living"}],"correctOptionId":"b","explanationVi":"for + khoảng thời gian kéo dài đến nay → have lived."}'::jsonb),
 ('b1-u01-l1-q2','b1-u01-l1','grammar_fill_blank',9,'quiz','easy',true,'{"question":"Chia động từ: \"She ___ (already / finish) the test.\"","acceptedAnswers":["has already finished"],"explanationVi":"already + hoàn thành: has already finished."}'::jsonb),
 ('b1-u01-l1-q3','b1-u01-l1','multiple_choice',10,'quiz','medium',true,'{"question":"Chọn câu ĐÚNG với \"ago\":","options":[{"id":"a","text":"I have met him two years ago."},{"id":"b","text":"I met him two years ago."},{"id":"c","text":"I have been meeting him two years ago."}],"correctOptionId":"b","explanationVi":"ago = thời điểm quá khứ cụ thể → quá khứ đơn."}'::jsonb),
 ('b1-u01-l1-q4','b1-u01-l1','grammar_fill_blank',11,'quiz','medium',true,'{"question":"Điền for hoặc since: \"He has worked here ___ three years.\"","acceptedAnswers":["for"],"explanationVi":"three years = khoảng thời gian → for."}'::jsonb),
 ('b1-u01-l1-q5','b1-u01-l1','vocabulary_match',12,'quiz','medium',true,'{"question":"Nối từ với nghĩa:","pairs":[{"left":"already","right":"đã rồi"},{"left":"yet","right":"chưa"},{"left":"just","right":"vừa mới"},{"left":"ever","right":"đã từng"}],"explanationVi":"Ghép đúng từng trạng từ hoàn thành."}'::jsonb),
 ('b1-u01-l1-q6','b1-u01-l1','sentence_ordering',13,'quiz','hard',true,'{"question":"Sắp xếp thành câu đúng:","tokens":["Have","ever","you","sushi","eaten"],"correctOrder":[0,2,1,4,3],"explanationVi":"Have you ever eaten sushi?"}'::jsonb),
 ('b1-u01-l1-q7','b1-u01-l1','grammar_fill_blank',14,'quiz','hard',true,'{"question":"Chia động từ: \"I ___ (see) that film last night.\"","acceptedAnswers":["saw"],"explanationVi":"last night = thời điểm cụ thể → saw."}'::jsonb);
INSERT INTO learning_lessons (id, level_code, skill_code, unit_id, lesson_type, lesson_order, title, subtitle, duration_minutes, xp_reward, required_score_to_pass, content, theory_content) VALUES
 ('b1-u01-l2','B1','reading','b1-u01','normal',2,'Past Perfect','Had done: sắp xếp hai sự kiện trong quá khứ',10,20,70,'{}'::jsonb,
INSERT INTO learning_lesson_activities (id, lesson_id, activity_type, display_order, phase, difficulty, counts_toward_mastery, payload) VALUES
 ('b1-u01-l2-p1','b1-u01-l2','grammar_fill_blank',1,'practice','easy',false,'{"question":"Chia động từ: \"When I arrived, she ___ (already/leave).\"","acceptedAnswers":["had already left"],"explanationVi":"Sự kiện xảy ra trước: had already left."}'::jsonb),
 ('b1-u01-l2-p2','b1-u01-l2','multiple_choice',2,'practice','easy',false,'{"question":"Chọn câu ĐÚNG để diễn đạt sự kiện xảy ra trước:","options":[{"id":"a","text":"He ate before he left."},{"id":"b","text":"He had eaten before he left."},{"id":"c","text":"He eats before he left."}],"correctOptionId":"b","explanationVi":"Ăn xảy ra trước rời đi → had eaten."}'::jsonb),
 ('b1-u01-l2-p3','b1-u01-l2','vocabulary_match',3,'practice','easy',false,'{"question":"Nối từ/cụm từ với vai trò trong quá khứ hoàn thành:","pairs":[{"left":"by the time","right":"vào lúc mà"},{"left":"already","right":"đã rồi"},{"left":"before","right":"trước khi"},{"left":"after","right":"sau khi"}],"explanationVi":"Nhận biết dấu hiệu quá khứ hoàn thành."}'::jsonb),
 ('b1-u01-l2-p4','b1-u01-l2','grammar_fill_blank',4,'practice','medium',false,'{"question":"Chia động từ: \"By the time we got there, the party ___ (finish).\"","acceptedAnswers":["had finished"],"explanationVi":"Kết thúc trước khi chúng tôi đến: had finished."}'::jsonb),
 ('b1-u01-l2-p5','b1-u01-l2','translation',5,'practice','medium',false,'{"question":"Dịch sang tiếng Anh:","sourceText":"Anh ấy mệt vì đã làm việc cả ngày.","acceptedAnswers":["He was tired because he had worked all day.","He was tired because he had been working all day."],"explanationVi":"had worked xảy ra trước was tired."}'::jsonb),
 ('b1-u01-l2-p6','b1-u01-l2','error_correction',6,'practice','medium',false,'{"question":"Sửa lỗi:","sourceText":"When I called, she already left.","acceptedAnswers":["When I called, she had already left.","When I called, she had already left"],"explanationVi":"Sự kiện trước cần had + V3: had already left."}'::jsonb),
 ('b1-u01-l2-p7','b1-u01-l2','sentence_ordering',7,'practice','medium',false,'{"question":"Sắp xếp thành câu đúng:","tokens":["had","She","finished","already","when I arrived"],"correctOrder":[1,0,2,3,4],"explanationVi":"She had already finished when I arrived."}'::jsonb),
 ('b1-u01-l2-q1','b1-u01-l2','multiple_choice',8,'quiz','easy',true,'{"question":"Chọn câu ĐÚNG: \"I was hungry because I ___ not eaten.\"","options":[{"id":"a","text":"have"},{"id":"b","text":"had"},{"id":"c","text":"did"}],"correctOptionId":"b","explanationVi":"Đói vì chưa ăn trước đó → had not eaten."}'::jsonb),
 ('b1-u01-l2-q2','b1-u01-l2','grammar_fill_blank',9,'quiz','easy',true,'{"question":"Chia động từ: \"After she ___ (finish) dinner, she called me.\"","acceptedAnswers":["had finished"],"explanationVi":"Ăn xong trước khi gọi: had finished."}'::jsonb),
 ('b1-u01-l2-q3','b1-u01-l2','multiple_choice',10,'quiz','medium',true,'{"question":"Sự kiện nào dùng quá khứ hoàn thành trong câu: \"The bus had left when I arrived at the stop.\"","options":[{"id":"a","text":"I arrived"},{"id":"b","text":"The bus left"},{"id":"c","text":"Cả hai"}],"correctOptionId":"b","explanationVi":"Bus rời đi TRƯỚC khi tôi đến → had left."}'::jsonb),
 ('b1-u01-l2-q4','b1-u01-l2','grammar_fill_blank',11,'quiz','medium',true,'{"question":"Chia động từ: \"We ___ (never/see) snow before that winter.\"","acceptedAnswers":["had never seen"],"explanationVi":"Chưa từng thấy tuyết trước mùa đông đó: had never seen."}'::jsonb),
 ('b1-u01-l2-q5','b1-u01-l2','sentence_ordering',12,'quiz','hard',true,'{"question":"Sắp xếp thành câu đúng:","tokens":["arrived","By the time","the show","had","she","started"],"correctOrder":[1,4,0,3,2,5],"explanationVi":"By the time she arrived, the show had started."}'::jsonb),
 ('b1-u01-l2-q6','b1-u01-l2','vocabulary_match',13,'quiz','medium',true,'{"question":"Nối từ với nghĩa:","pairs":[{"left":"by the time","right":"vào lúc mà"},{"left":"before","right":"trước khi"},{"left":"after","right":"sau khi"}],"explanationVi":"Ghép đúng từng từ chỉ thứ tự thời gian."}'::jsonb),
 ('b1-u01-l2-q7','b1-u01-l2','grammar_fill_blank',14,'quiz','hard',true,'{"question":"Chia động từ: \"He was tired because he ___ (work) all night.\"","acceptedAnswers":["had worked"],"explanationVi":"Làm việc cả đêm trước khi mệt: had worked."}'::jsonb);
INSERT INTO learning_lessons (id, level_code, skill_code, unit_id, lesson_type, lesson_order, title, subtitle, duration_minutes, xp_reward, required_score_to_pass, content, theory_content) VALUES
 ('b1-u01-l3','B1','reading','b1-u01','normal',3,'Emotions & Feelings','Từ vựng: Cảm xúc & Tình cảm',10,20,70,'{}'::jsonb,
INSERT INTO learning_lesson_activities (id, lesson_id, activity_type, display_order, phase, difficulty, counts_toward_mastery, payload) VALUES
 ('b1-u01-l3-p1','b1-u01-l3','vocabulary_match',1,'practice','easy',false,'{"question":"Nối từ cảm xúc với nghĩa tiếng Việt:","pairs":[{"left":"proud","right":"tự hào"},{"left":"relieved","right":"nhẹ nhõm"},{"left":"shocked","right":"sốc"},{"left":"annoyed","right":"khó chịu"}],"explanationVi":"Ghép đúng từng từ cảm xúc."}'::jsonb),
 ('b1-u01-l3-p2','b1-u01-l3','vocabulary_match',2,'practice','easy',false,'{"question":"Nối từ với nghĩa:","pairs":[{"left":"admire","right":"ngưỡng mộ"},{"left":"amazed","right":"kinh ngạc"},{"left":"confident","right":"tự tin"},{"left":"disappointed","right":"thất vọng"}],"explanationVi":"Ghép đúng từng từ cảm xúc."}'::jsonb),
 ('b1-u01-l3-p3','b1-u01-l3','multiple_choice',3,'practice','easy',false,'{"question":"Cảm xúc nào diễn tả sự \"nhẹ nhõm\" sau khi lo lắng?","options":[{"id":"a","text":"frustrated"},{"id":"b","text":"relieved"},{"id":"c","text":"embarrassed"}],"correctOptionId":"b","explanationVi":"relieved = nhẹ nhõm sau lo lắng."}'::jsonb),
 ('b1-u01-l3-p4','b1-u01-l3','multiple_choice',4,'practice','medium',false,'{"question":"Điền từ phù hợp: \"She felt ___ when she forgot her speech in front of everyone.\"","options":[{"id":"a","text":"proud"},{"id":"b","text":"relieved"},{"id":"c","text":"embarrassed"}],"correctOptionId":"c","explanationVi":"Quên bài trước mọi người → embarrassed (xấu hổ)."}'::jsonb),
 ('b1-u01-l3-p5','b1-u01-l3','translation',5,'practice','medium',false,'{"question":"Dịch sang tiếng Anh:","sourceText":"Tôi cảm thấy tự hào về những gì mình đã đạt được.","acceptedAnswers":["I felt proud of what I had achieved.","I was proud of what I achieved.","I felt proud of what I achieved."],"explanationVi":"felt proud of what I had achieved."}'::jsonb),
 ('b1-u01-l3-p6','b1-u01-l3','multiple_choice',6,'practice','medium',false,'{"question":"Từ nào phù hợp: \"He was ___ with the traffic — it made him late every day.\"","options":[{"id":"a","text":"amazed"},{"id":"b","text":"frustrated"},{"id":"c","text":"confident"}],"correctOptionId":"b","explanationVi":"Tắc đường lặp đi lặp lại gây bực tức → frustrated."}'::jsonb),
 ('b1-u01-l3-p7','b1-u01-l3','vocabulary_match',7,'practice','easy',false,'{"question":"Nối từ còn lại với nghĩa:","pairs":[{"left":"frustrated","right":"nản lòng, bực tức"},{"left":"embarrassed","right":"xấu hổ, bối rối"}],"explanationVi":"Ghép đúng hai từ còn lại."}'::jsonb),
 ('b1-u01-l3-q1','b1-u01-l3','vocabulary_match',8,'quiz','easy',true,'{"question":"Nối từ cảm xúc với nghĩa:","pairs":[{"left":"shocked","right":"sốc"},{"left":"proud","right":"tự hào"},{"left":"relieved","right":"nhẹ nhõm"}],"explanationVi":"Ghép đúng từng cặp."}'::jsonb),
 ('b1-u01-l3-q2','b1-u01-l3','multiple_choice',9,'quiz','easy',true,'{"question":"Từ nào có nghĩa là \"kinh ngạc, choáng ngợp\"?","options":[{"id":"a","text":"annoyed"},{"id":"b","text":"amazed"},{"id":"c","text":"relieved"}],"correctOptionId":"b","explanationVi":"amazed = kinh ngạc, choáng ngợp."}'::jsonb),
 ('b1-u01-l3-q3','b1-u01-l3','multiple_choice',10,'quiz','medium',true,'{"question":"Điền từ phù hợp: \"I was ___ to hear she had won the competition.\"","options":[{"id":"a","text":"frustrated"},{"id":"b","text":"embarrassed"},{"id":"c","text":"amazed"}],"correctOptionId":"c","explanationVi":"Nghe tin chiến thắng → amazed (kinh ngạc)."}'::jsonb),
 ('b1-u01-l3-q4','b1-u01-l3','grammar_fill_blank',11,'quiz','medium',true,'{"question":"Điền từ cảm xúc đúng: \"She was ___ with the result because she expected to pass.\" (thất vọng)","acceptedAnswers":["disappointed"],"explanationVi":"Mong qua mà không qua → disappointed."}'::jsonb),
 ('b1-u01-l3-q5','b1-u01-l3','multiple_choice',12,'quiz','medium',true,'{"question":"Từ nào diễn tả cảm giác tin tưởng vào bản thân?","options":[{"id":"a","text":"embarrassed"},{"id":"b","text":"confident"},{"id":"c","text":"shocked"}],"correctOptionId":"b","explanationVi":"confident = tự tin vào bản thân."}'::jsonb),
 ('b1-u01-l3-q6','b1-u01-l3','sentence_ordering',13,'quiz','hard',true,'{"question":"Sắp xếp thành câu đúng:","tokens":["was","She","proud","had","of","what","she","achieved"],"correctOrder":[1,0,2,3,4,5,6,7],"explanationVi":"She was proud of what she had achieved."}'::jsonb),
 ('b1-u01-l3-q7','b1-u01-l3','vocabulary_match',14,'quiz','medium',true,'{"question":"Nối từ cảm xúc với tình huống phù hợp:","pairs":[{"left":"annoyed","right":"bị làm phiền liên tục"},{"left":"admire","right":"tôn trọng ai rất nhiều"},{"left":"frustrated","right":"kế hoạch bị cản trở"}],"explanationVi":"Ghép đúng từng tình huống."}'::jsonb);
INSERT INTO learning_lessons (id, level_code, skill_code, unit_id, lesson_type, lesson_order, title, subtitle, duration_minutes, xp_reward, required_score_to_pass, content, theory_content) VALUES
 ('b1-u01-l4','B1','reading','b1-u01','normal',4,'A Memorable Journey','Đọc hiểu: Một chuyến đi đáng nhớ',10,20,70,'{}'::jsonb,
INSERT INTO learning_lesson_activities (id, lesson_id, activity_type, display_order, phase, difficulty, counts_toward_mastery, payload) VALUES
 ('b1-u01-l4-p1','b1-u01-l4','multiple_choice',1,'practice','easy',false,'{"question":"Đây là chuyến đi một mình lần thứ mấy của Ana?","options":[{"id":"a","text":"Lần thứ hai"},{"id":"b","text":"Lần đầu tiên"},{"id":"c","text":"Lần thứ ba"}],"correctOptionId":"b","explanationVi":"\"travel alone for the first time\" → lần đầu tiên."}'::jsonb),
 ('b1-u01-l4-p2','b1-u01-l4','multiple_choice',2,'practice','easy',false,'{"question":"Ana phát hiện ra điều gì tại sân bay?","options":[{"id":"a","text":"Mất vé máy bay"},{"id":"b","text":"Bỏ quên hộ chiếu ở khách sạn"},{"id":"c","text":"Hành lý bị thất lạc"}],"correctOptionId":"b","explanationVi":"\"she had left her passport at the hotel\" → bỏ quên hộ chiếu."}'::jsonb),
 ('b1-u01-l4-p3','b1-u01-l4','multiple_choice',3,'practice','medium',false,'{"question":"Cảm xúc của Ana khi phát hiện sự cố là gì?","options":[{"id":"a","text":"Relieved and happy"},{"id":"b","text":"Shocked and frustrated"},{"id":"c","text":"Proud and confident"}],"correctOptionId":"b","explanationVi":"\"She was shocked and frustrated\" → sốc và bực tức."}'::jsonb),
 ('b1-u01-l4-p4','b1-u01-l4','vocabulary_match',4,'practice','easy',false,'{"question":"Nối từ trong bài với nghĩa:","pairs":[{"left":"memorable","right":"đáng nhớ"},{"left":"journey","right":"hành trình"},{"left":"unexpected","right":"bất ngờ"},{"left":"overcome","right":"vượt qua"}],"explanationVi":"Ghép đúng từng từ vựng trong bài."}'::jsonb),
 ('b1-u01-l4-p5','b1-u01-l4','multiple_choice',5,'practice','medium',false,'{"question":"Ai đã giúp Ana lấy lại hộ chiếu?","options":[{"id":"a","text":"Bạn của cô ấy"},{"id":"b","text":"Nhân viên sân bay"},{"id":"c","text":"Nhân viên khách sạn"}],"correctOptionId":"c","explanationVi":"\"a kind staff member brought her passport\" → nhân viên khách sạn."}'::jsonb),
 ('b1-u01-l4-p6','b1-u01-l4','multiple_choice',6,'practice','medium',false,'{"question":"Sau sự cố, Ana cảm thấy thế nào?","options":[{"id":"a","text":"Disappointed"},{"id":"b","text":"More confident than ever"},{"id":"c","text":"Embarrassed"}],"correctOptionId":"b","explanationVi":"\"Ana felt more confident than ever\" → tự tin hơn bao giờ hết."}'::jsonb),
 ('b1-u01-l4-p7','b1-u01-l4','grammar_fill_blank',7,'practice','medium',false,'{"question":"Hoàn thành theo bài: \"She ___ (always/want) to visit Vietnam.\"","acceptedAnswers":["had always wanted"],"explanationVi":"Mong muốn trước khi đặt vé: had always wanted."}'::jsonb),
 ('b1-u01-l4-q1','b1-u01-l4','multiple_choice',8,'quiz','easy',true,'{"question":"Ana đã để quên gì ở khách sạn?","options":[{"id":"a","text":"Vé máy bay"},{"id":"b","text":"Hộ chiếu"},{"id":"c","text":"Điện thoại"}],"correctOptionId":"b","explanationVi":"\"she had left her passport at the hotel\"."}'::jsonb),
 ('b1-u01-l4-q2','b1-u01-l4','multiple_choice',9,'quiz','easy',true,'{"question":"Ana đi đến thành phố nào ở Việt Nam?","options":[{"id":"a","text":"Hồ Chí Minh"},{"id":"b","text":"Đà Nẵng"},{"id":"c","text":"Hà Nội"}],"correctOptionId":"c","explanationVi":"\"booked a flight to Hanoi\" → Hà Nội."}'::jsonb),
 ('b1-u01-l4-q3','b1-u01-l4','multiple_choice',10,'quiz','medium',true,'{"question":"Tại sao Ana gọi là một người can đảm trong câu chuyện?","options":[{"id":"a","text":"Vì cô ấy đi du lịch một mình"},{"id":"b","text":"Vì cô ấy vượt qua thử thách và giữ bình tĩnh"},{"id":"c","text":"Vì cô ấy nói tiếng Việt"}],"correctOptionId":"b","explanationVi":"Cô giữ bình tĩnh và vượt qua thách thức → can đảm."}'::jsonb),
 ('b1-u01-l4-q4','b1-u01-l4','grammar_fill_blank',11,'quiz','medium',true,'{"question":"Hoàn thành: \"She has never ___ (forget) that journey.\"","acceptedAnswers":["forgotten"],"explanationVi":"has never forgotten = chưa bao giờ quên."}'::jsonb),
 ('b1-u01-l4-q5','b1-u01-l4','multiple_choice',12,'quiz','medium',true,'{"question":"Từ nào mô tả chuyến đi sau khi giải quyết sự cố?","options":[{"id":"a","text":"Terrible"},{"id":"b","text":"Amazing"},{"id":"c","text":"Boring"}],"correctOptionId":"b","explanationVi":"\"the rest of her trip was amazing\"."}'::jsonb),
 ('b1-u01-l4-q6','b1-u01-l4','vocabulary_match',13,'quiz','easy',true,'{"question":"Nối từ với nghĩa:","pairs":[{"left":"memorable","right":"đáng nhớ"},{"left":"overcome","right":"vượt qua"},{"left":"unexpected","right":"bất ngờ"}],"explanationVi":"Ghép đúng từng từ."}'::jsonb),
 ('b1-u01-l4-q7','b1-u01-l4','grammar_fill_blank',14,'quiz','hard',true,'{"question":"Chia động từ: \"When Ana arrived, she realised she ___ (leave) her passport.\"","acceptedAnswers":["had left"],"explanationVi":"Bỏ quên xảy ra trước khi nhận ra: had left."}'::jsonb);
