 ('b1-u01-l5-q3','b1-u01-l5','multiple_choice',3,'quiz','easy',true,'{"question":"Từ nào có nghĩa là \"tự hào\"?","options":[{"id":"a","text":"relieved"},{"id":"b","text":"proud"},{"id":"c","text":"frustrated"}],"correctOptionId":"b","explanationVi":"proud = tự hào."}'::jsonb),
 ('b1-u01-l5-q4','b1-u01-l5','grammar_fill_blank',4,'quiz','medium',true,'{"question":"Điền for hoặc since: \"He has studied here ___ 2019.\"","acceptedAnswers":["since"],"explanationVi":"2019 là mốc cụ thể → since."}'::jsonb),
 ('b1-u01-l5-q5','b1-u01-l5','multiple_choice',5,'quiz','medium',true,'{"question":"Câu nào ĐÚNG?","options":[{"id":"a","text":"When I got home, she already left."},{"id":"b","text":"When I got home, she had already left."},{"id":"c","text":"When I got home, she has already left."}],"correctOptionId":"b","explanationVi":"Rời đi trước khi tôi về: had already left."}'::jsonb),
 ('b1-u01-l5-q6','b1-u01-l5','vocabulary_match',6,'quiz','medium',true,'{"question":"Nối từ cảm xúc với nghĩa:","pairs":[{"left":"amazed","right":"kinh ngạc"},{"left":"annoyed","right":"khó chịu"},{"left":"confident","right":"tự tin"},{"left":"disappointed","right":"thất vọng"}],"explanationVi":"Ghép đúng từng cặp."}'::jsonb),
 ('b1-u01-l5-q7','b1-u01-l5','grammar_fill_blank',7,'quiz','medium',true,'{"question":"Chia động từ: \"By the time we arrived, they ___ (finish) the food.\"","acceptedAnswers":["had finished"],"explanationVi":"Kết thúc trước khi chúng tôi đến: had finished."}'::jsonb),
 ('b1-u01-l5-q8','b1-u01-l5','sentence_ordering',8,'quiz','hard',true,'{"question":"Sắp xếp thành câu đúng:","tokens":["Have","to","you","Paris","ever","been"],"correctOrder":[0,2,4,1,3,5],"explanationVi":"Have you ever been to Paris?"}'::jsonb),
