 ('b1-u01-l5-q10','b1-u01-l5','grammar_fill_blank',10,'quiz','hard',true,'{"question":"Chia động từ: \"She was ___ (embarrass) because she had made a mistake.\"","acceptedAnswers":["embarrassed"],"explanationVi":"embarrassed = xấu hổ (tính từ cảm xúc)."}'::jsonb);
