INSERT INTO learning_lesson_activities (id, lesson_id, activity_type, display_order, phase, difficulty, counts_toward_mastery, payload) VALUES
 ('b1-u02-l1-p1','b1-u02-l1','grammar_fill_blank',1,'practice','easy',false,'{"question":"Chia động từ: \"She ___ (study) all morning.\"","acceptedAnswers":["has been studying"],"explanationVi":"all morning + nhấn thời gian → has been studying."}'::jsonb),
 ('b1-u02-l1-p2','b1-u02-l1','multiple_choice',2,'practice','easy',false,'{"question":"Chọn câu ĐÚNG nhấn mạnh thời gian đang chờ:","options":[{"id":"a","text":"I have waited for two hours."},{"id":"b","text":"I have been waiting for two hours."},{"id":"c","text":"I am waiting for two hours."}],"correctOptionId":"b","explanationVi":"Nhấn thời gian kéo dài → have been waiting."}'::jsonb),
 ('b1-u02-l1-p3','b1-u02-l1','vocabulary_match',3,'practice','easy',false,'{"question":"Nối từ/cụm từ chỉ thời gian với nghĩa:","pairs":[{"left":"for","right":"trong khoảng thời gian"},{"left":"since","right":"kể từ mốc thời gian"},{"left":"all day","right":"cả ngày"},{"left":"how long","right":"bao lâu"}],"explanationVi":"Phân biệt for vs since."}'::jsonb),
 ('b1-u02-l1-p4','b1-u02-l1','grammar_fill_blank',4,'practice','medium',false,'{"question":"Đặt câu hỏi: \"___ you ___ (wait) long?\"","acceptedAnswers":["Have you been waiting"],"explanationVi":"Have you been waiting long?"}'::jsonb),
 ('b1-u02-l1-p5','b1-u02-l1','translation',5,'practice','medium',false,'{"question":"Dịch sang tiếng Anh:","sourceText":"Tôi đã học tiếng Anh được ba năm (và vẫn đang học).","acceptedAnswers":["I have been learning English for three years.","I''ve been learning English for three years.","I have been studying English for three years.","I''ve been studying English for three years."],"explanationVi":"have been learning/studying for three years."}'::jsonb),
 ('b1-u02-l1-p6','b1-u02-l1','error_correction',6,'practice','medium',false,'{"question":"Sửa lỗi:","sourceText":"I am working here since January.","acceptedAnswers":["I have been working here since January.","I''ve been working here since January."],"explanationVi":"since + khoảng dài → have been working."}'::jsonb),
 ('b1-u02-l1-p7','b1-u02-l1','grammar_fill_blank',7,'practice','medium',false,'{"question":"Chia động từ: \"How long ___ you ___ (know) her?\"","acceptedAnswers":["have you known"],"explanationVi":"know là stative verb → have known (không dùng been knowing)."}'::jsonb),
 ('b1-u02-l1-q1','b1-u02-l1','multiple_choice',8,'quiz','easy',true,'{"question":"Chọn thì ĐÚNG: \"He looks exhausted. He ___ all day.\"","options":[{"id":"a","text":"has worked"},{"id":"b","text":"has been working"},{"id":"c","text":"is working"}],"correctOptionId":"b","explanationVi":"Nhấn kết quả hiện tại (mệt) + thời gian → has been working."}'::jsonb),
