 ('b1-u02-l1-q3','b1-u02-l1','multiple_choice',10,'quiz','medium',true,'{"question":"Câu nào diễn tả hành động đã HOÀN THÀNH (nhấn kết quả)?","options":[{"id":"a","text":"I have been reading the report."},{"id":"b","text":"I have read the report."},{"id":"c","text":"I was reading the report."}],"correctOptionId":"b","explanationVi":"have read = xong, kết quả."}'::jsonb),
 ('b1-u02-l1-q4','b1-u02-l1','grammar_fill_blank',11,'quiz','medium',true,'{"question":"Chia động từ: \"She ___ (not/feel) well recently.\"","acceptedAnswers":["hasn''t been feeling","has not been feeling"],"explanationVi":"recently + phủ định → hasn''t been feeling."}'::jsonb),
 ('b1-u02-l1-q5','b1-u02-l1','sentence_ordering',12,'quiz','hard',true,'{"question":"Sắp xếp thành câu đúng:","tokens":["have","How long","here","been","you","working"],"correctOrder":[1,4,0,5,3,2],"explanationVi":"How long have you been working here?"}'::jsonb),
 ('b1-u02-l1-q6','b1-u02-l1','vocabulary_match',13,'quiz','medium',true,'{"question":"Nối từ với nghĩa:","pairs":[{"left":"recently","right":"gần đây"},{"left":"all day","right":"cả ngày"},{"left":"since","right":"kể từ"}],"explanationVi":"Ghép đúng từng cặp."}'::jsonb),
 ('b1-u02-l1-q7','b1-u02-l1','grammar_fill_blank',14,'quiz','hard',true,'{"question":"Chia động từ: \"I ___ (wait) for you for an hour!\"","acceptedAnswers":["have been waiting","''ve been waiting"],"explanationVi":"for + thời gian kéo dài → have been waiting."}'::jsonb);
