INSERT INTO learning_lesson_activities (id, lesson_id, activity_type, display_order, phase, difficulty, counts_toward_mastery, payload) VALUES
 ('b1-u02-l4-p1','b1-u02-l4','multiple_choice',1,'practice','easy',false,'{"question":"David đã chuyển đến Thành phố Hồ Chí Minh bao lâu?","options":[{"id":"a","text":"Ba tháng"},{"id":"b","text":"Sáu tháng"},{"id":"c","text":"Một năm"}],"correctOptionId":"b","explanationVi":"six months ago → sáu tháng."}'::jsonb),
 ('b1-u02-l4-p2','b1-u02-l4','multiple_choice',2,'practice','easy',false,'{"question":"David đang cố gắng học điều gì?","options":[{"id":"a","text":"Lái xe máy"},{"id":"b","text":"Tiếng Việt"},{"id":"c","text":"Nấu ăn"}],"correctOptionId":"b","explanationVi":"I have been trying to learn Vietnamese."}'::jsonb),
 ('b1-u02-l4-p3','b1-u02-l4','multiple_choice',3,'practice','medium',false,'{"question":"David gặp gỡ bạn bè mới ở đâu?","options":[{"id":"a","text":"Ở phố"},{"id":"b","text":"Trên mạng"},{"id":"c","text":"Ở chỗ làm"}],"correctOptionId":"c","explanationVi":"I have been meeting new people at work."}'::jsonb),
 ('b1-u02-l4-p4','b1-u02-l4','vocabulary_match',4,'practice','easy',false,'{"question":"Nối từ với nghĩa:","pairs":[{"left":"settle in","right":"ổn định, quen dần"},{"left":"challenge","right":"thách thức"},{"left":"neighbourhood","right":"khu phố"},{"left":"commute","right":"đi làm hàng ngày"}],"explanationVi":"Ghép đúng từng từ."}'::jsonb),
 ('b1-u02-l4-p5','b1-u02-l4','multiple_choice',5,'practice','medium',false,'{"question":"David cảm thấy thế nào bây giờ so với lúc mới đến?","options":[{"id":"a","text":"Cô đơn hơn"},{"id":"b","text":"Ổn định hơn"},{"id":"c","text":"Căng thẳng hơn"}],"correctOptionId":"b","explanationVi":"I feel much more settled now."}'::jsonb),
 ('b1-u02-l4-p6','b1-u02-l4','multiple_choice',6,'practice','medium',false,'{"question":"Thành phố nào David chuyển đến?","options":[{"id":"a","text":"Hà Nội"},{"id":"b","text":"Đà Nẵng"},{"id":"c","text":"Thành phố Hồ Chí Minh"}],"correctOptionId":"c","explanationVi":"I moved to Ho Chi Minh City."}'::jsonb),
 ('b1-u02-l4-p7','b1-u02-l4','grammar_fill_blank',7,'practice','medium',false,'{"question":"Hoàn thành theo bài: ''David has been ___ (get) used to the noise.''","acceptedAnswers":["getting"],"explanationVi":"have been getting = đang dần quen."}'::jsonb),
 ('b1-u02-l4-q1','b1-u02-l4','listening_choice',8,'quiz','easy',true,'{"audioText":"Hi, my name is David. I moved to Ho Chi Minh City six months ago. It has been an amazing experience, but also quite challenging. I have been trying to learn Vietnamese, and I have been making some progress.","question":"How long has David lived in Ho Chi Minh City?","options":[{"id":"a","text":"Three months"},{"id":"b","text":"Six months"},{"id":"c","text":"One year"}],"correctOptionId":"b","explanationVi":"six months ago → sáu tháng."}'::jsonb),
 ('b1-u02-l4-q2','b1-u02-l4','listening_choice',9,'quiz','easy',true,'{"audioText":"The city is very busy and I have been getting used to the noise and the traffic. I have been meeting new people at work, and I have already made some good friends.","question":"Where has David been meeting new people?","options":[{"id":"a","text":"At the gym"},{"id":"b","text":"In the neighbourhood"},{"id":"c","text":"At work"}],"correctOptionId":"c","explanationVi":"meeting new people at work."}'::jsonb),
 ('b1-u02-l4-q3','b1-u02-l4','multiple_choice',10,'quiz','medium',true,'{"question":"Thì nào David dùng để nói về quá trình học tiếng Việt?","options":[{"id":"a","text":"Present simple"},{"id":"b","text":"Present perfect continuous"},{"id":"c","text":"Past simple"}],"correctOptionId":"b","explanationVi":"have been trying = present perfect continuous."}'::jsonb),
 ('b1-u02-l4-q4','b1-u02-l4','grammar_fill_blank',11,'quiz','medium',true,'{"question":"Hoàn thành: ''I have already ___ some good friends.'' (make)","acceptedAnswers":["made"],"explanationVi":"have already made = đã kết bạn được."}'::jsonb),
 ('b1-u02-l4-q5','b1-u02-l4','multiple_choice',12,'quiz','medium',true,'{"question":"David mô tả trải nghiệm là:","options":[{"id":"a","text":"Amazing and boring"},{"id":"b","text":"Amazing and challenging"},{"id":"c","text":"Easy and relaxing"}],"correctOptionId":"b","explanationVi":"amazing experience, but also quite challenging."}'::jsonb),
 ('b1-u02-l4-q6','b1-u02-l4','vocabulary_match',13,'quiz','easy',true,'{"question":"Nối từ với nghĩa:","pairs":[{"left":"settle in","right":"ổn định, quen dần"},{"left":"challenge","right":"thách thức"},{"left":"neighbourhood","right":"khu phố"}],"explanationVi":"Ghép đúng từng từ."}'::jsonb),
 ('b1-u02-l4-q7','b1-u02-l4','listening_choice',14,'quiz','hard',true,'{"audioText":"I feel much more settled now than I did when I first arrived.","question":"How does David feel now compared to when he first arrived?","options":[{"id":"a","text":"More lonely"},{"id":"b","text":"More stressed"},{"id":"c","text":"More settled"}],"correctOptionId":"c","explanationVi":"much more settled now."}'::jsonb);
INSERT INTO learning_lessons (id, level_code, skill_code, unit_id, lesson_type, lesson_order, title, subtitle, duration_minutes, xp_reward, required_score_to_pass, content, theory_content) VALUES
 ('b1-u02-l5','B1','listening','b1-u02','unit_review',5,'Unit 2 Review','Ôn tập Unit 2: Trải nghiệm gần đây & Thay đổi',12,30,75,'{}'::jsonb,
INSERT INTO learning_lesson_activities (id, lesson_id, activity_type, display_order, phase, difficulty, counts_toward_mastery, payload) VALUES
 ('b1-u02-l5-q1','b1-u02-l5','grammar_fill_blank',1,'quiz','easy',true,'{"question":"Chia động từ: ''I ___ (study) English for two years now.''","acceptedAnswers":["have been studying","''ve been studying"],"explanationVi":"for + kéo dài đến nay → have been studying."}'::jsonb),
 ('b1-u02-l5-q2','b1-u02-l5','multiple_choice',2,'quiz','easy',true,'{"question":"Chọn câu nhấn mạnh thời gian chờ đang diễn ra:","options":[{"id":"a","text":"I waited for an hour."},{"id":"b","text":"I have been waiting for an hour."},{"id":"c","text":"I had waited for an hour."}],"correctOptionId":"b","explanationVi":"Đang chờ (còn kéo dài) → have been waiting."}'::jsonb),
 ('b1-u02-l5-q3','b1-u02-l5','multiple_choice',3,'quiz','easy',true,'{"question":"Từ nào có nghĩa là ''duy trì''?","options":[{"id":"a","text":"reduce"},{"id":"b","text":"develop"},{"id":"c","text":"maintain"}],"correctOptionId":"c","explanationVi":"maintain = duy trì."}'::jsonb),
 ('b1-u02-l5-q4','b1-u02-l5','grammar_fill_blank',4,'quiz','medium',true,'{"question":"Chia động từ: ''She was exhausted because she ___ (work) all day.''","acceptedAnswers":["had been working"],"explanationVi":"Giải thích trạng thái quá khứ: had been working."}'::jsonb),
 ('b1-u02-l5-q5','b1-u02-l5','multiple_choice',5,'quiz','medium',true,'{"question":"Chọn câu ĐÚNG với since:","options":[{"id":"a","text":"He has been working here since three years."},{"id":"b","text":"He has been working here since 2021."},{"id":"c","text":"He has been working here for 2021."}],"correctOptionId":"b","explanationVi":"since + mốc cụ thể: since 2021."}'::jsonb),
 ('b1-u02-l5-q6','b1-u02-l5','vocabulary_match',6,'quiz','medium',true,'{"question":"Nối từ với nghĩa:","pairs":[{"left":"diet","right":"chế độ ăn"},{"left":"habit","right":"thói quen"},{"left":"stress","right":"căng thẳng"},{"left":"lifestyle","right":"lối sống"}],"explanationVi":"Ghép đúng từng từ."}'::jsonb),
 ('b1-u02-l5-q7','b1-u02-l5','grammar_fill_blank',7,'quiz','medium',true,'{"question":"Chia động từ: ''How long ___ you ___ (know) her?''","acceptedAnswers":["have you known"],"explanationVi":"know là stative verb → have known."}'::jsonb),
 ('b1-u02-l5-q8','b1-u02-l5','sentence_ordering',8,'quiz','hard',true,'{"question":"Sắp xếp thành câu đúng:","tokens":["She","has","been","trying","to","reduce","her stress"],"correctOrder":[0,1,2,3,4,5,6],"explanationVi":"She has been trying to reduce her stress."}'::jsonb),
 ('b1-u02-l5-q9','b1-u02-l5','multiple_choice',9,'quiz','medium',true,'{"question":"Chọn câu nhấn mạnh KẾT QUẢ hoàn thành:","options":[{"id":"a","text":"I have been reading the book."},{"id":"b","text":"I have read the book."},{"id":"c","text":"I was reading the book."}],"correctOptionId":"b","explanationVi":"have read = đã đọc xong (kết quả)."}'::jsonb),
 ('b1-u02-l5-q10','b1-u02-l5','grammar_fill_blank',10,'quiz','hard',true,'{"question":"Chia động từ: ''His hands were dirty because he ___ (repair) the car.''","acceptedAnswers":["had been repairing"],"explanationVi":"Sửa xe liên tục trước khi tay bẩn: had been repairing."}'::jsonb);
INSERT INTO learning_lessons (id, level_code, skill_code, unit_id, lesson_type, lesson_order, title, subtitle, duration_minutes, xp_reward, required_score_to_pass, content, theory_content) VALUES
 ('b1-u03-l1','B1','reading','b1-u03','normal',1,'First & Second Conditional','If + present → will; If + past → would',10,20,70,'{}'::jsonb,
INSERT INTO learning_lesson_activities (id, lesson_id, activity_type, display_order, phase, difficulty, counts_toward_mastery, payload) VALUES
 ('b1-u03-l1-p1','b1-u03-l1','grammar_fill_blank',1,'practice','easy',false,'{"question":"First conditional: ''If it ___ (rain), I ___ (stay) at home.''","acceptedAnswers":["rains, I will stay","rains, I''ll stay"],"explanationVi":"If + present simple, will + V."}'::jsonb),
 ('b1-u03-l1-p2','b1-u03-l1','multiple_choice',2,'practice','easy',false,'{"question":"Chọn câu second conditional ĐÚNG:","options":[{"id":"a","text":"If I have money, I would travel."},{"id":"b","text":"If I had money, I would travel."},{"id":"c","text":"If I would have money, I would travel."}],"correctOptionId":"b","explanationVi":"If + past simple: If I had money."}'::jsonb),
 ('b1-u03-l1-p3','b1-u03-l1','vocabulary_match',3,'practice','easy',false,'{"question":"Nối từ với nghĩa:","pairs":[{"left":"unless","right":"trừ phi"},{"left":"provided that","right":"miễn là"},{"left":"as long as","right":"chừng nào"},{"left":"would","right":"sẽ (giả định)"}],"explanationVi":"Ghép đúng từng từ."}'::jsonb),
 ('b1-u03-l1-p4','b1-u03-l1','grammar_fill_blank',4,'practice','medium',false,'{"question":"Second conditional: ''If I ___ (be) you, I ___ (apologise).''","acceptedAnswers":["were, I would apologise","were, I''d apologise"],"explanationVi":"If I were you, I would apologise."}'::jsonb),
 ('b1-u03-l1-p5','b1-u03-l1','translation',5,'practice','medium',false,'{"question":"Dịch sang tiếng Anh (second conditional):","sourceText":"Nếu tôi là triệu phú, tôi sẽ du lịch vòng quanh thế giới.","acceptedAnswers":["If I were a millionaire, I would travel around the world.","If I was a millionaire, I would travel around the world."],"explanationVi":"If I were a millionaire, I would travel around the world."}'::jsonb),
 ('b1-u03-l1-p6','b1-u03-l1','error_correction',6,'practice','medium',false,'{"question":"Sửa lỗi:","sourceText":"If I would have more time, I would learn guitar.","acceptedAnswers":["If I had more time, I would learn guitar.","If I had more time, I''d learn guitar."],"explanationVi":"Mệnh đề if không dùng would: If I had more time."}'::jsonb),
 ('b1-u03-l1-p7','b1-u03-l1','multiple_choice',7,'practice','medium',false,'{"question":"Phân biệt: Câu nào là FIRST conditional (có thể xảy ra)?","options":[{"id":"a","text":"If I were a bird, I would fly."},{"id":"b","text":"If I had time, I would help you."},{"id":"c","text":"If she studies, she will pass."}],"correctOptionId":"c","explanationVi":"will = first conditional (thực tế có thể xảy ra)."}'::jsonb),
 ('b1-u03-l1-q1','b1-u03-l1','multiple_choice',8,'quiz','easy',true,'{"question":"Chọn câu ĐÚNG (first conditional):","options":[{"id":"a","text":"If it rains, I would stay at home."},{"id":"b","text":"If it rains, I will stay at home."},{"id":"c","text":"If it would rain, I will stay at home."}],"correctOptionId":"b","explanationVi":"First conditional: If + present simple, will + V."}'::jsonb),
 ('b1-u03-l1-q2','b1-u03-l1','grammar_fill_blank',9,'quiz','easy',true,'{"question":"Chia động từ: ''If she ___ (work) harder, she would get a promotion.''","acceptedAnswers":["worked"],"explanationVi":"Second conditional: If + past simple."}'::jsonb),
 ('b1-u03-l1-q3','b1-u03-l1','multiple_choice',10,'quiz','medium',true,'{"question":"Chọn câu second conditional ĐÚNG với to be:","options":[{"id":"a","text":"If I was you, I would accept."},{"id":"b","text":"If I am you, I will accept."},{"id":"c","text":"If I were you, I would accept."}],"correctOptionId":"c","explanationVi":"To be trong second conditional: were."}'::jsonb),
 ('b1-u03-l1-q4','b1-u03-l1','grammar_fill_blank',11,'quiz','medium',true,'{"question":"Chia động từ: ''If you leave now, you ___ (catch) the bus.''","acceptedAnswers":["will catch","''ll catch"],"explanationVi":"First conditional: will catch."}'::jsonb),
 ('b1-u03-l1-q5','b1-u03-l1','sentence_ordering',12,'quiz','hard',true,'{"question":"Sắp xếp thành câu second conditional:","tokens":["I","had","If","more money","would","I","travel"],"correctOrder":[2,0,1,3,5,4,6],"explanationVi":"If I had more money, I would travel."}'::jsonb),
 ('b1-u03-l1-q6','b1-u03-l1','vocabulary_match',13,'quiz','medium',true,'{"question":"Nối từ với nghĩa:","pairs":[{"left":"unless","right":"trừ phi"},{"left":"as long as","right":"miễn là"},{"left":"would","right":"sẽ (giả định)"}],"explanationVi":"Ghép đúng từng từ."}'::jsonb),
 ('b1-u03-l1-q7','b1-u03-l1','grammar_fill_blank',14,'quiz','hard',true,'{"question":"Chia động từ: ''Unless you hurry, you ___ (miss) the train.''","acceptedAnswers":["will miss","''ll miss"],"explanationVi":"unless = if not → will miss."}'::jsonb);
INSERT INTO learning_lessons (id, level_code, skill_code, unit_id, lesson_type, lesson_order, title, subtitle, duration_minutes, xp_reward, required_score_to_pass, content, theory_content) VALUES
 ('b1-u03-l2','B1','reading','b1-u03','normal',2,'Future Continuous','Will be doing: hành động đang xảy ra tại thời điểm tương lai',10,20,70,'{}'::jsonb,
INSERT INTO learning_lesson_activities (id, lesson_id, activity_type, display_order, phase, difficulty, counts_toward_mastery, payload) VALUES
 ('b1-u03-l2-p1','b1-u03-l2','grammar_fill_blank',1,'practice','easy',false,'{"question":"Chia động từ: ''This time tomorrow, I ___ (fly) to London.''","acceptedAnswers":["will be flying","''ll be flying"],"explanationVi":"will be + V-ing: will be flying."}'::jsonb),
 ('b1-u03-l2-p2','b1-u03-l2','multiple_choice',2,'practice','easy',false,'{"question":"Chọn câu future continuous ĐÚNG:","options":[{"id":"a","text":"She will study at 9 pm."},{"id":"b","text":"She will be studying at 9 pm."},{"id":"c","text":"She is studying at 9 pm."}],"correctOptionId":"b","explanationVi":"Đang học tại thời điểm 9 pm → will be studying."}'::jsonb),
 ('b1-u03-l2-p3','b1-u03-l2','vocabulary_match',3,'practice','easy',false,'{"question":"Nối từ với nghĩa:","pairs":[{"left":"this time tomorrow","right":"vào giờ này ngày mai"},{"left":"meanwhile","right":"trong khi đó"},{"left":"flight","right":"chuyến bay"},{"left":"board","right":"lên máy bay"}],"explanationVi":"Ghép đúng từng từ."}'::jsonb),
 ('b1-u03-l2-p4','b1-u03-l2','grammar_fill_blank',4,'practice','medium',false,'{"question":"Đặt câu hỏi lịch sự: ''___ you ___ (use) the car tonight?''","acceptedAnswers":["Will you be using"],"explanationVi":"Will you be using = hỏi lịch lịch sự."}'::jsonb),
 ('b1-u03-l2-p5','b1-u03-l2','translation',5,'practice','medium',false,'{"question":"Dịch sang tiếng Anh:","sourceText":"Vào giờ này tuần sau, tôi sẽ đang nằm trên bãi biển.","acceptedAnswers":["This time next week, I will be lying on a beach.","This time next week I''ll be lying on a beach."],"explanationVi":"This time next week, I will be lying on a beach."}'::jsonb),
 ('b1-u03-l2-p6','b1-u03-l2','error_correction',6,'practice','medium',false,'{"question":"Sửa lỗi:","sourceText":"At 8 pm tonight, I will be watch a film.","acceptedAnswers":["At 8 pm tonight, I will be watching a film.","At 8 pm tonight I''ll be watching a film."],"explanationVi":"will be + V-ing: will be watching."}'::jsonb),
 ('b1-u03-l2-p7','b1-u03-l2','multiple_choice',7,'practice','medium',false,'{"question":"Chọn câu phù hợp với tình huống: ''Vào 9 giờ sáng mai, tôi đang trong cuộc họp.''","options":[{"id":"a","text":"I will have a meeting at 9 am tomorrow."},{"id":"b","text":"I will be having a meeting at 9 am tomorrow."},{"id":"c","text":"I am having a meeting at 9 am tomorrow."}],"correctOptionId":"b","explanationVi":"Đang diễn ra tại thời điểm tương lai → will be having."}'::jsonb),
 ('b1-u03-l2-q1','b1-u03-l2','multiple_choice',8,'quiz','easy',true,'{"question":"Chọn câu ĐÚNG: ''At midnight, they ___.''","options":[{"id":"a","text":"will sleep"},{"id":"b","text":"will be sleeping"},{"id":"c","text":"are sleeping"}],"correctOptionId":"b","explanationVi":"Đang ngủ tại thời điểm nửa đêm → will be sleeping."}'::jsonb),
 ('b1-u03-l2-q2','b1-u03-l2','grammar_fill_blank',9,'quiz','easy',true,'{"question":"Chia động từ: ''This time next year, she ___ (study) at university.''","acceptedAnswers":["will be studying","''ll be studying"],"explanationVi":"Tại thời điểm tương lai cụ thể → will be studying."}'::jsonb),
 ('b1-u03-l2-q3','b1-u03-l2','multiple_choice',10,'quiz','medium',true,'{"question":"Câu hỏi nào lịch sự nhất để hỏi mượn xe?","options":[{"id":"a","text":"Do you use the car tonight?"},{"id":"b","text":"Will you be using the car tonight?"},{"id":"c","text":"Are you using the car tonight?"}],"correctOptionId":"b","explanationVi":"Will you be using = hỏi lịch lịch sự."}'::jsonb),
 ('b1-u03-l2-q4','b1-u03-l2','grammar_fill_blank',11,'quiz','medium',true,'{"question":"Chia động từ: ''They ___ (not/work) this time tomorrow.''","acceptedAnswers":["will not be working","won''t be working"],"explanationVi":"Phủ định: won''t be working."}'::jsonb),
 ('b1-u03-l2-q5','b1-u03-l2','sentence_ordering',12,'quiz','hard',true,'{"question":"Sắp xếp thành câu đúng:","tokens":["be","I","will","on a beach","lying","next week","this time"],"correctOrder":[6,5,0,1,2,4,3],"explanationVi":"This time next week, I will be lying on a beach."}'::jsonb),
 ('b1-u03-l2-q6','b1-u03-l2','vocabulary_match',13,'quiz','medium',true,'{"question":"Nối từ với nghĩa:","pairs":[{"left":"this time tomorrow","right":"vào giờ này ngày mai"},{"left":"meanwhile","right":"trong khi đó"},{"left":"board","right":"lên máy bay"}],"explanationVi":"Ghép đúng từng từ."}'::jsonb),
 ('b1-u03-l2-q7','b1-u03-l2','grammar_fill_blank',14,'quiz','hard',true,'{"question":"Chia động từ: ''At 10 am tomorrow, he ___ (present) his project.''","acceptedAnswers":["will be presenting","''ll be presenting"],"explanationVi":"Đang trình bày tại thời điểm tương lai → will be presenting."}'::jsonb);
INSERT INTO learning_lessons (id, level_code, skill_code, unit_id, lesson_type, lesson_order, title, subtitle, duration_minutes, xp_reward, required_score_to_pass, content, theory_content) VALUES
 ('b1-u03-l3','B1','reading','b1-u03','normal',3,'Work & Study Goals','Từ vựng: Mục tiêu công việc & Học tập',10,20,70,'{}'::jsonb,
INSERT INTO learning_lesson_activities (id, lesson_id, activity_type, display_order, phase, difficulty, counts_toward_mastery, payload) VALUES
 ('b1-u03-l3-p1','b1-u03-l3','vocabulary_match',1,'practice','easy',false,'{"question":"Nối từ với nghĩa tiếng Việt:","pairs":[{"left":"career","right":"sự nghiệp"},{"left":"degree","right":"bằng đại học"},{"left":"salary","right":"lương"},{"left":"promotion","right":"thăng chức"}],"explanationVi":"Ghép đúng từng từ."}'::jsonb),
 ('b1-u03-l3-p2','b1-u03-l3','vocabulary_match',2,'practice','easy',false,'{"question":"Nối từ với nghĩa:","pairs":[{"left":"apply","right":"nộp đơn"},{"left":"achieve","right":"đạt được"},{"left":"succeed","right":"thành công"},{"left":"opportunity","right":"cơ hội"}],"explanationVi":"Ghép đúng từng từ."}'::jsonb),
 ('b1-u03-l3-p3','b1-u03-l3','multiple_choice',3,'practice','easy',false,'{"question":"Từ nào có nghĩa là ''bằng cấp, chứng chỉ''?","options":[{"id":"a","text":"salary"},{"id":"b","text":"qualification"},{"id":"c","text":"promotion"}],"correctOptionId":"b","explanationVi":"qualification = bằng cấp, chứng chỉ."}'::jsonb),
 ('b1-u03-l3-p4','b1-u03-l3','multiple_choice',4,'practice','medium',false,'{"question":"Điền từ phù hợp: ''She is going to ___ for a job at Google.''","options":[{"id":"a","text":"achieve"},{"id":"b","text":"apply"},{"id":"c","text":"succeed"}],"correctOptionId":"b","explanationVi":"apply for = nộp đơn ứng tuyển."}'::jsonb),
