 ('b1-u03-l3-q3','b1-u03-l3','multiple_choice',10,'quiz','medium',true,'{"question":"Điền từ đúng: ''This job is a great ___ to learn new skills.''","options":[{"id":"a","text":"challenge"},{"id":"b","text":"opportunity"},{"id":"c","text":"qualification"}],"correctOptionId":"b","explanationVi":"opportunity = cơ hội."}'::jsonb),
