 ('b1-u03-l3-q5','b1-u03-l3','vocabulary_match',12,'quiz','medium',true,'{"question":"Nối từ với nghĩa:","pairs":[{"left":"career","right":"sự nghiệp"},{"left":"degree","right":"bằng đại học"},{"left":"salary","right":"lương"},{"left":"challenge","right":"thách thức"}],"explanationVi":"Ghép đúng bốn từ."}'::jsonb),
 ('b1-u03-l3-q6','b1-u03-l3','sentence_ordering',13,'quiz','hard',true,'{"question":"Sắp xếp thành câu đúng:","tokens":["will","If","a degree","I","I","get","more opportunities","have"],"correctOrder":[1,3,5,2,4,7,6,8],"explanationVi":"If I get a degree, I will have more opportunities."}'::jsonb),
