INSERT INTO learning_lessons (id, level_code, skill_code, unit_id, lesson_type, lesson_order, title, subtitle, duration_minutes, xp_reward, required_score_to_pass, content, theory_content) VALUES
 ('b1-u03-l4','B1','reading','b1-u03','normal',4,'Chasing a Dream Job','Đọc hiểu: Theo đuổi công việc mơ ước',10,20,70,'{}'::jsonb,
INSERT INTO learning_lesson_activities (id, lesson_id, activity_type, display_order, phase, difficulty, counts_toward_mastery, payload) VALUES
 ('b1-u03-l4-p1','b1-u03-l4','multiple_choice',1,'practice','easy',false,'{"question":"Linh muốn trở thành nghề gì?","options":[{"id":"a","text":"Bác sĩ"},{"id":"b","text":"Nhà thiết kế đồ họa"},{"id":"c","text":"Giáo viên"}],"correctOptionId":"b","explanationVi":"''She has always wanted to be a graphic designer.''"}'::jsonb),
 ('b1-u03-l4-p2','b1-u03-l4','multiple_choice',2,'practice','easy',false,'{"question":"Linh tốt nghiệp bao lâu trước?","options":[{"id":"a","text":"Một năm"},{"id":"b","text":"Hai năm"},{"id":"c","text":"Ba năm"}],"correctOptionId":"b","explanationVi":"''got a degree two years ago'' → hai năm trước."}'::jsonb),
 ('b1-u03-l4-p3','b1-u03-l4','multiple_choice',3,'practice','medium',false,'{"question":"Điều gì xảy ra khi Linh bị từ chối nhiều lần?","options":[{"id":"a","text":"Cô bỏ cuộc"},{"id":"b","text":"Cô không bao giờ bỏ cuộc"},{"id":"c","text":"Cô đổi ngành học"}],"correctOptionId":"b","explanationVi":"''she never gave up'' → không bao giờ bỏ cuộc."}'::jsonb),
 ('b1-u03-l4-p4','b1-u03-l4','vocabulary_match',4,'practice','easy',false,'{"question":"Nối từ với nghĩa:","pairs":[{"left":"passion","right":"đam mê"},{"left":"determination","right":"quyết tâm"},{"left":"internship","right":"thực tập"},{"left":"portfolio","right":"hồ sơ tác phẩm"}],"explanationVi":"Ghép đúng từng từ."}'::jsonb),
 ('b1-u03-l4-p5','b1-u03-l4','multiple_choice',5,'practice','medium',false,'{"question":"Nếu được nhận vào agency, Linh sẽ làm gì?","options":[{"id":"a","text":"Mở công ty riêng"},{"id":"b","text":"Làm việc với những nhà thiết kế giỏi nhất"},{"id":"c","text":"Quay lại học đại học"}],"correctOptionId":"b","explanationVi":"''she will be working with some of the best designers.''"}'::jsonb),
 ('b1-u03-l4-p6','b1-u03-l4','grammar_fill_blank',6,'practice','medium',false,'{"question":"Hoàn thành theo bài: ''If she gets the job, she ___ (work) with top designers.''","acceptedAnswers":["will be working"],"explanationVi":"First conditional + future continuous: will be working."}'::jsonb),
 ('b1-u03-l4-p7','b1-u03-l4','multiple_choice',7,'practice','medium',false,'{"question":"Linh nộp đơn vào đâu tháng trước?","options":[{"id":"a","text":"Một trường đại học"},{"id":"b","text":"Một agency thiết kế hàng đầu"},{"id":"c","text":"Một tạp chí thời trang"}],"correctOptionId":"b","explanationVi":"''applied for a position at a top design agency.''"}'::jsonb),
 ('b1-u03-l4-q1','b1-u03-l4','multiple_choice',8,'quiz','easy',true,'{"question":"Linh học ngành gì ở đại học?","options":[{"id":"a","text":"Kinh tế"},{"id":"b","text":"Mỹ thuật"},{"id":"c","text":"Công nghệ"}],"correctOptionId":"b","explanationVi":"''She studied art at university.''"}'::jsonb),
 ('b1-u03-l4-q2','b1-u03-l4','multiple_choice',9,'quiz','easy',true,'{"question":"Linh đã làm gì từ khi tốt nghiệp?","options":[{"id":"a","text":"Dạy học"},{"id":"b","text":"Du lịch"},{"id":"c","text":"Xây dựng portfolio và nộp đơn xin việc"}],"correctOptionId":"c","explanationVi":"''building her portfolio and applying for jobs.''"}'::jsonb),
 ('b1-u03-l4-q3','b1-u03-l4','multiple_choice',10,'quiz','medium',true,'{"question":"Cấu trúc ngữ pháp nào được dùng: ''If she gets the job, she will be working...''?","options":[{"id":"a","text":"Second conditional + past simple"},{"id":"b","text":"First conditional + future continuous"},{"id":"c","text":"Third conditional + past perfect"}],"correctOptionId":"b","explanationVi":"First conditional + future continuous."}'::jsonb),
 ('b1-u03-l4-q4','b1-u03-l4','grammar_fill_blank',11,'quiz','medium',true,'{"question":"Hoàn thành: ''She has been ___ for jobs since graduation.'' (apply)","acceptedAnswers":["applying"],"explanationVi":"has been applying = present perfect continuous."}'::jsonb),
 ('b1-u03-l4-q5','b1-u03-l4','multiple_choice',12,'quiz','medium',true,'{"question":"Linh tin rằng điều gì dẫn đến thành công?","options":[{"id":"a","text":"May mắn và tiền bạc"},{"id":"b","text":"Đam mê và quyết tâm"},{"id":"c","text":"Bằng cấp và kinh nghiệm"}],"correctOptionId":"b","explanationVi":"''passion and determination'' → đam mê và quyết tâm."}'::jsonb),
 ('b1-u03-l4-q6','b1-u03-l4','vocabulary_match',13,'quiz','easy',true,'{"question":"Nối từ với nghĩa:","pairs":[{"left":"passion","right":"đam mê"},{"left":"determination","right":"quyết tâm"},{"left":"portfolio","right":"hồ sơ tác phẩm"}],"explanationVi":"Ghép đúng từng từ."}'::jsonb),
 ('b1-u03-l4-q7','b1-u03-l4','grammar_fill_blank',14,'quiz','hard',true,'{"question":"Chia động từ: ''This time next year, she ___ (lead) her own team.''","acceptedAnswers":["will be leading","might be leading"],"explanationVi":"Future continuous: will be leading (hoặc might be leading)."}'::jsonb);
