INSERT INTO learning_lesson_activities (id, lesson_id, activity_type, display_order, phase, difficulty, counts_toward_mastery, payload) VALUES
 ('b1-u03-l5-q1','b1-u03-l5','grammar_fill_blank',1,'quiz','easy',true,'{"question":"First conditional: ''If she studies hard, she ___ (pass) the exam.''","acceptedAnswers":["will pass","''ll pass"],"explanationVi":"First conditional: will + V."}'::jsonb),
 ('b1-u03-l5-q2','b1-u03-l5','multiple_choice',2,'quiz','easy',true,'{"question":"Chọn câu second conditional ĐÚNG:","options":[{"id":"a","text":"If I have more money, I would travel."},{"id":"b","text":"If I had more money, I would travel."},{"id":"c","text":"If I would have more money, I would travel."}],"correctOptionId":"b","explanationVi":"Second conditional: If + past simple, would."}'::jsonb),
 ('b1-u03-l5-q3','b1-u03-l5','multiple_choice',3,'quiz','easy',true,'{"question":"Từ nào có nghĩa là ''thăng chức''?","options":[{"id":"a","text":"degree"},{"id":"b","text":"promotion"},{"id":"c","text":"career"}],"correctOptionId":"b","explanationVi":"promotion = thăng chức."}'::jsonb),
 ('b1-u03-l5-q4','b1-u03-l5','grammar_fill_blank',4,'quiz','medium',true,'{"question":"Chia động từ: ''This time tomorrow, I ___ (fly) to Singapore.''","acceptedAnswers":["will be flying","''ll be flying"],"explanationVi":"Future continuous: will be flying."}'::jsonb),
 ('b1-u03-l5-q5','b1-u03-l5','multiple_choice',5,'quiz','medium',true,'{"question":"Câu nào ĐÚNG với ''unless''?","options":[{"id":"a","text":"Unless you hurry, you will miss the train."},{"id":"b","text":"Unless you hurry, you would miss the train."},{"id":"c","text":"Unless you would hurry, you will miss the train."}],"correctOptionId":"a","explanationVi":"unless = if not → will miss."}'::jsonb),
 ('b1-u03-l5-q6','b1-u03-l5','vocabulary_match',6,'quiz','medium',true,'{"question":"Nối từ với nghĩa:","pairs":[{"left":"career","right":"sự nghiệp"},{"left":"opportunity","right":"cơ hội"},{"left":"achieve","right":"đạt được"},{"left":"qualify","right":"bằng cấp"}],"explanationVi":"Ghép đúng từng từ."}'::jsonb),
 ('b1-u03-l5-q7','b1-u03-l5','grammar_fill_blank',7,'quiz','medium',true,'{"question":"Second conditional với to be: ''If I ___ (be) you, I would apply.''","acceptedAnswers":["were"],"explanationVi":"To be trong second conditional: were."}'::jsonb),
 ('b1-u03-l5-q8','b1-u03-l5','sentence_ordering',8,'quiz','hard',true,'{"question":"Sắp xếp thành câu đúng:","tokens":["be","At 9 pm","will","she","studying","tonight"],"correctOrder":[1,3,2,0,4,5],"explanationVi":"At 9 pm tonight, she will be studying."}'::jsonb),
 ('b1-u03-l5-q9','b1-u03-l5','multiple_choice',9,'quiz','medium',true,'{"question":"Chọn câu phù hợp hỏi lịch lịch sự:","options":[{"id":"a","text":"Do you use the car tonight?"},{"id":"b","text":"Will you be using the car tonight?"},{"id":"c","text":"Are you going to use the car tonight?"}],"correctOptionId":"b","explanationVi":"Will you be using = hỏi lịch lịch sự."}'::jsonb),
 ('b1-u03-l5-q10','b1-u03-l5','grammar_fill_blank',10,'quiz','hard',true,'{"question":"Chia động từ: ''If she gets the job, she ___ (work) with top designers.''","acceptedAnswers":["will be working"],"explanationVi":"First conditional + future continuous: will be working."}'::jsonb);
INSERT INTO learning_lessons (id, level_code, skill_code, unit_id, lesson_type, lesson_order, title, subtitle, duration_minutes, xp_reward, required_score_to_pass, content, theory_content) VALUES
 ('b1-u04-l1','B1','reading','b1-u04','normal',1,'Third Conditional','If + had done, would have done: quá khứ không thể thay đổi',10,20,70,'{}'::jsonb,
INSERT INTO learning_lesson_activities (id, lesson_id, activity_type, display_order, phase, difficulty, counts_toward_mastery, payload) VALUES
 ('b1-u04-l1-p1','b1-u04-l1','grammar_fill_blank',1,'practice','easy',false,'{"question":"Third conditional: ''If I ___ (study) harder, I ___ (pass) the exam.''","acceptedAnswers":["had studied, I would have passed","had studied, I''d have passed"],"explanationVi":"If + had done, would have done."}'::jsonb),
 ('b1-u04-l1-p2','b1-u04-l1','multiple_choice',2,'practice','easy',false,'{"question":"Chọn câu third conditional ĐÚNG:","options":[{"id":"a","text":"If I would have left earlier, I would have caught the bus."},{"id":"b","text":"If I had left earlier, I would have caught the bus."},{"id":"c","text":"If I left earlier, I would have caught the bus."}],"correctOptionId":"b","explanationVi":"If + had + V3: If I had left earlier."}'::jsonb),
 ('b1-u04-l1-p3','b1-u04-l1','vocabulary_match',3,'practice','easy',false,'{"question":"Nối từ với nghĩa:","pairs":[{"left":"would have","right":"đã có thể (giả định quá khứ)"},{"left":"regret","right":"hối tiếc"},{"left":"otherwise","right":"nếu không thì"},{"left":"consequence","right":"hậu quả"}],"explanationVi":"Ghép đúng từng từ."}'::jsonb),
 ('b1-u04-l1-p4','b1-u04-l1','grammar_fill_blank',4,'practice','medium',false,'{"question":"Chia động từ: ''She ___ (pass) if she ___ (study) harder.''","acceptedAnswers":["would have passed, had studied","''d have passed, ''d studied"],"explanationVi":"would have passed if she had studied."}'::jsonb),
 ('b1-u04-l1-p5','b1-u04-l1','translation',5,'practice','medium',false,'{"question":"Dịch sang tiếng Anh:","sourceText":"Giá mà tôi đi sớm hơn, tôi đã bắt kịp xe buýt.","acceptedAnswers":["If I had left earlier, I would have caught the bus.","If I''d left earlier, I''d have caught the bus."],"explanationVi":"If I had left earlier, I would have caught the bus."}'::jsonb),
 ('b1-u04-l1-p6','b1-u04-l1','error_correction',6,'practice','medium',false,'{"question":"Sửa lỗi:","sourceText":"If I would have studied, I would have passed.","acceptedAnswers":["If I had studied, I would have passed.","If I''d studied, I would have passed."],"explanationVi":"Mệnh đề if: had studied (không dùng would have)."}'::jsonb),
 ('b1-u04-l1-p7','b1-u04-l1','multiple_choice',7,'practice','medium',false,'{"question":"Câu nào là THIRD conditional?","options":[{"id":"a","text":"If I have time, I will help you."},{"id":"b","text":"If I had time, I would help you."},{"id":"c","text":"If I had had time, I would have helped you."}],"correctOptionId":"c","explanationVi":"Third conditional: had had → would have helped."}'::jsonb),
 ('b1-u04-l1-q1','b1-u04-l1','multiple_choice',8,'quiz','easy',true,'{"question":"Chọn câu ĐÚNG:","options":[{"id":"a","text":"If she had known, she would have come."},{"id":"b","text":"If she would have known, she would have come."},{"id":"c","text":"If she knew, she would have come."}],"correctOptionId":"a","explanationVi":"If + had known → would have come."}'::jsonb),
 ('b1-u04-l1-q2','b1-u04-l1','grammar_fill_blank',9,'quiz','easy',true,'{"question":"Chia động từ: ''If he ___ (not be) late, they ___ (not miss) the flight.''","acceptedAnswers":["hadn''t been, would not have missed","hadn''t been, wouldn''t have missed"],"explanationVi":"hadn''t been late → wouldn''t have missed."}'::jsonb),
 ('b1-u04-l1-q3','b1-u04-l1','multiple_choice',10,'quiz','medium',true,'{"question":"Third conditional nói về:","options":[{"id":"a","text":"Tình huống có thể xảy ra trong tương lai"},{"id":"b","text":"Tình huống giả định trong hiện tại"},{"id":"c","text":"Tình huống không thể thay đổi trong quá khứ"}],"correctOptionId":"c","explanationVi":"Third conditional = giả định quá khứ không thể thay đổi."}'::jsonb),
 ('b1-u04-l1-q4','b1-u04-l1','grammar_fill_blank',11,'quiz','medium',true,'{"question":"Chia động từ: ''I ___ (call) you if I ___ (know) your number.''","acceptedAnswers":["would have called, had known","''d have called, ''d known"],"explanationVi":"would have called if I had known."}'::jsonb),
 ('b1-u04-l1-q5','b1-u04-l1','sentence_ordering',12,'quiz','hard',true,'{"question":"Sắp xếp thành câu đúng:","tokens":["she","had","studied","If","would have","she","passed","harder"],"correctOrder":[3,0,1,2,7,5,4,6],"explanationVi":"If she had studied harder, she would have passed."}'::jsonb),
 ('b1-u04-l1-q6','b1-u04-l1','vocabulary_match',13,'quiz','medium',true,'{"question":"Nối từ với nghĩa:","pairs":[{"left":"regret","right":"hối tiếc"},{"left":"otherwise","right":"nếu không thì"},{"left":"consequence","right":"hậu quả"}],"explanationVi":"Ghép đúng từng từ."}'::jsonb),
 ('b1-u04-l1-q7','b1-u04-l1','grammar_fill_blank',14,'quiz','hard',true,'{"question":"Hoàn thành: ''She would have been on time if she ___ (leave) earlier.''","acceptedAnswers":["had left"],"explanationVi":"had left = điều kiện giả định quá khứ."}'::jsonb);
INSERT INTO learning_lessons (id, level_code, skill_code, unit_id, lesson_type, lesson_order, title, subtitle, duration_minutes, xp_reward, required_score_to_pass, content, theory_content) VALUES
 ('b1-u04-l2','B1','reading','b1-u04','normal',2,'Should have / Might have / Could have','Hối tiếc, phê bình và suy đoán về quá khứ',10,20,70,'{}'::jsonb,
INSERT INTO learning_lesson_activities (id, lesson_id, activity_type, display_order, phase, difficulty, counts_toward_mastery, payload) VALUES
 ('b1-u04-l2-p1','b1-u04-l2','grammar_fill_blank',1,'practice','easy',false,'{"question":"Hoàn thành (hối tiếc): ''I ___ (study) more before the exam.''","acceptedAnswers":["should have studied"],"explanationVi":"should have + V3 = hối tiếc."}'::jsonb),
 ('b1-u04-l2-p2','b1-u04-l2','multiple_choice',2,'practice','easy',false,'{"question":"Chọn câu ĐÚNG để diễn đạt ''có lẽ cô ấy đã quên'':","options":[{"id":"a","text":"She should have forgotten."},{"id":"b","text":"She might have forgotten."},{"id":"c","text":"She could have forgotten the meeting."}],"correctOptionId":"b","explanationVi":"might have = có lẽ đã (không chắc)."}'::jsonb),
 ('b1-u04-l2-p3','b1-u04-l2','vocabulary_match',3,'practice','easy',false,'{"question":"Nối cấu trúc với nghĩa:","pairs":[{"left":"should have","right":"lẽ ra nên đã"},{"left":"might have","right":"có lẽ đã"},{"left":"could have","right":"đã có thể"},{"left":"must have","right":"chắc chắn đã"}],"explanationVi":"Phân biệt bốn cấu trúc."}'::jsonb),
 ('b1-u04-l2-p4','b1-u04-l2','grammar_fill_blank',4,'practice','medium',false,'{"question":"Hoàn thành (phê bình): ''You ___ (tell) me about the problem earlier!''","acceptedAnswers":["should have told"],"explanationVi":"should have told = lẽ ra phải nói."}'::jsonb),
 ('b1-u04-l2-p5','b1-u04-l2','translation',5,'practice','medium',false,'{"question":"Dịch sang tiếng Anh:","sourceText":"Lẽ ra tôi không nên nói điều đó.","acceptedAnswers":["I shouldn''t have said that.","I should not have said that."],"explanationVi":"I shouldn''t have said that."}'::jsonb),
 ('b1-u04-l2-p6','b1-u04-l2','error_correction',6,'practice','medium',false,'{"question":"Sửa lỗi:","sourceText":"She might has taken the wrong bus.","acceptedAnswers":["She might have taken the wrong bus.","She might have taken the wrong bus"],"explanationVi":"Sau modal always dùng have (không chia): might have."}'::jsonb),
 ('b1-u04-l2-p7','b1-u04-l2','multiple_choice',7,'practice','medium',false,'{"question":"Chọn câu ĐÚNG để nói về suy đoán chắc chắn:","options":[{"id":"a","text":"He might have been tired."},{"id":"b","text":"He must have been tired — he slept straight away."},{"id":"c","text":"He could have been tired."}],"correctOptionId":"b","explanationVi":"must have = chắc chắn đã (suy đoán mạnh với bằng chứng)."}'::jsonb),
 ('b1-u04-l2-q1','b1-u04-l2','multiple_choice',8,'quiz','easy',true,'{"question":"Chọn câu ĐÚNG (hối tiếc):","options":[{"id":"a","text":"I should study more."},{"id":"b","text":"I should have studied more."},{"id":"c","text":"I should had studied more."}],"correctOptionId":"b","explanationVi":"should have + V3: should have studied."}'::jsonb),
 ('b1-u04-l2-q2','b1-u04-l2','grammar_fill_blank',9,'quiz','easy',true,'{"question":"Chia động từ: ''She ___ (might/take) the wrong train.''","acceptedAnswers":["might have taken"],"explanationVi":"might have taken = có lẽ đã đi nhầm."}'::jsonb),
 ('b1-u04-l2-q3','b1-u04-l2','multiple_choice',10,'quiz','medium',true,'{"question":"Câu nào diễn đạt CƠ HỘI BỊ BỎ LỠ?","options":[{"id":"a","text":"You should have helped."},{"id":"b","text":"You could have helped."},{"id":"c","text":"You must have helped."}],"correctOptionId":"b","explanationVi":"could have = đã có thể (cơ hội bị bỏ lỡ)."}'::jsonb),
 ('b1-u04-l2-q4','b1-u04-l2','grammar_fill_blank',11,'quiz','medium',true,'{"question":"Hoàn thành: ''He fell asleep straight away. He ___ (must/be) very tired.''","acceptedAnswers":["must have been"],"explanationVi":"Bằng chứng rõ ràng → must have been."}'::jsonb),
 ('b1-u04-l2-q5','b1-u04-l2','sentence_ordering',12,'quiz','hard',true,'{"question":"Sắp xếp thành câu đúng:","tokens":["should","You","the","have","told","me","truth"],"correctOrder":[1,0,3,2,4,5,6],"explanationVi":"You should have told me the truth."}'::jsonb),
 ('b1-u04-l2-q6','b1-u04-l2','vocabulary_match',13,'quiz','medium',true,'{"question":"Nối cấu trúc với nghĩa:","pairs":[{"left":"should have","right":"lẽ ra nên"},{"left":"might have","right":"có lẽ đã"},{"left":"must have","right":"chắc chắn đã"}],"explanationVi":"Ghép đúng từng cấu trúc."}'::jsonb),
 ('b1-u04-l2-q7','b1-u04-l2','grammar_fill_blank',14,'quiz','hard',true,'{"question":"Hoàn thành (phê bình): ''You ___ (shouldn''t/say) that to her — she was upset.''","acceptedAnswers":["shouldn''t have said","should not have said"],"explanationVi":"shouldn''t have said = lẽ ra không nên nói."}'::jsonb);
