 ('b1-u04-l3-p1','b1-u04-l3','vocabulary_match',1,'practice','easy',false,'{"question":"Nối từ với nghĩa tiếng Việt:","pairs":[{"left":"regret","right":"hối tiếc"},{"left":"blame","right":"đổ lỗi"},{"left":"fault","right":"lỗi"},{"left":"guilty","right":"tội lỗi, có lỗi"}],"explanationVi":"Ghép đúng từng từ."}'::jsonb),
 ('b1-u04-l3-p2','b1-u04-l3','vocabulary_match',2,'practice','easy',false,'{"question":"Nối từ với nghĩa:","pairs":[{"left":"ashamed","right":"hổ thẹn"},{"left":"forgive","right":"tha thứ"},{"left":"apologise","right":"xin lỗi"},{"left":"consequence","right":"hậu quả"}],"explanationVi":"Ghép đúng từng từ."}'::jsonb),
 ('b1-u04-l3-p3','b1-u04-l3','multiple_choice',3,'practice','easy',false,'{"question":"Từ nào có nghĩa là ''tha thứ''?","options":[{"id":"a","text":"blame"},{"id":"b","text":"forgive"},{"id":"c","text":"regret"}],"correctOptionId":"b","explanationVi":"forgive = tha thứ."}'::jsonb),
 ('b1-u04-l3-p4','b1-u04-l3','multiple_choice',4,'practice','medium',false,'{"question":"Điền từ phù hợp: ''It was ___ — I made the wrong decision.'' (lỗi của tôi)","options":[{"id":"a","text":"my mistake"},{"id":"b","text":"my fault"},{"id":"c","text":"both a and b"}],"correctOptionId":"c","explanationVi":"Both ''my mistake'' and ''my fault'' đúng trong ngữ cảnh này."}'::jsonb),
 ('b1-u04-l3-p5','b1-u04-l3','translation',5,'practice','medium',false,'{"question":"Dịch sang tiếng Anh:","sourceText":"Anh ấy xin lỗi vì đã đến muộn.","acceptedAnswers":["He apologised for being late.","He apologized for being late.","He apologised for arriving late."],"explanationVi":"apologise for + V-ing."}'::jsonb),
 ('b1-u04-l3-p6','b1-u04-l3','grammar_fill_blank',6,'practice','medium',false,'{"question":"Điền từ đúng: ''Think about the ___ of your actions.'' (hậu quả)","acceptedAnswers":["consequences","consequence"],"explanationVi":"consequences = hậu quả."}'::jsonb),
 ('b1-u04-l3-p7','b1-u04-l3','multiple_choice',7,'practice','medium',false,'{"question":"Từ nào mô tả cảm giác xấu hổ sâu sắc vì làm điều sai?","options":[{"id":"a","text":"proud"},{"id":"b","text":"ashamed"},{"id":"c","text":"relieved"}],"correctOptionId":"b","explanationVi":"ashamed = hổ thẹn vì làm điều sai."}'::jsonb),
 ('b1-u04-l3-q1','b1-u04-l3','vocabulary_match',8,'quiz','easy',true,'{"question":"Nối từ với nghĩa:","pairs":[{"left":"mistake","right":"lỗi lầm"},{"left":"decision","right":"quyết định"},{"left":"forgive","right":"tha thứ"}],"explanationVi":"Ghép đúng từng từ."}'::jsonb),
 ('b1-u04-l3-q2','b1-u04-l3','multiple_choice',9,'quiz','easy',true,'{"question":"Từ nào có nghĩa là ''đổ lỗi''?","options":[{"id":"a","text":"forgive"},{"id":"b","text":"blame"},{"id":"c","text":"regret"}],"correctOptionId":"b","explanationVi":"blame = đổ lỗi, trách móc."}'::jsonb),
 ('b1-u04-l3-q3','b1-u04-l3','multiple_choice',10,'quiz','medium',true,'{"question":"Điền từ đúng: ''She felt ___ about lying to her friend.'' (tội lỗi)","options":[{"id":"a","text":"guilty"},{"id":"b","text":"ashamed"},{"id":"c","text":"proud"}],"correctOptionId":"a","explanationVi":"guilty = cảm giác có lỗi."}'::jsonb),
 ('b1-u04-l3-q4','b1-u04-l3','grammar_fill_blank',11,'quiz','medium',true,'{"question":"Điền từ đúng: ''I ___ not saying sorry earlier.'' (hối tiếc)","acceptedAnswers":["regret"],"explanationVi":"regret + V-ing: I regret not saying..."}'::jsonb),
 ('b1-u04-l3-q5','b1-u04-l3','vocabulary_match',12,'quiz','medium',true,'{"question":"Nối từ với nghĩa:","pairs":[{"left":"guilty","right":"có lỗi"},{"left":"ashamed","right":"hổ thẹn"},{"left":"consequence","right":"hậu quả"},{"left":"apologise","right":"xin lỗi"}],"explanationVi":"Ghép đúng bốn từ."}'::jsonb),
 ('b1-u04-l3-q6','b1-u04-l3','sentence_ordering',13,'quiz','hard',true,'{"question":"Sắp xếp thành câu đúng:","tokens":["felt","She","ashamed","guilty","and","her decision","of"],"correctOrder":[1,0,3,4,2,6,5],"explanationVi":"She felt guilty and ashamed of her decision."}'::jsonb),
 ('b1-u04-l3-q7','b1-u04-l3','grammar_fill_blank',14,'quiz','hard',true,'{"question":"Điền từ đúng: ''Can you ___ me for what I said?'' (tha thứ)","acceptedAnswers":["forgive"],"explanationVi":"forgive sb for sth."}'::jsonb);
INSERT INTO learning_lessons (id, level_code, skill_code, unit_id, lesson_type, lesson_order, title, subtitle, duration_minutes, xp_reward, required_score_to_pass, content, theory_content) VALUES
 ('b1-u04-l4','B1','listening','b1-u04','normal',4,'A Decision I Regret','Nghe hiểu: Quyết định tôi hối tiếc',10,20,70,'{}'::jsonb,
INSERT INTO learning_lesson_activities (id, lesson_id, activity_type, display_order, phase, difficulty, counts_toward_mastery, payload) VALUES
 ('b1-u04-l4-p1','b1-u04-l4','multiple_choice',1,'practice','easy',false,'{"question":"Mark đã từ chối điều gì?","options":[{"id":"a","text":"Lời mời kết hôn"},{"id":"b","text":"Cơ hội làm việc ở Nhật"},{"id":"c","text":"Học bổng đại học"}],"correctOptionId":"b","explanationVi":"''turned down'' a job offer in Japan."}'::jsonb),
 ('b1-u04-l4-p2','b1-u04-l4','multiple_choice',2,'practice','easy',false,'{"question":"Lý do Mark từ chối là gì?","options":[{"id":"a","text":"Lương thấp"},{"id":"b","text":"Sợ sống ở nước ngoài"},{"id":"c","text":"Muốn ở lại gia đình"}],"correctOptionId":"b","explanationVi":"''afraid of living abroad'' → sợ sống ở nước ngoài."}'::jsonb),
 ('b1-u04-l4-p3','b1-u04-l4','multiple_choice',3,'practice','medium',false,'{"question":"Cụm từ ''in hindsight'' có nghĩa là gì?","options":[{"id":"a","text":"Trong tương lai"},{"id":"b","text":"Nhìn lại mới thấy"},{"id":"c","text":"Ngay lúc đó"}],"correctOptionId":"b","explanationVi":"in hindsight = nhìn lại mới thấy."}'::jsonb),
 ('b1-u04-l4-p4','b1-u04-l4','vocabulary_match',4,'practice','easy',false,'{"question":"Nối từ với nghĩa:","pairs":[{"left":"turn down","right":"từ chối"},{"left":"in hindsight","right":"nhìn lại mới thấy"},{"left":"regrettable","right":"đáng tiếc"},{"left":"opportunity","right":"cơ hội"}],"explanationVi":"Ghép đúng từng từ."}'::jsonb),
 ('b1-u04-l4-p5','b1-u04-l4','multiple_choice',5,'practice','medium',false,'{"question":"Mark hối tiếc điều gì nhất?","options":[{"id":"a","text":"Không học tiếng Nhật"},{"id":"b","text":"Không chấp nhận cơ hội ở Nhật"},{"id":"c","text":"Không tìm việc sớm hơn"}],"correctOptionId":"b","explanationVi":"''I regret that decision deeply'' — từ chối cơ hội ở Nhật."}'::jsonb),
 ('b1-u04-l4-p6','b1-u04-l4','grammar_fill_blank',6,'practice','medium',false,'{"question":"Hoàn thành theo bài: ''I ___ (should/accept) the offer.''","acceptedAnswers":["should have accepted"],"explanationVi":"Hối tiếc về quá khứ: should have accepted."}'::jsonb),
 ('b1-u04-l4-p7','b1-u04-l4','multiple_choice',7,'practice','medium',false,'{"question":"Nếu Mark đã đến Nhật, điều gì CÓ LẼ đã xảy ra?","options":[{"id":"a","text":"Anh ấy sẽ mất việc"},{"id":"b","text":"Anh ấy có lẽ đã phát triển sự nghiệp nhanh hơn"},{"id":"c","text":"Anh ấy chắc chắn đã trở về ngay"}],"correctOptionId":"b","explanationVi":"''might have developed my career much faster'' → có lẽ."}'::jsonb),
 ('b1-u04-l4-q1','b1-u04-l4','listening_choice',8,'quiz','easy',true,'{"audioText":"Five years ago, I had the chance to work in Japan. A company offered me a position, but I turned it down because I was afraid of living abroad.","question":"Why did Mark turn down the job offer?","options":[{"id":"a","text":"The salary was too low"},{"id":"b","text":"He was afraid of living abroad"},{"id":"c","text":"He had another job"}],"correctOptionId":"b","explanationVi":"afraid of living abroad."}'::jsonb),
 ('b1-u04-l4-q2','b1-u04-l4','listening_choice',9,'quiz','easy',true,'{"audioText":"In hindsight, I should have accepted the offer. If I had gone to Japan, I would have learned so much.","question":"What does Mark say he should have done?","options":[{"id":"a","text":"Turned down the offer"},{"id":"b","text":"Accepted the offer"},{"id":"c","text":"Applied for a different job"}],"correctOptionId":"b","explanationVi":"should have accepted the offer."}'::jsonb),
 ('b1-u04-l4-q3','b1-u04-l4','multiple_choice',10,'quiz','medium',true,'{"question":"Câu ''If I had gone to Japan, I would have learned so much'' là:","options":[{"id":"a","text":"First conditional"},{"id":"b","text":"Second conditional"},{"id":"c","text":"Third conditional"}],"correctOptionId":"c","explanationVi":"If + had gone → would have learned = third conditional."}'::jsonb),
 ('b1-u04-l4-q4','b1-u04-l4','grammar_fill_blank',11,'quiz','medium',true,'{"question":"Hoàn thành: ''I ___ (shouldn''t/let) fear control my choices.''","acceptedAnswers":["shouldn''t have let","should not have let"],"explanationVi":"shouldn''t have let = lẽ ra không nên để."}'::jsonb),
 ('b1-u04-l4-q5','b1-u04-l4','multiple_choice',12,'quiz','medium',true,'{"question":"Từ ''could have made'' trong bài có nghĩa là:","options":[{"id":"a","text":"Chắc chắn đã tạo được"},{"id":"b","text":"Đã có thể tạo được (cơ hội bị bỏ lỡ)"},{"id":"c","text":"Lẽ ra phải tạo được"}],"correctOptionId":"b","explanationVi":"could have = đã có thể (cơ hội bị bỏ lỡ)."}'::jsonb),
 ('b1-u04-l4-q6','b1-u04-l4','vocabulary_match',13,'quiz','easy',true,'{"question":"Nối từ với nghĩa:","pairs":[{"left":"turn down","right":"từ chối"},{"left":"in hindsight","right":"nhìn lại mới thấy"},{"left":"opportunity","right":"cơ hội"}],"explanationVi":"Ghép đúng từng từ."}'::jsonb),
 ('b1-u04-l4-q7','b1-u04-l4','listening_choice',14,'quiz','hard',true,'{"audioText":"I could have made amazing connections. Now I regret that decision deeply. I shouldn''t have let fear control my choices.","question":"What does Mark regret the most?","options":[{"id":"a","text":"Not learning Japanese"},{"id":"b","text":"Letting fear control his decision"},{"id":"c","text":"Leaving his current job"}],"correctOptionId":"b","explanationVi":"shouldn''t have let fear control my choices."}'::jsonb);
