 ('b1-u04-l5-q5','b1-u04-l5','multiple_choice',5,'quiz','medium',true,'{"question":"Câu nào diễn đạt suy đoán CHẮC CHẮN về quá khứ?","options":[{"id":"a","text":"She might have been tired."},{"id":"b","text":"She could have been tired."},{"id":"c","text":"She must have been tired — she slept all day."}],"correctOptionId":"c","explanationVi":"must have = chắc chắn đã (có bằng chứng)."}'::jsonb),
 ('b1-u04-l5-q6','b1-u04-l5','vocabulary_match',6,'quiz','medium',true,'{"question":"Nối từ với nghĩa:","pairs":[{"left":"guilty","right":"có lỗi"},{"left":"ashamed","right":"hổ thẹn"},{"left":"consequence","right":"hậu quả"},{"left":"mistake","right":"lỗi lầm"}],"explanationVi":"Ghép đúng từng từ."}'::jsonb),
 ('b1-u04-l5-q7','b1-u04-l5','grammar_fill_blank',7,'quiz','medium',true,'{"question":"Hoàn thành: ''You ___ (shouldn''t/say) that — she was really upset.''","acceptedAnswers":["shouldn''t have said","should not have said"],"explanationVi":"shouldn''t have said = lẽ ra không nên nói."}'::jsonb),
 ('b1-u04-l5-q8','b1-u04-l5','sentence_ordering',8,'quiz','hard',true,'{"question":"Sắp xếp thành câu đúng:","tokens":["had","she","If","harder","passed","she","would have","studied"],"correctOrder":[2,1,0,3,7,5,6,4],"explanationVi":"If she had studied harder, she would have passed."}'::jsonb),
 ('b1-u04-l5-q9','b1-u04-l5','multiple_choice',9,'quiz','medium',true,'{"question":"Câu ''could have'' diễn đạt điều gì?","options":[{"id":"a","text":"Hối tiếc mạnh"},{"id":"b","text":"Suy đoán chắc chắn"},{"id":"c","text":"Cơ hội bị bỏ lỡ hoặc khả năng có thể"}],"correctOptionId":"c","explanationVi":"could have = cơ hội bị bỏ lỡ/khả năng."}'::jsonb),
 ('b1-u04-l5-q10','b1-u04-l5','grammar_fill_blank',10,'quiz','hard',true,'{"question":"Chia động từ (suy đoán không chắc): ''He ___ (might/take) the wrong road.''","acceptedAnswers":["might have taken"],"explanationVi":"might have taken = có lẽ đã đi nhầm."}'::jsonb);
INSERT INTO learning_lessons (id, level_code, skill_code, unit_id, lesson_type, lesson_order, title, subtitle, duration_minutes, xp_reward, required_score_to_pass, content, theory_content) VALUES
 ('b1-u05-l1','B1','reading','b1-u05','normal',1,'Connecting Words','Cause/effect/contrast: because, so, although, however, despite, therefore, since',10,20,70,'{}'::jsonb,
INSERT INTO learning_lesson_activities (id, lesson_id, activity_type, display_order, phase, difficulty, counts_toward_mastery, payload) VALUES
 ('b1-u05-l1-p1','b1-u05-l1','grammar_fill_blank',1,'practice','easy',false,'{"question":"Điền từ nối phù hợp: ''She stayed home ___ it was raining.'' (vì)","acceptedAnswers":["because","since","as"],"explanationVi":"Nguyên nhân: because/since/as."}'::jsonb),
 ('b1-u05-l1-p2','b1-u05-l1','multiple_choice',2,'practice','easy',false,'{"question":"Chọn câu ĐÚNG với ''despite'':","options":[{"id":"a","text":"Despite she was tired, she worked."},{"id":"b","text":"Despite being tired, she worked."},{"id":"c","text":"Despite of being tired, she worked."}],"correctOptionId":"b","explanationVi":"despite + noun/V-ing (không + clause, không dùng ''of'')."}'::jsonb),
 ('b1-u05-l1-p3','b1-u05-l1','vocabulary_match',3,'practice','easy',false,'{"question":"Nối từ nối với chức năng:","pairs":[{"left":"because","right":"nguyên nhân"},{"left":"so","right":"kết quả"},{"left":"although","right":"tương phản (+ mệnh đề)"},{"left":"however","right":"tương phản (đầu câu)"}],"explanationVi":"Phân loại từ nối theo chức năng."}'::jsonb),
 ('b1-u05-l1-p4','b1-u05-l1','grammar_fill_blank',4,'practice','medium',false,'{"question":"Điền từ nối: ''It was expensive. ___, I bought it anyway.'' (tuy nhiên)","acceptedAnswers":["However"],"explanationVi":"Tương phản đầu câu: However."}'::jsonb),
 ('b1-u05-l1-p5','b1-u05-l1','translation',5,'practice','medium',false,'{"question":"Dịch sang tiếng Anh:","sourceText":"Mặc dù mệt, cô ấy vẫn hoàn thành dự án.","acceptedAnswers":["Despite being tired, she finished the project.","Although she was tired, she finished the project.","Even though she was tired, she finished the project."],"explanationVi":"Despite being tired / Although she was tired."}'::jsonb),
 ('b1-u05-l1-p6','b1-u05-l1','error_correction',6,'practice','medium',false,'{"question":"Sửa lỗi:","sourceText":"Despite she was tired, she kept working.","acceptedAnswers":["Despite being tired, she kept working.","Despite her tiredness, she kept working."],"explanationVi":"despite + noun/V-ing."}'::jsonb),
 ('b1-u05-l1-p7','b1-u05-l1','multiple_choice',7,'practice','medium',false,'{"question":"Chọn câu dùng ''therefore'' ĐÚNG:","options":[{"id":"a","text":"She studied hard, therefore she passed."},{"id":"b","text":"Therefore she passed, she studied hard."},{"id":"c","text":"She studied hard. Therefore, she passed."}],"correctOptionId":"c","explanationVi":"therefore đầu câu mới + dấu phẩy: Therefore, she passed."}'::jsonb),
 ('b1-u05-l1-q1','b1-u05-l1','multiple_choice',8,'quiz','easy',true,'{"question":"Chọn từ nối NGUYÊN NHÂN phù hợp:","options":[{"id":"a","text":"however"},{"id":"b","text":"despite"},{"id":"c","text":"because"}],"correctOptionId":"c","explanationVi":"because = từ nối nguyên nhân."}'::jsonb),
 ('b1-u05-l1-q2','b1-u05-l1','grammar_fill_blank',9,'quiz','easy',true,'{"question":"Điền từ nối: ''It was raining. ___, she went out.'' (tuy nhiên)","acceptedAnswers":["However"],"explanationVi":"Tương phản đầu câu: However."}'::jsonb),
 ('b1-u05-l1-q3','b1-u05-l1','multiple_choice',10,'quiz','medium',true,'{"question":"Chọn câu dùng ''although'' ĐÚNG:","options":[{"id":"a","text":"Although, he was late."},{"id":"b","text":"Although he was tired, he kept going."},{"id":"c","text":"Although he was tired but he kept going."}],"correctOptionId":"b","explanationVi":"although + clause, không thêm but."}'::jsonb),
 ('b1-u05-l1-q4','b1-u05-l1','grammar_fill_blank',11,'quiz','medium',true,'{"question":"Điền từ nối phù hợp: ''___ the heavy traffic, she arrived on time.'' (mặc dù)","acceptedAnswers":["Despite","In spite of"],"explanationVi":"despite/in spite of + noun."}'::jsonb),
 ('b1-u05-l1-q5','b1-u05-l1','sentence_ordering',12,'quiz','hard',true,'{"question":"Sắp xếp thành câu đúng:","tokens":["tired","Although","kept","was","he","working","he"],"correctOrder":[1,6,3,2,0,4,5],"explanationVi":"Although he was tired, he kept working."}'::jsonb),
 ('b1-u05-l1-q6','b1-u05-l1','vocabulary_match',13,'quiz','medium',true,'{"question":"Nối từ nối với chức năng:","pairs":[{"left":"therefore","right":"kết quả (trang trọng)"},{"left":"despite","right":"tương phản + noun/V-ing"},{"left":"since","right":"nguyên nhân"}],"explanationVi":"Ghép đúng từng từ nối."}'::jsonb),
 ('b1-u05-l1-q7','b1-u05-l1','grammar_fill_blank',14,'quiz','hard',true,'{"question":"Điền từ nối ĐÚNG: ''She worked very hard. ___, she got a promotion.'' (do đó)","acceptedAnswers":["Therefore","As a result"],"explanationVi":"Kết quả: Therefore / As a result."}'::jsonb);
INSERT INTO learning_lessons (id, level_code, skill_code, unit_id, lesson_type, lesson_order, title, subtitle, duration_minutes, xp_reward, required_score_to_pass, content, theory_content) VALUES
 ('b1-u05-l2','B1','reading','b1-u05','normal',2,'-ing/-ed Adjectives','Boring/bored, exciting/excited: phân biệt và dùng đúng',10,20,70,'{}'::jsonb,
INSERT INTO learning_lesson_activities (id, lesson_id, activity_type, display_order, phase, difficulty, counts_toward_mastery, payload) VALUES
 ('b1-u05-l2-p1','b1-u05-l2','multiple_choice',1,'practice','easy',false,'{"question":"Chọn từ ĐÚNG: ''The match was really ___.''","options":[{"id":"a","text":"excited"},{"id":"b","text":"exciting"},{"id":"c","text":"excite"}],"correctOptionId":"b","explanationVi":"Mô tả trận đấu (sự vật) → exciting."}'::jsonb),
 ('b1-u05-l2-p2','b1-u05-l2','multiple_choice',2,'practice','easy',false,'{"question":"Chọn từ ĐÚNG: ''She was very ___ about the trip.''","options":[{"id":"a","text":"exciting"},{"id":"b","text":"excited"},{"id":"c","text":"excite"}],"correctOptionId":"b","explanationVi":"Mô tả cảm giác của người → excited."}'::jsonb),
 ('b1-u05-l2-p3','b1-u05-l2','vocabulary_match',3,'practice','easy',false,'{"question":"Nối từ với nghĩa:","pairs":[{"left":"boring","right":"nhàm chán (gây buồn)"},{"left":"bored","right":"chán (cảm giác)"},{"left":"tiring","right":"mệt mỏi (gây mệt)"},{"left":"tired","right":"mệt (cảm giác)"}],"explanationVi":"Phân biệt -ing và -ed."}'::jsonb),
 ('b1-u05-l2-p4','b1-u05-l2','grammar_fill_blank',4,'practice','medium',false,'{"question":"Điền từ đúng: ''The news was ___ — nobody expected it.'' (gây bất ngờ)","acceptedAnswers":["surprising"],"explanationVi":"surprising = gây bất ngờ (mô tả tin tức)."}'::jsonb),
 ('b1-u05-l2-p5','b1-u05-l2','translation',5,'practice','medium',false,'{"question":"Dịch sang tiếng Anh:","sourceText":"Cuốn sách này rất thú vị. Tôi rất hứng thú với nó.","acceptedAnswers":["This book is very interesting. I am very interested in it.","The book is very interesting. I am very interested in it."],"explanationVi":"interesting (sách) + interested (tôi)."}'::jsonb),
 ('b1-u05-l2-p6','b1-u05-l2','error_correction',6,'practice','medium',false,'{"question":"Sửa lỗi:","sourceText":"I am boring because the lesson is bored.","acceptedAnswers":["I am bored because the lesson is boring.","I am bored because the lesson is boring"],"explanationVi":"Người = bored; bài học = boring."}'::jsonb),
 ('b1-u05-l2-p7','b1-u05-l2','multiple_choice',7,'practice','medium',false,'{"question":"Chọn câu ĐÚNG:","options":[{"id":"a","text":"The journey was very tired."},{"id":"b","text":"The journey was very tiring."},{"id":"c","text":"I felt tiring after the journey."}],"correctOptionId":"b","explanationVi":"Hành trình (sự vật) gây mệt → tiring."}'::jsonb),
 ('b1-u05-l2-q1','b1-u05-l2','multiple_choice',8,'quiz','easy',true,'{"question":"Chọn từ ĐÚNG: ''The homework was really ___.''","options":[{"id":"a","text":"confused"},{"id":"b","text":"confusing"},{"id":"c","text":"confuse"}],"correctOptionId":"b","explanationVi":"Mô tả bài tập → confusing."}'::jsonb),
 ('b1-u05-l2-q2','b1-u05-l2','grammar_fill_blank',9,'quiz','easy',true,'{"question":"Điền từ đúng: ''The students were ___ by the instructions.'' (bị bối rối)","acceptedAnswers":["confused"],"explanationVi":"Học sinh cảm thấy → confused."}'::jsonb),
 ('b1-u05-l2-q3','b1-u05-l2','multiple_choice',10,'quiz','medium',true,'{"question":"Câu nào ĐÚNG?","options":[{"id":"a","text":"I am boring at home."},{"id":"b","text":"Staying home is bored."},{"id":"c","text":"I feel bored staying home."}],"correctOptionId":"c","explanationVi":"Người cảm thấy → bored."}'::jsonb),
 ('b1-u05-l2-q4','b1-u05-l2','grammar_fill_blank',11,'quiz','medium',true,'{"question":"Điền từ đúng: ''She was ___ to hear the news.'' (bị bất ngờ)","acceptedAnswers":["surprised"],"explanationVi":"Người bị tác động → surprised."}'::jsonb),
 ('b1-u05-l2-q5','b1-u05-l2','vocabulary_match',12,'quiz','medium',true,'{"question":"Nối từ với nghĩa:","pairs":[{"left":"interesting","right":"thú vị (gây tò mò)"},{"left":"interested","right":"thấy thích thú"},{"left":"frightening","right":"đáng sợ (gây sợ)"},{"left":"frightened","right":"sợ hãi (cảm giác)"}],"explanationVi":"Phân biệt -ing và -ed."}'::jsonb),
 ('b1-u05-l2-q6','b1-u05-l2','sentence_ordering',13,'quiz','hard',true,'{"question":"Sắp xếp thành câu đúng:","tokens":["exciting","The","was","match","fans","The","excited","were"],"correctOrder":[1,2,0,3,4,5,7,6],"explanationVi":"The match was exciting. The fans were excited."}'::jsonb),
 ('b1-u05-l2-q7','b1-u05-l2','grammar_fill_blank',14,'quiz','hard',true,'{"question":"Điền từ đúng: ''The long flight was ___ but I was too ___ to sleep.'' (gây mệt / hứng khởi)","acceptedAnswers":["tiring, excited"],"explanationVi":"tiring (chuyến bay gây mệt) + excited (tôi hứng khởi)."}'::jsonb);
INSERT INTO learning_lessons (id, level_code, skill_code, unit_id, lesson_type, lesson_order, title, subtitle, duration_minutes, xp_reward, required_score_to_pass, content, theory_content) VALUES
 ('b1-u05-l3','B1','reading','b1-u05','normal',3,'Opinion Expressions','Từ vựng: Diễn đạt ý kiến',10,20,70,'{}'::jsonb,
INSERT INTO learning_lesson_activities (id, lesson_id, activity_type, display_order, phase, difficulty, counts_toward_mastery, payload) VALUES
 ('b1-u05-l3-p1','b1-u05-l3','vocabulary_match',1,'practice','easy',false,'{"question":"Nối cụm từ với nghĩa:","pairs":[{"left":"In my opinion","right":"theo ý kiến của tôi"},{"left":"I believe","right":"tôi tin rằng"},{"left":"Personally","right":"cá nhân tôi"},{"left":"I''d say","right":"tôi sẽ nói rằng"}],"explanationVi":"Ghép đúng từng cụm từ ý kiến."}'::jsonb),
 ('b1-u05-l3-p2','b1-u05-l3','vocabulary_match',2,'practice','easy',false,'{"question":"Nối cụm từ với nghĩa:","pairs":[{"left":"As far as I know","right":"theo tôi biết"},{"left":"I''m not sure I agree","right":"tôi không chắc đồng ý"},{"left":"That''s a good point","right":"đó là điểm hay"}],"explanationVi":"Ghép đúng từng cụm từ phản hồi."}'::jsonb),
 ('b1-u05-l3-p3','b1-u05-l3','multiple_choice',3,'practice','easy',false,'{"question":"Cụm từ nào dùng để ĐỒNG Ý một phần nhưng còn nghi ngờ?","options":[{"id":"a","text":"I believe"},{"id":"b","text":"I''m not sure I agree"},{"id":"c","text":"In my opinion"}],"correctOptionId":"b","explanationVi":"I''m not sure I agree = không chắc đồng ý."}'::jsonb),
 ('b1-u05-l3-p4','b1-u05-l3','multiple_choice',4,'practice','medium',false,'{"question":"Chọn câu phù hợp để bắt đầu ý kiến cá nhân:","options":[{"id":"a","text":"As far as I know, I love this film."},{"id":"b","text":"Personally, I think homework is useful."},{"id":"c","text":"That''s a good point that homework is useful."}],"correctOptionId":"b","explanationVi":"Personally + ý kiến cá nhân rõ ràng."}'::jsonb),
 ('b1-u05-l3-p5','b1-u05-l3','translation',5,'practice','medium',false,'{"question":"Dịch sang tiếng Anh:","sourceText":"Theo ý kiến của tôi, học sinh nên có ít bài tập về nhà hơn.","acceptedAnswers":["In my opinion, students should have less homework.","I think students should have less homework.","Personally, I think students should have less homework."],"explanationVi":"In my opinion, students should have less homework."}'::jsonb),
 ('b1-u05-l3-p6','b1-u05-l3','grammar_fill_blank',6,'practice','medium',false,'{"question":"Điền cụm từ phù hợp: ''___, the meeting is at 3 pm.'' (theo tôi biết)","acceptedAnswers":["As far as I know"],"explanationVi":"As far as I know = theo tôi biết."}'::jsonb),
 ('b1-u05-l3-p7','b1-u05-l3','multiple_choice',7,'practice','medium',false,'{"question":"Chọn câu phản hồi ĐÚNG khi đồng ý điểm đó là hay:","options":[{"id":"a","text":"I''m not sure I agree with that."},{"id":"b","text":"That''s a good point."},{"id":"c","text":"As far as I know."}],"correctOptionId":"b","explanationVi":"That''s a good point = công nhận điểm hay của người kia."}'::jsonb),
 ('b1-u05-l3-q1','b1-u05-l3','vocabulary_match',8,'quiz','easy',true,'{"question":"Nối cụm từ với nghĩa:","pairs":[{"left":"I believe","right":"tôi tin rằng"},{"left":"I''d say","right":"tôi sẽ nói rằng"},{"left":"Personally","right":"cá nhân tôi"}],"explanationVi":"Ghép đúng từng cụm từ."}'::jsonb),
 ('b1-u05-l3-q2','b1-u05-l3','multiple_choice',9,'quiz','easy',true,'{"question":"Cụm từ nào dùng để nêu ý kiến CHẮC CHẮN nhất?","options":[{"id":"a","text":"I''d say"},{"id":"b","text":"As far as I know"},{"id":"c","text":"I believe"}],"correctOptionId":"c","explanationVi":"I believe = diễn đạt niềm tin mạnh hơn I''d say."}'::jsonb),
 ('b1-u05-l3-q3','b1-u05-l3','multiple_choice',10,'quiz','medium',true,'{"question":"Chọn câu ĐÚNG để bày tỏ ý kiến cá nhân:","options":[{"id":"a","text":"In my opinion, I think homework is important."},{"id":"b","text":"In my opinion, homework is important."},{"id":"c","text":"In my opinion, that homework is important."}],"correctOptionId":"b","explanationVi":"Không kép cụm + I think: chỉ cần một."}'::jsonb),
 ('b1-u05-l3-q4','b1-u05-l3','grammar_fill_blank',11,'quiz','medium',true,'{"question":"Điền cụm từ phản hồi: ''___ — I hadn''t thought of that.'' (điểm hay)","acceptedAnswers":["That''s a good point","That is a good point"],"explanationVi":"That''s a good point = công nhận điểm hay."}'::jsonb),
 ('b1-u05-l3-q5','b1-u05-l3','vocabulary_match',12,'quiz','medium',true,'{"question":"Nối cụm từ với mức độ chắc chắn:","pairs":[{"left":"I believe","right":"chắc chắn"},{"left":"I''d say","right":"không chắc lắm"},{"left":"As far as I know","right":"có thể sai"}],"explanationVi":"Phân biệt mức độ chắc chắn."}'::jsonb),
 ('b1-u05-l3-q6','b1-u05-l3','sentence_ordering',13,'quiz','hard',true,'{"question":"Sắp xếp thành câu đúng:","tokens":["I","opinion,","In","less","students","should","homework","have","my"],"correctOrder":[2,0,1,4,5,3,7,6,8],"explanationVi":"In my opinion, students should have less homework."}'::jsonb),
 ('b1-u05-l3-q7','b1-u05-l3','grammar_fill_blank',14,'quiz','hard',true,'{"question":"Điền cụm từ: ''___, technology makes life much easier.'' (cá nhân tôi)","acceptedAnswers":["Personally"],"explanationVi":"Personally = cá nhân tôi."}'::jsonb);
INSERT INTO learning_lessons (id, level_code, skill_code, unit_id, lesson_type, lesson_order, title, subtitle, duration_minutes, xp_reward, required_score_to_pass, content, theory_content) VALUES
 ('b1-u05-l4','B1','reading','b1-u05','normal',4,'Should Homework Be Banned?','Đọc hiểu: Bài văn nghị luận B1',10,20,70,'{}'::jsonb,
INSERT INTO learning_lesson_activities (id, lesson_id, activity_type, display_order, phase, difficulty, counts_toward_mastery, payload) VALUES
 ('b1-u05-l4-p1','b1-u05-l4','multiple_choice',1,'practice','easy',false,'{"question":"Theo bài đọc, học sinh nghĩ bài tập về nhà gây ra điều gì?","options":[{"id":"a","text":"Kết quả tốt hơn"},{"id":"b","text":"Căng thẳng và mất thời gian"},{"id":"c","text":"Thói quen học tập tốt"}],"correctOptionId":"b","explanationVi":"''homework causes stress and takes time away'' → căng thẳng và mất thời gian."}'::jsonb),
 ('b1-u05-l4-p2','b1-u05-l4','multiple_choice',2,'practice','easy',false,'{"question":"Hầu hết giáo viên ủng hộ hay phản đối bài tập về nhà?","options":[{"id":"a","text":"Phản đối"},{"id":"b","text":"Ủng hộ"},{"id":"c","text":"Không quan tâm"}],"correctOptionId":"b","explanationVi":"''most teachers disagree'' (với học sinh) → giáo viên ủng hộ bài tập."}'::jsonb),
 ('b1-u05-l4-p3','b1-u05-l4','multiple_choice',3,'practice','medium',false,'{"question":"Từ nối nào báo hiệu thông tin bổ sung trong bài?","options":[{"id":"a","text":"However"},{"id":"b","text":"Despite"},{"id":"c","text":"Furthermore"}],"correctOptionId":"c","explanationVi":"Furthermore = hơn nữa, bổ sung thêm luận điểm."}'::jsonb),
 ('b1-u05-l4-p4','b1-u05-l4','vocabulary_match',4,'practice','easy',false,'{"question":"Nối từ với nghĩa:","pairs":[{"left":"ban","right":"cấm, bãi bỏ"},{"left":"argument","right":"lập luận"},{"left":"benefit","right":"lợi ích"},{"left":"stress","right":"căng thẳng"}],"explanationVi":"Ghép đúng từng từ."}'::jsonb),
 ('b1-u05-l4-p5','b1-u05-l4','multiple_choice',5,'practice','medium',false,'{"question":"Nghiên cứu cho thấy điều gì về học sinh làm bài tập?","options":[{"id":"a","text":"Họ căng thẳng hơn"},{"id":"b","text":"Họ đạt kết quả thi tốt hơn"},{"id":"c","text":"Họ có ít thời gian vui chơi hơn"}],"correctOptionId":"b","explanationVi":"''students who do homework achieve better results in exams.''"}'::jsonb),
 ('b1-u05-l4-p6','b1-u05-l4','multiple_choice',6,'practice','medium',false,'{"question":"Theo tác giả, điều gì quan trọng hơn trong bài tập về nhà?","options":[{"id":"a","text":"Số lượng"},{"id":"b","text":"Chất lượng"},{"id":"c","text":"Thời gian làm"}],"correctOptionId":"b","explanationVi":"''quality of homework matters more than the quantity.''"}'::jsonb),
 ('b1-u05-l4-p7','b1-u05-l4','grammar_fill_blank',7,'practice','medium',false,'{"question":"Điền từ nối phù hợp: ''___, many experts suggest a balance is needed.'' (vì vậy)","acceptedAnswers":["Therefore"],"explanationVi":"Therefore = kết quả luận điểm."}'::jsonb),
 ('b1-u05-l4-q1','b1-u05-l4','multiple_choice',8,'quiz','easy',true,'{"question":"Lập luận chính của học sinh chống bài tập là gì?","options":[{"id":"a","text":"Bài tập không giúp ích gì"},{"id":"b","text":"Bài tập gây căng thẳng và mất thời gian tự do"},{"id":"c","text":"Giáo viên giao bài tập quá khó"}],"correctOptionId":"b","explanationVi":"''causes stress and takes time away from family and hobbies.''"}'::jsonb),
 ('b1-u05-l4-q2','b1-u05-l4','multiple_choice',9,'quiz','easy',true,'{"question":"Giáo viên tin rằng bài tập giúp học sinh làm gì?","options":[{"id":"a","text":"Vui chơi nhiều hơn"},{"id":"b","text":"Học ít hơn ở trường"},{"id":"c","text":"Luyện tập và hình thành thói quen học tốt"}],"correctOptionId":"c","explanationVi":"''practise what they have learned and develop good study habits.''"}'::jsonb),
 ('b1-u05-l4-q3','b1-u05-l4','multiple_choice',10,'quiz','medium',true,'{"question":"Từ nối nào trong bài báo hiệu TƯƠNG PHẢN?","options":[{"id":"a","text":"Furthermore"},{"id":"b","text":"However"},{"id":"c","text":"Therefore"}],"correctOptionId":"b","explanationVi":"However = tuy nhiên (tương phản)."}'::jsonb),
 ('b1-u05-l4-q4','b1-u05-l4','grammar_fill_blank',11,'quiz','medium',true,'{"question":"Hoàn thành: ''___ this, most teachers disagree.'' (mặc dù điều đó)","acceptedAnswers":["Despite"],"explanationVi":"Despite this = mặc dù điều đó."}'::jsonb),
 ('b1-u05-l4-q5','b1-u05-l4','multiple_choice',12,'quiz','medium',true,'{"question":"Ý kiến cá nhân của tác giả là gì?","options":[{"id":"a","text":"Nên bãi bỏ hoàn toàn bài tập"},{"id":"b","text":"Chất lượng quan trọng hơn số lượng"},{"id":"c","text":"Học sinh nên làm nhiều bài tập hơn"}],"correctOptionId":"b","explanationVi":"''quality of homework matters more than the quantity.''"}'::jsonb),
 ('b1-u05-l4-q6','b1-u05-l4','vocabulary_match',13,'quiz','easy',true,'{"question":"Nối từ với nghĩa:","pairs":[{"left":"ban","right":"cấm"},{"left":"benefit","right":"lợi ích"},{"left":"argument","right":"lập luận"}],"explanationVi":"Ghép đúng từng từ."}'::jsonb),
 ('b1-u05-l4-q7','b1-u05-l4','grammar_fill_blank',14,'quiz','hard',true,'{"question":"Điền cụm từ ý kiến phù hợp vào: ''___, homework should be limited to 30 minutes a day.'' (cá nhân tôi)","acceptedAnswers":["Personally","In my opinion","I believe"],"explanationVi":"Các cụm từ ý kiến cá nhân."}'::jsonb);
