 ('b1-u05-l5','B1','reading','b1-u05','unit_review',5,'Unit 5 Review','Ôn tập Unit 5: Your Opinions',12,30,75,'{}'::jsonb,
INSERT INTO learning_lesson_activities (id, lesson_id, activity_type, display_order, phase, difficulty, counts_toward_mastery, payload) VALUES
 ('b1-u05-l5-q1','b1-u05-l5','grammar_fill_blank',1,'quiz','easy',true,'{"question":"Điền từ nối nguyên nhân: ''She stayed home ___ she was sick.''","acceptedAnswers":["because","since","as"],"explanationVi":"Nguyên nhân: because/since/as."}'::jsonb),
 ('b1-u05-l5-q2','b1-u05-l5','multiple_choice',2,'quiz','easy',true,'{"question":"Chọn câu ĐÚNG với ''despite'':","options":[{"id":"a","text":"Despite she was tired, she worked."},{"id":"b","text":"Despite being tired, she worked."},{"id":"c","text":"Despite of being tired, she worked."}],"correctOptionId":"b","explanationVi":"despite + V-ing."}'::jsonb),
 ('b1-u05-l5-q3','b1-u05-l5','multiple_choice',3,'quiz','easy',true,'{"question":"Chọn từ ĐÚNG: ''The film was very ___.'' (gây hấp dẫn)","options":[{"id":"a","text":"excited"},{"id":"b","text":"exciting"},{"id":"c","text":"excite"}],"correctOptionId":"b","explanationVi":"Mô tả bộ phim (sự vật) → exciting."}'::jsonb),
 ('b1-u05-l5-q4','b1-u05-l5','grammar_fill_blank',4,'quiz','medium',true,'{"question":"Điền từ đúng: ''I am ___ by the instructions.'' (bị bối rối)","acceptedAnswers":["confused"],"explanationVi":"Người cảm thấy → confused."}'::jsonb),
 ('b1-u05-l5-q5','b1-u05-l5','multiple_choice',5,'quiz','medium',true,'{"question":"Cụm từ nào diễn đạt ý kiến KHÔNG CHẮC CHẮN?","options":[{"id":"a","text":"I believe"},{"id":"b","text":"I''d say"},{"id":"c","text":"In my opinion"}],"correctOptionId":"b","explanationVi":"I''d say = không chắc lắm."}'::jsonb),
 ('b1-u05-l5-q6','b1-u05-l5','vocabulary_match',6,'quiz','medium',true,'{"question":"Nối từ nối với chức năng:","pairs":[{"left":"because","right":"nguyên nhân"},{"left":"however","right":"tương phản"},{"left":"therefore","right":"kết quả"},{"left":"although","right":"tương phản + mệnh đề"}],"explanationVi":"Phân loại từ nối."}'::jsonb),
 ('b1-u05-l5-q7','b1-u05-l5','grammar_fill_blank',7,'quiz','medium',true,'{"question":"Điền cụm từ: ''___, technology makes life easier.'' (cá nhân tôi)","acceptedAnswers":["Personally"],"explanationVi":"Personally = cá nhân tôi."}'::jsonb),
 ('b1-u05-l5-q8','b1-u05-l5','sentence_ordering',8,'quiz','hard',true,'{"question":"Sắp xếp thành câu đúng:","tokens":["tired","Although","working","was","he","kept","he"],"correctOrder":[1,6,3,2,0,4,5],"explanationVi":"Although he was tired, he kept working."}'::jsonb),
 ('b1-u05-l5-q9','b1-u05-l5','multiple_choice',9,'quiz','medium',true,'{"question":"Câu nào ĐÚNG (phản hồi trong tranh luận)?","options":[{"id":"a","text":"I''m not sure I agree with that view."},{"id":"b","text":"As far as I know, I like this."},{"id":"c","text":"That''s a good point is important."}],"correctOptionId":"a","explanationVi":"I''m not sure I agree with that view = phản hồi không đồng ý."}'::jsonb),
 ('b1-u05-l5-q10','b1-u05-l5','grammar_fill_blank',10,'quiz','hard',true,'{"question":"Điền từ nối tương phản ĐÚNG: ''She studied hard. ___, she failed the exam.''","acceptedAnswers":["However"],"explanationVi":"Tương phản đầu câu: However."}'::jsonb);
INSERT INTO learning_lessons (id, level_code, skill_code, unit_id, lesson_type, lesson_order, title, subtitle, duration_minutes, xp_reward, required_score_to_pass, content, theory_content) VALUES
 ('b1-u06-l1','B1','reading','b1-u06','normal',1,'Passive Voice (Present & Past Simple)','Am/is/are/was/were + V3: câu bị động hiện tại & quá khứ',10,20,70,'{}'::jsonb,
INSERT INTO learning_lesson_activities (id, lesson_id, activity_type, display_order, phase, difficulty, counts_toward_mastery, payload) VALUES
 ('b1-u06-l1-p1','b1-u06-l1','grammar_fill_blank',1,'practice','easy',false,'{"question":"Chuyển sang bị động: ''People speak English worldwide.'' → ''English ___ (speak) worldwide.''","acceptedAnswers":["is spoken"],"explanationVi":"Hiện tại đơn bị động: is spoken."}'::jsonb),
 ('b1-u06-l1-p2','b1-u06-l1','multiple_choice',2,'practice','easy',false,'{"question":"Chọn câu bị động ĐÚNG: ''Someone stole my car.''","options":[{"id":"a","text":"My car was stolen."},{"id":"b","text":"My car is stolen."},{"id":"c","text":"My car was steal."}],"correctOptionId":"a","explanationVi":"Quá khứ bị động: was + V3 (stolen)."}'::jsonb),
 ('b1-u06-l1-p3','b1-u06-l1','vocabulary_match',3,'practice','easy',false,'{"question":"Nối dạng bị động với nghĩa:","pairs":[{"left":"is made","right":"được làm ra"},{"left":"was built","right":"được xây dựng"},{"left":"are sold","right":"được bán"},{"left":"were found","right":"được tìm thấy"}],"explanationVi":"Ghép đúng từng dạng bị động."}'::jsonb),
 ('b1-u06-l1-p4','b1-u06-l1','grammar_fill_blank',4,'practice','medium',false,'{"question":"Chuyển sang bị động: ''They cleaned the office.'' → ''The office ___ (clean).''","acceptedAnswers":["was cleaned"],"explanationVi":"Quá khứ bị động: was cleaned."}'::jsonb),
 ('b1-u06-l1-p5','b1-u06-l1','translation',5,'practice','medium',false,'{"question":"Dịch sang tiếng Anh (bị động):","sourceText":"Tiếng Anh được dạy ở tất cả các trường.","acceptedAnswers":["English is taught in all schools.","English is taught at all schools."],"explanationVi":"English is taught in all schools."}'::jsonb),
 ('b1-u06-l1-p6','b1-u06-l1','error_correction',6,'practice','medium',false,'{"question":"Sửa lỗi:","sourceText":"The window was broke by the ball.","acceptedAnswers":["The window was broken by the ball.","The window was broken by the ball"],"explanationVi":"break → broken (V3 bất quy tắc)."}'::jsonb),
 ('b1-u06-l1-p7','b1-u06-l1','grammar_fill_blank',7,'practice','medium',false,'{"question":"Chuyển sang bị động: ''A famous architect designed this building.'' → ''This building ___ (design) by a famous architect.''","acceptedAnswers":["was designed"],"explanationVi":"Quá khứ bị động: was designed."}'::jsonb),
 ('b1-u06-l1-q1','b1-u06-l1','multiple_choice',8,'quiz','easy',true,'{"question":"Chọn câu bị động ĐÚNG:","options":[{"id":"a","text":"This product is make in Vietnam."},{"id":"b","text":"This product is made in Vietnam."},{"id":"c","text":"This product are made in Vietnam."}],"correctOptionId":"b","explanationVi":"is + V3: is made."}'::jsonb),
 ('b1-u06-l1-q2','b1-u06-l1','grammar_fill_blank',9,'quiz','easy',true,'{"question":"Chuyển sang bị động: ''Millions of tourists visit this city.'' → ''This city ___ (visit) by millions of tourists.''","acceptedAnswers":["is visited"],"explanationVi":"Hiện tại bị động: is visited."}'::jsonb),
 ('b1-u06-l1-q3','b1-u06-l1','multiple_choice',10,'quiz','medium',true,'{"question":"Chọn câu bị động ĐÚNG ở thì quá khứ:","options":[{"id":"a","text":"The museum was open last year."},{"id":"b","text":"The museum was opened last year."},{"id":"c","text":"The museum is opened last year."}],"correctOptionId":"b","explanationVi":"Quá khứ bị động: was + V3 (opened)."}'::jsonb),
 ('b1-u06-l1-q4','b1-u06-l1','grammar_fill_blank',11,'quiz','medium',true,'{"question":"Chia bị động: ''These computers ___ (not/make) in Japan.''","acceptedAnswers":["are not made","aren''t made"],"explanationVi":"Phủ định hiện tại bị động: are not made."}'::jsonb),
 ('b1-u06-l1-q5','b1-u06-l1','sentence_ordering',12,'quiz','hard',true,'{"question":"Sắp xếp thành câu bị động đúng:","tokens":["in","built","was","The bridge","1990"],"correctOrder":[3,2,1,0,4],"explanationVi":"The bridge was built in 1990."}'::jsonb),
 ('b1-u06-l1-q6','b1-u06-l1','vocabulary_match',13,'quiz','medium',true,'{"question":"Nối dạng bị động với nghĩa:","pairs":[{"left":"is spoken","right":"được nói"},{"left":"was stolen","right":"bị đánh cắp"},{"left":"are sold","right":"được bán"}],"explanationVi":"Ghép đúng từng dạng bị động."}'::jsonb),
 ('b1-u06-l1-q7','b1-u06-l1','grammar_fill_blank',14,'quiz','hard',true,'{"question":"Đặt câu hỏi bị động: ''___ the report ___ (write) by the manager?''","acceptedAnswers":["Was the report written"],"explanationVi":"Câu hỏi quá khứ bị động: Was + S + V3?"}'::jsonb);
INSERT INTO learning_lessons (id, level_code, skill_code, unit_id, lesson_type, lesson_order, title, subtitle, duration_minutes, xp_reward, required_score_to_pass, content, theory_content) VALUES
 ('b1-u06-l2','B1','reading','b1-u06','normal',2,'Passive: Present Perfect & Future','Has been done / Will be done: bị động các thì nâng cao',10,20,70,'{}'::jsonb,
INSERT INTO learning_lesson_activities (id, lesson_id, activity_type, display_order, phase, difficulty, counts_toward_mastery, payload) VALUES
 ('b1-u06-l2-p1','b1-u06-l2','grammar_fill_blank',1,'practice','easy',false,'{"question":"Chia bị động: ''The bridge ___ (repair) already.''","acceptedAnswers":["has been repaired"],"explanationVi":"Present perfect passive: has been repaired."}'::jsonb),
 ('b1-u06-l2-p2','b1-u06-l2','multiple_choice',2,'practice','easy',false,'{"question":"Chọn câu future passive ĐÚNG:","options":[{"id":"a","text":"The road will been built."},{"id":"b","text":"The road will be built."},{"id":"c","text":"The road will be build."}],"correctOptionId":"b","explanationVi":"Future passive: will be + V3."}'::jsonb),
 ('b1-u06-l2-p3','b1-u06-l2','vocabulary_match',3,'practice','easy',false,'{"question":"Nối dạng bị động với nghĩa:","pairs":[{"left":"has been repaired","right":"đã được sửa"},{"left":"have been arrested","right":"đã bị bắt"},{"left":"will be built","right":"sẽ được xây"},{"left":"will be announced","right":"sẽ được thông báo"}],"explanationVi":"Ghép đúng từng dạng bị động."}'::jsonb),
 ('b1-u06-l2-p4','b1-u06-l2','grammar_fill_blank',4,'practice','medium',false,'{"question":"Chuyển sang bị động: ''They will open the new museum next year.'' → ''The new museum ___ (open) next year.''","acceptedAnswers":["will be opened"],"explanationVi":"Future passive: will be opened."}'::jsonb),
 ('b1-u06-l2-p5','b1-u06-l2','translation',5,'practice','medium',false,'{"question":"Dịch sang tiếng Anh (bị động tương lai):","sourceText":"Kết quả sẽ được thông báo vào thứ Hai.","acceptedAnswers":["The results will be announced on Monday.","The result will be announced on Monday."],"explanationVi":"will be announced on Monday."}'::jsonb),
 ('b1-u06-l2-p6','b1-u06-l2','error_correction',6,'practice','medium',false,'{"question":"Sửa lỗi:","sourceText":"Three suspects have been arrest.","acceptedAnswers":["Three suspects have been arrested.","Three suspects have been arrested"],"explanationVi":"have been + V3: have been arrested."}'::jsonb),
 ('b1-u06-l2-p7','b1-u06-l2','grammar_fill_blank',7,'practice','medium',false,'{"question":"Chia bị động: ''Many trees ___ (cut down) to build the new road.''","acceptedAnswers":["have been cut down"],"explanationVi":"Present perfect passive: have been cut down."}'::jsonb),
 ('b1-u06-l2-q1','b1-u06-l2','multiple_choice',8,'quiz','easy',true,'{"question":"Chọn câu present perfect passive ĐÚNG:","options":[{"id":"a","text":"The new law has been approve."},{"id":"b","text":"The new law has been approved."},{"id":"c","text":"The new law have been approved."}],"correctOptionId":"b","explanationVi":"has been + V3: has been approved."}'::jsonb),
 ('b1-u06-l2-q2','b1-u06-l2','grammar_fill_blank',9,'quiz','easy',true,'{"question":"Chia bị động: ''A new hospital ___ (build) next year.''","acceptedAnswers":["will be built"],"explanationVi":"Future passive: will be built."}'::jsonb),
 ('b1-u06-l2-q3','b1-u06-l2','multiple_choice',10,'quiz','medium',true,'{"question":"Câu nào là present perfect passive?","options":[{"id":"a","text":"The bridge will be repaired."},{"id":"b","text":"The bridge has been repaired."},{"id":"c","text":"The bridge was repaired."}],"correctOptionId":"b","explanationVi":"has been repaired = present perfect passive."}'::jsonb),
 ('b1-u06-l2-q4','b1-u06-l2','grammar_fill_blank',11,'quiz','medium',true,'{"question":"Chia bị động: ''The results ___ (not/announce) yet.''","acceptedAnswers":["have not been announced","haven''t been announced"],"explanationVi":"Phủ định present perfect passive: haven''t been announced."}'::jsonb),
 ('b1-u06-l2-q5','b1-u06-l2','sentence_ordering',12,'quiz','hard',true,'{"question":"Sắp xếp thành câu đúng:","tokens":["will","A new","station","next spring","opened","be"],"correctOrder":[1,2,0,4,5,3],"explanationVi":"A new station will be opened next spring."}'::jsonb),
 ('b1-u06-l2-q6','b1-u06-l2','vocabulary_match',13,'quiz','medium',true,'{"question":"Nối dạng bị động với nghĩa:","pairs":[{"left":"has been repaired","right":"đã được sửa"},{"left":"will be announced","right":"sẽ được thông báo"},{"left":"have been arrested","right":"đã bị bắt"}],"explanationVi":"Ghép đúng từng dạng bị động."}'::jsonb),
 ('b1-u06-l2-q7','b1-u06-l2','grammar_fill_blank',14,'quiz','hard',true,'{"question":"Chia bị động: ''The decision ___ (make) by the board of directors tomorrow.''","acceptedAnswers":["will be made"],"explanationVi":"Future passive: will be made."}'::jsonb);
INSERT INTO learning_lessons (id, level_code, skill_code, unit_id, lesson_type, lesson_order, title, subtitle, duration_minutes, xp_reward, required_score_to_pass, content, theory_content) VALUES
 ('b1-u06-l3','B1','reading','b1-u06','normal',3,'Media & Technology','Từ vựng: Truyền thông & Công nghệ',10,20,70,'{}'::jsonb,
INSERT INTO learning_lesson_activities (id, lesson_id, activity_type, display_order, phase, difficulty, counts_toward_mastery, payload) VALUES
 ('b1-u06-l3-p1','b1-u06-l3','vocabulary_match',1,'practice','easy',false,'{"question":"Nối từ với nghĩa tiếng Việt:","pairs":[{"left":"headline","right":"tiêu đề báo"},{"left":"broadcast","right":"phát sóng"},{"left":"journalist","right":"nhà báo"},{"left":"report","right":"bản tin"}],"explanationVi":"Ghép đúng từng từ."}'::jsonb),
 ('b1-u06-l3-p2','b1-u06-l3','vocabulary_match',2,'practice','easy',false,'{"question":"Nối từ với nghĩa:","pairs":[{"left":"publish","right":"xuất bản"},{"left":"online","right":"trực tuyến"},{"left":"network","right":"mạng lưới"},{"left":"access","right":"truy cập"}],"explanationVi":"Ghép đúng từng từ."}'::jsonb),
 ('b1-u06-l3-p3','b1-u06-l3','multiple_choice',3,'practice','easy',false,'{"question":"Từ nào có nghĩa là ''nhà báo''?","options":[{"id":"a","text":"broadcast"},{"id":"b","text":"journalist"},{"id":"c","text":"headline"}],"correctOptionId":"b","explanationVi":"journalist = nhà báo."}'::jsonb),
 ('b1-u06-l3-p4','b1-u06-l3','multiple_choice',4,'practice','medium',false,'{"question":"Điền từ phù hợp: ''She ___ the article on her social media page.''","options":[{"id":"a","text":"broadcast"},{"id":"b","text":"published"},{"id":"c","text":"posted"}],"correctOptionId":"c","explanationVi":"post = đăng bài trên mạng xã hội."}'::jsonb),
 ('b1-u06-l3-p5','b1-u06-l3','translation',5,'practice','medium',false,'{"question":"Dịch sang tiếng Anh:","sourceText":"Hàng triệu người truy cập tin tức trực tuyến mỗi ngày.","acceptedAnswers":["Millions of people access the news online every day.","Millions of people access news online every day."],"explanationVi":"access the news online every day."}'::jsonb),
 ('b1-u06-l3-p6','b1-u06-l3','grammar_fill_blank',6,'practice','medium',false,'{"question":"Điền từ đúng: ''The story was ___ on all major networks.'' (phát sóng)","acceptedAnswers":["broadcast"],"explanationVi":"broadcast = phát sóng (V3 cũng là broadcast)."}'::jsonb),
 ('b1-u06-l3-p7','b1-u06-l3','multiple_choice',7,'practice','medium',false,'{"question":"Từ nào mô tả ''tiêu đề lớn trên báo''?","options":[{"id":"a","text":"post"},{"id":"b","text":"headline"},{"id":"c","text":"network"}],"correctOptionId":"b","explanationVi":"headline = tiêu đề, đầu đề báo."}'::jsonb),
 ('b1-u06-l3-q1','b1-u06-l3','vocabulary_match',8,'quiz','easy',true,'{"question":"Nối từ với nghĩa:","pairs":[{"left":"publish","right":"xuất bản"},{"left":"communicate","right":"giao tiếp"},{"left":"post","right":"đăng bài"}],"explanationVi":"Ghép đúng từng từ."}'::jsonb),
 ('b1-u06-l3-q2','b1-u06-l3','multiple_choice',9,'quiz','easy',true,'{"question":"Từ nào có nghĩa là ''phát sóng''?","options":[{"id":"a","text":"publish"},{"id":"b","text":"broadcast"},{"id":"c","text":"access"}],"correctOptionId":"b","explanationVi":"broadcast = phát sóng."}'::jsonb),
 ('b1-u06-l3-q3','b1-u06-l3','multiple_choice',10,'quiz','medium',true,'{"question":"Điền từ đúng: ''The report was ___ by a famous journalist.''","options":[{"id":"a","text":"broadcast"},{"id":"b","text":"accessed"},{"id":"c","text":"published"}],"correctOptionId":"c","explanationVi":"report + published = bản tin được xuất bản."}'::jsonb),
 ('b1-u06-l3-q4','b1-u06-l3','grammar_fill_blank',11,'quiz','medium',true,'{"question":"Điền từ đúng: ''Everyone should have ___ to basic information.'' (tiếp cận)","acceptedAnswers":["access"],"explanationVi":"access (n) = quyền tiếp cận."}'::jsonb),
 ('b1-u06-l3-q5','b1-u06-l3','vocabulary_match',12,'quiz','medium',true,'{"question":"Nối từ với nghĩa:","pairs":[{"left":"headline","right":"tiêu đề báo"},{"left":"journalist","right":"nhà báo"},{"left":"network","right":"mạng lưới"},{"left":"online","right":"trực tuyến"}],"explanationVi":"Ghép đúng bốn từ."}'::jsonb),
 ('b1-u06-l3-q6','b1-u06-l3','sentence_ordering',13,'quiz','hard',true,'{"question":"Sắp xếp thành câu đúng:","tokens":["published","The","was","article","journalist","by","a"],"correctOrder":[1,3,0,2,6,4,5],"explanationVi":"The article was published by a journalist."}'::jsonb),
 ('b1-u06-l3-q7','b1-u06-l3','grammar_fill_blank',14,'quiz','hard',true,'{"question":"Điền từ đúng: ''She ___ the news on her page to inform her followers.'' (đăng bài)","acceptedAnswers":["posted"],"explanationVi":"post (v) → posted = đã đăng."}'::jsonb);
INSERT INTO learning_lessons (id, level_code, skill_code, unit_id, lesson_type, lesson_order, title, subtitle, duration_minutes, xp_reward, required_score_to_pass, content, theory_content) VALUES
 ('b1-u06-l4','B1','listening','b1-u06','normal',4,'Short News Bulletin','Nghe hiểu: Bản tin ngắn',10,20,70,'{}'::jsonb,
INSERT INTO learning_lesson_activities (id, lesson_id, activity_type, display_order, phase, difficulty, counts_toward_mastery, payload) VALUES
 ('b1-u06-l4-p1','b1-u06-l4','multiple_choice',1,'practice','easy',false,'{"question":"Theo bản tin, điều gì đã được ký kết?","options":[{"id":"a","text":"Một hiệp ước hòa bình"},{"id":"b","text":"Một hiệp định thương mại"},{"id":"c","text":"Một thỏa thuận môi trường"}],"correctOptionId":"b","explanationVi":"''A new trade agreement has been signed.''"}'::jsonb),
 ('b1-u06-l4-p2','b1-u06-l4','multiple_choice',2,'practice','easy',false,'{"question":"Vụ cháy xảy ra ở đâu?","options":[{"id":"a","text":"Trong một trường học"},{"id":"b","text":"Trong một kho hàng"},{"id":"c","text":"Trong một nhà máy"}],"correctOptionId":"b","explanationVi":"''a fire broke out at a warehouse'' → kho hàng."}'::jsonb),
 ('b1-u06-l4-p3','b1-u06-l4','multiple_choice',3,'practice','medium',false,'{"question":"Bao nhiêu người bị thương trong vụ cháy?","options":[{"id":"a","text":"Một người"},{"id":"b","text":"Hai người"},{"id":"c","text":"Ba người"}],"correctOptionId":"c","explanationVi":"''Three people were injured.''"}'::jsonb),
 ('b1-u06-l4-p4','b1-u06-l4','vocabulary_match',4,'practice','easy',false,'{"question":"Nối từ với nghĩa:","pairs":[{"left":"announce","right":"thông báo"},{"left":"confirm","right":"xác nhận"},{"left":"injured","right":"bị thương"},{"left":"rescue","right":"cứu hộ"}],"explanationVi":"Ghép đúng từng từ."}'::jsonb),
 ('b1-u06-l4-p5','b1-u06-l4','multiple_choice',5,'practice','medium',false,'{"question":"Nguyên nhân vụ cháy đã được xác nhận chưa?","options":[{"id":"a","text":"Đã được xác nhận"},{"id":"b","text":"Chưa được xác nhận"},{"id":"c","text":"Đang điều tra"}],"correctOptionId":"b","explanationVi":"''The cause of the fire has not been confirmed yet.''"}'::jsonb),
 ('b1-u06-l4-p6','b1-u06-l4','multiple_choice',6,'practice','medium',false,'{"question":"Các trận đấu bóng đá sẽ được xem ở đâu?","options":[{"id":"a","text":"Trên mạng xã hội"},{"id":"b","text":"Truyền hình quốc gia"},{"id":"c","text":"Sân vận động"}],"correctOptionId":"b","explanationVi":"''broadcast live on national television.''"}'::jsonb),
 ('b1-u06-l4-p7','b1-u06-l4','grammar_fill_blank',7,'practice','medium',false,'{"question":"Hoàn thành theo bản tin: ''The trade agreement ___ (sign) between two countries.''","acceptedAnswers":["has been signed"],"explanationVi":"Present perfect passive: has been signed."}'::jsonb),
 ('b1-u06-l4-q1','b1-u06-l4','listening_choice',8,'quiz','easy',true,'{"audioText":"Good morning. Here are today''s headlines. A new trade agreement has been signed between two neighbouring countries. The deal is expected to create thousands of new jobs.","question":"What has been signed according to the bulletin?","options":[{"id":"a","text":"A peace treaty"},{"id":"b","text":"A trade agreement"},{"id":"c","text":"An environmental deal"}],"correctOptionId":"b","explanationVi":"A new trade agreement has been signed."}'::jsonb),
 ('b1-u06-l4-q2','b1-u06-l4','listening_choice',9,'quiz','easy',true,'{"audioText":"In local news, a fire broke out at a warehouse last night. Three people were injured, but all have been taken to hospital and are reported to be in a stable condition.","question":"What condition are the injured people in?","options":[{"id":"a","text":"Critical condition"},{"id":"b","text":"Stable condition"},{"id":"c","text":"Unknown condition"}],"correctOptionId":"b","explanationVi":"are reported to be in a stable condition."}'::jsonb),
 ('b1-u06-l4-q3','b1-u06-l4','multiple_choice',10,'quiz','medium',true,'{"question":"Dạng bị động nào được dùng nhiều nhất trong bản tin?","options":[{"id":"a","text":"Future passive"},{"id":"b","text":"Past simple passive"},{"id":"c","text":"Present perfect passive"}],"correctOptionId":"c","explanationVi":"has been signed, have been taken = present perfect passive."}'::jsonb),
 ('b1-u06-l4-q4','b1-u06-l4','grammar_fill_blank',11,'quiz','medium',true,'{"question":"Hoàn thành: ''The cause of the fire ___ (not/confirm) yet.''","acceptedAnswers":["has not been confirmed","hasn''t been confirmed"],"explanationVi":"Phủ định present perfect passive."}'::jsonb),
 ('b1-u06-l4-q5','b1-u06-l4','multiple_choice',12,'quiz','medium',true,'{"question":"Cụm ''is expected to'' trong bài có nghĩa là gì?","options":[{"id":"a","text":"đang làm"},{"id":"b","text":"được dự kiến sẽ"},{"id":"c","text":"đã từng"}],"correctOptionId":"b","explanationVi":"is expected to = được dự kiến sẽ."}'::jsonb),
 ('b1-u06-l4-q6','b1-u06-l4','vocabulary_match',13,'quiz','easy',true,'{"question":"Nối từ với nghĩa:","pairs":[{"left":"announce","right":"thông báo"},{"left":"confirm","right":"xác nhận"},{"left":"injured","right":"bị thương"}],"explanationVi":"Ghép đúng từng từ."}'::jsonb),
 ('b1-u06-l4-q7','b1-u06-l4','listening_choice',14,'quiz','hard',true,'{"audioText":"In sport, the national football team has been selected for the championship. Matches will be broadcast live on national television.","question":"How will the matches be shown?","options":[{"id":"a","text":"On social media only"},{"id":"b","text":"Live on national television"},{"id":"c","text":"On paid streaming platforms"}],"correctOptionId":"b","explanationVi":"broadcast live on national television."}'::jsonb);
