INSERT INTO learning_lesson_activities (id, lesson_id, activity_type, display_order, phase, difficulty, counts_toward_mastery, payload) VALUES
 ('b1-u06-l5-q1','b1-u06-l5','grammar_fill_blank',1,'quiz','easy',true,'{"question":"Chia bị động: ''English ___ (speak) in many countries.''","acceptedAnswers":["is spoken"],"explanationVi":"Hiện tại bị động: is spoken."}'::jsonb),
 ('b1-u06-l5-q2','b1-u06-l5','multiple_choice',2,'quiz','easy',true,'{"question":"Chọn câu bị động ĐÚNG:","options":[{"id":"a","text":"The bridge was build in 1980."},{"id":"b","text":"The bridge was built in 1980."},{"id":"c","text":"The bridge is built in 1980."}],"correctOptionId":"b","explanationVi":"Quá khứ bị động: was + V3 (built)."}'::jsonb),
 ('b1-u06-l5-q3','b1-u06-l5','multiple_choice',3,'quiz','easy',true,'{"question":"Từ nào có nghĩa là ''nhà báo''?","options":[{"id":"a","text":"headline"},{"id":"b","text":"journalist"},{"id":"c","text":"broadcast"}],"correctOptionId":"b","explanationVi":"journalist = nhà báo."}'::jsonb),
 ('b1-u06-l5-q4','b1-u06-l5','grammar_fill_blank',4,'quiz','medium',true,'{"question":"Chia bị động: ''The new school ___ (open) next month.''","acceptedAnswers":["will be opened"],"explanationVi":"Future passive: will be opened."}'::jsonb),
 ('b1-u06-l5-q5','b1-u06-l5','multiple_choice',5,'quiz','medium',true,'{"question":"Chọn câu present perfect passive ĐÚNG:","options":[{"id":"a","text":"The suspect has arrested."},{"id":"b","text":"The suspect has been arrested."},{"id":"c","text":"The suspect have been arrested."}],"correctOptionId":"b","explanationVi":"has been + V3: has been arrested."}'::jsonb),
 ('b1-u06-l5-q6','b1-u06-l5','vocabulary_match',6,'quiz','medium',true,'{"question":"Nối từ với nghĩa:","pairs":[{"left":"headline","right":"tiêu đề báo"},{"left":"broadcast","right":"phát sóng"},{"left":"publish","right":"xuất bản"},{"left":"access","right":"truy cập"}],"explanationVi":"Ghép đúng từng từ."}'::jsonb),
 ('b1-u06-l5-q7','b1-u06-l5','grammar_fill_blank',7,'quiz','medium',true,'{"question":"Chia bị động: ''Three people ___ (injure) in the accident.''","acceptedAnswers":["were injured"],"explanationVi":"Quá khứ bị động: were injured."}'::jsonb),
 ('b1-u06-l5-q8','b1-u06-l5','sentence_ordering',8,'quiz','hard',true,'{"question":"Sắp xếp thành câu bị động đúng:","tokens":["been","The","has","agreement","signed","trade"],"correctOrder":[1,5,3,0,2,4],"explanationVi":"The trade agreement has been signed."}'::jsonb),
 ('b1-u06-l5-q9','b1-u06-l5','multiple_choice',9,'quiz','medium',true,'{"question":"Câu bị động nào ĐÚNG ở present perfect?","options":[{"id":"a","text":"The report will been published."},{"id":"b","text":"The report has been published."},{"id":"c","text":"The report was been published."}],"correctOptionId":"b","explanationVi":"Present perfect passive: has been + V3."}'::jsonb),
 ('b1-u06-l5-q10','b1-u06-l5','grammar_fill_blank',10,'quiz','hard',true,'{"question":"Chia bị động: ''The results ___ (not/announce) yet.''","acceptedAnswers":["have not been announced","haven''t been announced"],"explanationVi":"Phủ định present perfect passive: haven''t been announced."}'::jsonb);
